int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = -1;
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (min_idx == -1 || a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it
            // as long as a[i] + min_val <= k.
            // The number of times we can add min_val to a[i] is
            // floor((k - a[i]) / min_val).
            if (a[i] < k) { // Only if there's room to add
                total_operations += (k - a[i]) / min_val;
            }
        }
        std::cout << total_operations << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees a solution exists.
    // A simple strategy that works for all n >= 2 is to reverse the permutation.
    // If p = [p_1, p_2, ..., p_n], then p' = [p_n, p_{n-1}, ..., p_1].
    // The adjacent sums for p are: (p_1+p_2), (p_2+p_3), ..., (p_{n-1}+p_n).
    // The adjacent sums for p' are: (p_n+p_{n-1}), (p_{n-1}+p_{n-2}), ..., (p_2+p_1).
    // These are the same set of sums, just in reverse order.
    // Since the fingerprint is the sorted array of these sums, F(p) will be equal to F(p').
    //
    // The only case where p' might be equal to p is if p is a palindrome.
    // For example, if n=3, p=[1,2,1] is a palindrome. But p must be a permutation,
    // so elements must be distinct. Thus, p cannot be a palindrome for n > 1.
    // For n=2, p=[1,2], p'=[2,1]. They are different.
    // For n=3, p=[1,2,3], p'=[3,2,1]. They are different.
    // In general, for a permutation of distinct elements, p_i != p_{n-i+1} for at least one i,
    // unless n=1 (which is not allowed, n>=2).
    // If p_i = p_{n-i+1} for all i, then p would be a palindrome.
    // For example, if n=4, p=[1,2,3,4]. p'=[4,3,2,1]. Different.
    // If p=[1,4,3,2]. p'=[2,3,4,1]. Different.
    // A permutation cannot be a palindrome unless n=1 (e.g., [1]) or n=0 (empty).
    // For n >= 2, a permutation must contain at least two distinct elements.
    // If p were a palindrome, p_1 = p_n, p_2 = p_{n-1}, etc.
    // But all elements in a permutation must be distinct.
    // So p_1 cannot be equal to p_n unless n=1.
    // Therefore, for n >= 2, p_1 != p_n, which means p != p'.
    // So reversing the permutation always yields a different permutation with the same fingerprint.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

