int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    long long total_successful_a = 0;
    long long total_sent_a = 0;
    long long total_successful_b = 0;
    long long total_sent_b = 0;

    for (int i = 0; i < n; ++i) {
        int t, x, y;
        std::cin >> t >> x >> y;
        if (t == 1) { // Server 'a'
            total_successful_a += x;
            total_sent_a += 10; // Each ping sends 10 packets
        } else { // Server 'b'
            total_successful_b += x;
            total_sent_b += 10; // Each ping sends 10 packets
        }
    }

    // Check server 'a' status
    // A server is "alive" if at least half of the packets sent reached it successfully.
    // This means (successful_packets / total_packets) >= 0.5
    // Which is equivalent to successful_packets * 2 >= total_packets
    if (total_successful_a * 2 >= total_sent_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    // Check server 'b' status
    if (total_successful_b * 2 >= total_sent_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    return 0;
}

