#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_occupied(n, false);
    std::vector<bool> col_occupied(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_occupied[i] = true;
                col_occupied[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_occupied[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_occupied[j]) {
            available_cols++;
        }
    }

    int moves_possible = std::min(available_rows, available_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

