#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    bool n_used = false;

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
        if (p[i] == n) {
            n_used = true;
        }
    }

    if (!n_used) {
        // If 'n' was not assigned to any p[i], it means 'n' was never the minimum
        // in any pair (p[i], p[j]). This implies that for the element p[k] = n,
        // all other p[j] were smaller than p[k].
        // In this case, min(p[k], p[j]) = p[j].
        // So, max_{j!=k} (min(p[k], p[j])) = max_{j!=k} (p[j]) = n-1.
        // This means p[k] would have been assigned n-1 by the logic above.
        // To correct this, we find the p[i] that was assigned n-1 and change it to n.
        // There must be exactly one such p[i] because all values 1 to n-1 must appear
        // as max_val_in_row for some row, and n-1 is the largest among them.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price,
            // it means a[i] is a new minimum for the suffix starting at i.
            min_suffix_price = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

