        // The maximum number of teams is limited by:
        // 1. The number of coders (each team needs at least one).
        // 2. The number of mathematicians (each team needs at least one).
        // 3. The total number of students divided by 3 (each team needs 3 students).
        // So, an initial upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low' for binary search.
        // The absolute maximum possible teams is (c + m + x) / 3.
        // The absolute minimum possible teams is 0.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        // Binary search for the maximum number of teams 'k'
        // A number 'k' is feasible if we can form 'k' teams.
        // To form 'k' teams, we need:
        // - At least 'k' coders.
        // - At least 'k' mathematicians.
        // - At least 'k' students who are not coders or mathematicians (can be 'x' or additional 'c'/'m').
        // More precisely, we need 'k' coders, 'k' mathematicians, and 'k' "third members".
        // The 'k' third members can be taken from 'x' students first.
        // If 'x' is not enough, the remaining third members must come from additional coders or mathematicians.
        // The total number of students needed is 3*k.
        // The number of coders needed is at least k.
        // The number of mathematicians needed is at least k.
        // The remaining (3*k - k - k) = k slots must be filled.
        // These k slots can be filled by 'x' students, or by additional 'c' or 'm' students.
        // So, we need to check if (c - k) + (m - k) + x >= k.
        // This simplifies to c + m + x >= 3k.
        // And also c >= k and m >= k.
        // So, the condition for 'k' teams to be possible is:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3
        // All these conditions are already captured by the initial 'high' value.
        // Therefore, the maximum number of teams is simply the minimum of these three values.

        ans = high; // The binary search logic is not strictly necessary here because the function is monotonic and directly calculable.
                    // The problem constraints are simple enough that the minimum of the three values is the answer.
                    // Let's verify this.
                    // If we form 'k' teams:
                    // We use 'k' coders and 'k' mathematicians for the "at least one" requirement.
                    // Remaining students: (c-k) coders, (m-k) mathematicians, x non-specialized.
                    // Total remaining students: (c-k) + (m-k) + x.
                    // Each team needs 3 members. We've already assigned 2 members (1C, 1M) to each of the 'k' teams.
                    // So, we need 'k' more members in total for these 'k' teams.
                    // These 'k' members must come from the remaining students.
                    // So, we need (c-k) + (m-k) + x >= k.
                    // This simplifies to c + m + x >= 3k.
                    // So, the conditions are:
                    // 1. k <= c
                    // 2. k <= m
                    // 3. k <= (c + m + x) / 3
                    // The maximum k satisfying all these is indeed min(c, m, (c + m + x) / 3).

        std::cout << ans << "\n";
    }
    return 0;
}

