    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_idx = -1; // Represents the last 'R' cell index, or -1 for cell 0.
                             // The actual cell index is last_R_idx + 1.
                             // So, if last_R_idx = -1, it means we are at cell 0.
                             // If last_R_idx = 0, it means we are at cell 1.
                             // If last_R_idx = i-1, it means we are at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1.
                // Distance from previous 'R' cell (or cell 0) to current 'R' cell.
                // Previous 'R' cell was at index last_R_idx + 1.
                // Current 'R' cell is at index i + 1.
                // Distance is (i + 1) - (last_R_idx + 1) = i - last_R_idx.
                max_dist = std::max(max_dist, i - last_R_idx);
                last_R_idx = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // to the target cell n+1.
        // The last 'R' cell was at index last_R_idx + 1.
        // The target cell is n+1.
        // Distance is (n + 1) - (last_R_idx + 1) = n - last_R_idx.
        max_dist = std::max(max_dist, n - last_R_idx);

        std::cout << max_dist << "\n";
    }
    return 0;
}

