    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where l < r, the number 2 will always be a divisor
        // for at least floor(r/2) - ceil(l/2) + 1 numbers.
        // Specifically, if l is even, it's r/2 - l/2 + 1.
        // If l is odd, it's r/2 - (l+1)/2 + 1.
        // This count is at least 1 if r >= 2.
        //
        // Consider any other number k > 2.
        // The numbers divisible by k in the range [l, r] are k * ceil(l/k), k * (ceil(l/k)+1), ..., k * floor(r/k).
        // The count of such numbers is floor(r/k) - ceil(l/k) + 1.
        //
        // For k=2, the count is floor(r/2) - ceil(l/2) + 1.
        //
        // If l=2, r=2, answer is 2.
        // If l=2, r=3, numbers are 2, 3. Divisors: {2}, {3}. Max count is 1. Both 2 and 3 are valid.
        // If l=2, r=4, numbers are 2, 3, 4. Divisors: {2}, {3}, {2,4}. Count for 2 is 2. Count for 3 is 1. Count for 4 is 1. Max is 2. Answer is 2.
        //
        // In general, for any range [l, r] with l < r, the number 2 will appear as a divisor
        // for all even numbers in the range.
        // The count of even numbers in [l, r] is at least (r - l) / 2.
        // If r - l >= 1, there is at least one even number (if r >= 2).
        // If r - l >= 2, there are at least two even numbers.
        //
        // For example, if l=19, r=29.
        // Even numbers: 20, 22, 24, 26, 28. Count = 5. Divisor 2 appears 5 times.
        // Odd numbers: 19, 21, 23, 25, 27, 29.
        //
        // Consider any divisor d > 2.
        // The numbers divisible by d are d, 2d, 3d, ...
        // The density of multiples of d is 1/d.
        // The density of multiples of 2 is 1/2.
        // Since 1/2 > 1/d for any d > 2, 2 will always have more or equal occurrences
        // than any other divisor d > 2, provided the range is large enough.
        //
        // For any l < r, there are at least floor((r-l+1)/2) even numbers in the range.
        // For example, if l=3, r=6. Numbers: 3, 4, 5, 6.
        // Divisors:
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // 6: {2, 3, 6}
        // Counts:
        // 2: in 4, 6 (2 times)
        // 3: in 3, 6 (2 times)
        // 4: in 4 (1 time)
        // 5: in 5 (1 time)
        // 6: in 6 (1 time)
        // Max count is 2. Both 2 and 3 are valid answers. The problem asks for any.
        //
        // The only case where 2 might not be the unique answer is when l and r are small,
        // and some other number k has an equal count.
        // For example, l=3, r=6. Count for 2 is 2. Count for 3 is 2.
        // The problem states "If there are multiple answers, print any of them."
        //
        // Since 2 is the smallest prime number, it divides the most numbers on average.
        // For any range [l, r] with l < r, there will always be at least one even number
        // (unless r < 2, but l >= 2 is given).
        // If r - l >= 1, there is at least one even number.
        // If r - l >= 2, there are at least two even numbers.
        //
        // The number 2 will always be a divisor for at least floor((r-l+1)/2) numbers.
        // Any other number k > 2 will be a divisor for at most floor((r-l+1)/k) numbers.
        // Since 1/2 > 1/k for k > 2, 2 will generally have the highest count.
        //
        // The only edge case is when l=r. In this case, the only number is l, and its smallest divisor (other than 1) is the answer.
        // But the problem asks for "the integer that we wrote down the maximum number of times".
        // If l=r, there's only one number, l. Its divisors (excluding 1) are {d_1, d_2, ...}.
        // Each of these appears once. Any of them is a valid answer. The problem asks for "the integer".
        // If l=r, the answer is l itself (if l is prime) or its smallest prime factor.
        // However, the problem asks for *any* of them. So if l=r, l itself is a divisor of l, and it appears once.
        // So if l=r, printing l is a valid answer.
        //
        // Given l <= r, if l=r, print l.
        // Otherwise (l < r), print 2.
        // This covers all cases and satisfies the "print any" condition.
        //
        // Example 1: l=19, r=29. l < r. Output 2. Correct.
        // Example 2: l=3, r=6. l < r. Output 2. (Example output is 3, but 2 is also valid as explained above).
        //
        // This logic seems robust.

        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just p[pos[1]], which is [1].
        // min_idx and max_idx are already initialized to pos[1].
        // The length is 1, max is 1, min is 1. So m=1 is always beautiful.
        if (m == 1) {
            result += '1';
            continue;
        }

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' must be at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range
        // from min(pos[1], ..., pos[m]) to max(pos[1], ..., pos[m]).

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // satisfies the conditions for being a permutation of 1...m.
        // 1. Length must be m: (current_max_idx - current_min_idx + 1) == m
        // 2. Min element must be 1 (guaranteed by construction, as we always include pos[1])
        // 3. Max element must be m (guaranteed by construction, as we expand to include pos[m])
        // If these hold, and all numbers 1..m are distinct (which they are in a permutation),
        // then it's a permutation of 1..m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
