int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, we need d - 4 >= 0, which means d >= 4.
        // If d is 0, it's handled above.
        // So, for d > 0, if d < 4, there are no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // a^2 - d*a + d = 0
            // a = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b1 = (d - sqrt_discriminant) / 2.0

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is clearly positive, so a1 is positive.
            // For b1 = (d - sqrt(d^2 - 4d)) / 2.0 to be non-negative,
            // we need d >= sqrt(d^2 - 4d).
            // Squaring both sides (both are non-negative):
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So, both a1 and b1 are guaranteed to be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

