int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of A_piece = A_total / n = (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex. This cut forms a smaller triangle
    // similar to the original carrot. If the height of this smaller triangle is x,
    // its base length b_x is given by b_x / x = 1 / h, so b_x = x / h.
    // The area of this smaller triangle is A_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // The i-th cut (x_i) from the apex should enclose an area equal to i * A_piece.
    // So, A_{x_i} = i * A_piece.
    // x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
