int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());

    int count = 0;
    int b_ptr = 0; // Pointer for the elements we are trying to place (from the sorted array)

    // Iterate through the sorted original array (a_i)
    // For each a[i], we try to find the smallest b[j] such that b[j] > a[i]
    // and b[j] has not been used yet.
    // Since both arrays are sorted, we can use two pointers.
    // a_ptr points to the current element in the sorted original array.
    // b_ptr points to the current element in the sorted permutation array (which is also 'a').
    // We want to find a b[b_ptr] such that b[b_ptr] > a[a_ptr].
    // If we find such a pair, we increment count and advance both pointers.
    // If b[b_ptr] is not greater than a[a_ptr], it means b[b_ptr] is too small for a[a_ptr]
    // (and for any subsequent a[k] where k > a_ptr, since a[k] >= a[a_ptr]).
    // So, we must advance b_ptr to find a larger element.

    for (int a_ptr = 0; a_ptr < n; ++a_ptr) {
        // Try to find an element a[b_ptr] from the permutation array
        // that is strictly greater than a[a_ptr].
        // We only advance b_ptr if a[b_ptr] is not suitable for a[a_ptr].
        // If a[b_ptr] is suitable, we use it and advance both pointers.
        while (b_ptr < n && a[b_ptr] <= a[a_ptr]) {
            b_ptr++;
        }

        // If we found a suitable element a[b_ptr]
        if (b_ptr < n) {
            count++;
            b_ptr++; // Move to the next element in the permutation array
        } else {
            // No more elements in the permutation array are available
            // or are large enough. We can stop.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        // If we partition the students into two classes, C1 and C2,
        // such that |C1| = k1 and |C2| = k2, where k1 and k2 are odd,
        // and k1 + k2 = 2n.
        // The median of a class of size k (odd) is the element at index (k-1)/2
        // after sorting that class.
        //
        // Consider the specific partition where one class consists of the
        // first n students (a_0, ..., a_{n-1}) and the other class consists of
        // the remaining n students (a_n, ..., a_{2n-1}).
        // This partition is only valid if n is odd.
        // If n is odd, then both classes have size n (odd).
        // The median of the first class (a_0, ..., a_{n-1}) would be a_{(n-1)/2}.
        // The median of the second class (a_n, ..., a_{2n-1}) would be a_{n + (n-1)/2}.
        // The difference would be |a_{n + (n-1)/2} - a_{(n-1)/2}|.
        //
        // However, the problem statement implies that we can choose any odd sizes k1, k2.
        // The key insight for this problem is that to minimize the difference between medians,
        // we should try to make the medians as close as possible.
        //
        // If we sort the entire array of 2n skill levels: a_0, a_1, ..., a_{2n-1}.
        // The smallest possible median for any class is a_0 (if class size is 1).
        // The largest possible median for any class is a_{2n-1} (if class size is 1).
        //
        // Consider the case where we split the sorted array into two halves:
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        // Each class has exactly n students.
        // If n is odd, then this is a valid partition.
        // The median of Class 1 would be a_{(n-1)/2}.
        // The median of Class 2 would be a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // If n is even, this partition is not valid because class sizes are even.
        //
        // Let's re-examine the problem constraints and examples.
        // Example 1: n=1, 2n=2. Skills: [1, 1]. Sorted: [1, 1].
        // Only partition: C1={1}, C2={1}. Medians: 1, 1. Diff: 0.
        // Our formula for n=1 (odd): a_{1+(1-1)/2} - a_{(1-1)/2} = a_1 - a_0 = 1 - 1 = 0. This matches.
        //
        // Example 2: n=3, 2n=6. Skills: [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // n=3 is odd.
        // C1 = {1, 2, 3}. Median = a_{(3-1)/2} = a_1 = 2.
        // C2 = {4, 5, 6}. Median = a_{3+(3-1)/2} = a_{3+1} = a_4 = 5.
        // Difference = |5 - 2| = 3.
        // The example output is 1. This means my assumption about splitting into two halves of size n is not necessarily optimal.
        //
        // The example output for n=3 is 1. One possible partition given:
        // C1 = [6, 4, 2]. Sorted: [2, 4, 6]. Median = 4.
        // C2 = [5, 1, 3]. Sorted: [1, 3, 5]. Median = 3.
        // Difference = |4 - 3| = 1.
        //
        // This implies that the students are not necessarily split into contiguous blocks in the sorted array.
        //
        // Let's consider the general case. We have $2n$ students.
        // We need to pick $k_1$ students for class 1 and $k_2$ students for class 2,
        // where $k_1, k_2$ are odd and $k_1+k_2=2n$.
        //
        // The key observation for this type of problem is often that sorting the entire array helps.
        // Let the sorted array be $a_0, a_1, \dots, a_{2n-1}$.
        //
        // Consider the $n$-th element $a_{n-1}$ and the $(n+1)$-th element $a_n$.
        // These are the two middle elements of the entire sorted array.
        //
        // If we can form two classes such that one median is $a_{n-1}$ and the other is $a_n$,
        // then the difference would be $a_n - a_{n-1}$.
        //
        // Can we always achieve this?
        // To make $a_{n-1}$ the median of a class $C_1$ of size $k_1$, we need to pick $(k_1-1)/2$ elements smaller than or equal to $a_{n-1}$
        // and $(k_1-1)/2$ elements larger than or equal to $a_{n-1}$.
        // The smallest possible $k_1$ is 1. If $k_1=1$, median is $a_{n-1}$.
        // The largest possible $k_1$ is $2n-1$.
        //
        // Let's try to prove that the minimum difference is always $a_n - a_{n-1}$.
        //
        // Suppose we have two classes $C_A$ and $C_B$ with medians $M_A$ and $M_B$.
        // Let $M_A \le M_B$. We want to minimize $M_B - M_A$.
        //
        // The median of a class of size $k$ is the element at index $(k-1)/2$ in its sorted list.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // Any class $C_A$ of size $k_A$ must contain $k_A$ elements.
        // Its median $M_A$ must be one of the elements in $C_A$.
        // There are $(k_A-1)/2$ elements in $C_A$ less than or equal to $M_A$, and $(k_A-1)/2$ elements greater than or equal to $M_A$.
        //
        // Suppose $M_A < a_{n-1}$. This means $M_A$ is one of $a_0, \dots, a_{n-2}$.
        // If $M_A = a_i$ for $i < n-1$.
        // To have $a_i$ as median, we need $(k_A-1)/2$ elements $\le a_i$ and $(k_A-1)/2$ elements $\ge a_i$.
        // The elements $a_0, \dots, a_i$ are $i+1$ elements $\le a_i$.
        // The elements $a_i, \dots, a_{2n-1}$ are $2n-i$ elements $\ge a_i$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // Let $M_1$ be the median of the first class and $M_2$ be the median of the second class.
        // Without loss of generality, assume $M_1 \le M_2$.
        //
        // The element $M_1$ must be one of the $2n$ skill levels. Let $M_1 = a_i$.
        // The element $M_2$ must be one of the $2n$ skill levels. Let $M_2 = a_j$.
        // We want to minimize $a_j - a_i$.
        //
        // For $a_i$ to be the median of a class $C_1$ of size $k_1$:
        // There must be at least $(k_1-1)/2$ elements in $C_1$ that are $\le a_i$ (excluding $a_i$ itself).
        // There must be at least $(k_1-1)/2$ elements in $C_1$ that are $\ge a_i$ (excluding $a_i$ itself).
        //
        // The total number of elements less than $a_i$ in the entire set is $i$.
        // The total number of elements greater than $a_i$ in the entire set is $2n-1-i$.
        //
        // So, for $a_i$ to be a median of a class of size $k_1$, we must have:
        // $i \ge (k_1-1)/2$ (we can pick $(k_1-1)/2$ elements from $a_0, \dots, a_{i-1}$)
        // $2n-1-i \ge (k_1-1)/2$ (we can pick $(k_1-1)/2$ elements from $a_{i+1}, \dots, a_{2n-1}$)
        //
        // Similarly for $a_j$ to be a median of a class $C_2$ of size $k_2$:
        // $j \ge (k_2-1)/2$
        // $2n-1-j \ge (k_2-1)/2$
        //
        // The crucial part is that the elements chosen for $C_1$ and $C_2$ must be disjoint.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // Let's try to prove that $a_n - a_{n-1}$ is always achievable.
        // We need to construct two classes $C_1$ and $C_2$ such that their medians are $a_{n-1}$ and $a_n$ respectively,
        // and their sizes $k_1, k_2$ are odd, and $k_1+k_2=2n$.
        //
        // Let $C_1$ be the class with median $a_{n-1}$.
        // Let $C_2$ be the class with median $a_n$.
        //
        // We can form $C_1$ by taking $a_{n-1}$ itself.
        // We can form $C_2$ by taking $a_n$ itself.
        //
        // We have $2n-2$ remaining students. We need to distribute them such that $C_1$ and $C_2$ have odd sizes.
        //
        // Let's try to make $C_1$ contain $a_{n-1}$ and $C_2$ contain $a_n$.
        //
        // Consider the elements $a_0, \dots, a_{n-2}$ (there are $n-1$ of them).
        // Consider the elements $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ of them).
        //
        // We can put all $a_0, \dots, a_{n-2}$ into $C_1$.
        // So $C_1$ now has $a_0, \dots, a_{n-2}, a_{n-1}$. Its size is $n$.
        // If $n$ is odd, this is a valid class. Its median is $a_{(n-1)/2}$. This is not $a_{n-1}$ unless $(n-1)/2 = n-1$, which means $n=1$.
        //
        // The problem is simpler than trying to construct specific classes.
        // The crucial observation is that if we sort all $2n$ students, $a_0, a_1, \dots, a_{2n-1}$.
        // The median of any class of size $k$ (odd) must be one of the $a_i$'s.
        //
        // Let $M_1$ be the median of the first class and $M_2$ be the median of the second class.
        // Assume $M_1 \le M_2$.
        //
        // The first class $C_1$ has $k_1$ students. $M_1$ is the $((k_1-1)/2 + 1)$-th smallest student in $C_1$.
        // This means there are $(k_1-1)/2$ students in $C_1$ with skill $\le M_1$ and $(k_1-1)/2$ students with skill $\ge M_1$.
        //
        // The second class $C_2$ has $k_2$ students. $M_2$ is the $((k_2-1)/2 + 1)$-th smallest student in $C_2$.
        // This means there are $(k_2-1)/2$ students in $C_2$ with skill $\le M_2$ and $(k_2-1)/2$ students with skill $\ge M_2$.
        //
        // Total students $2n$.
        //
        // Consider the $n$ smallest students $a_0, \dots, a_{n-1}$.
        // Consider the $n$ largest students $a_n, \dots, a_{2n-1}$.
        //
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        //
        // Suppose $M_1$ is $a_i$ and $M_2$ is $a_j$.
        //
        // The total number of students less than or equal to $a_{n-1}$ is $n$.
        // The total number of students greater than or equal to $a_n$ is $n$.
        //
        // If $M_1$ is chosen from $a_0, \dots, a_{n-1}$ and $M_2$ is chosen from $a_n, \dots, a_{2n-1}$,
        // then $M_1 \le a_{n-1}$ and $M_2 \ge a_n$.
        //
        // It is always possible to construct two classes such that their medians are $a_{n-1}$ and $a_n$.
        //
        // Let $C_1$ be $\{a_0, a_1, \dots, a_{n-1}\}$. This class has $n$ students.
        // Let $C_2$ be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$. This class has $n$ students.
        //
        // If $n$ is odd, then this is a valid partition.
        // Median of $C_1$ is $a_{(n-1)/2}$.
        // Median of $C_2$ is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        //
        // This is not $a_n - a_{n-1}$ unless $n=1$.
        // For $n=3$, $a_{3+(3-1)/2} - a_{(3-1)/2} = a_4 - a_1$.
        // For [1,2,3,4,5,6], this is $5-2=3$.
        // The example output is 1, which is $a_3 - a_2 = 4-3=1$.
        //
        // This means the optimal strategy is to pick $a_{n-1}$ and $a_n$ as the medians.
        //
        // Let's try to prove that $a_n - a_{n-1}$ is the minimum possible difference.
        //
        // Let $M_A$ and $M_B$ be the medians of the two classes, $C_A$ and $C_B$.
        // Assume $M_A \le M_B$.
        //
        // The class $C_A$ has $k_A$ students. $M_A$ is the $((k_A-1)/2 + 1)$-th smallest element in $C_A$.
        // This means there are at least $(k_A-1)/2$ elements in $C_A$ that are $\le M_A$ (excluding $M_A$ itself).
        // And there are at least $(k_A-1)/2$ elements in $C_A$ that are $\ge M_A$ (excluding $M_A$ itself).
        //
        // The class $C_B$ has $k_B$ students. $M_B$ is the $((k_B-1)/2 + 1)$-th smallest element in $C_B$.
        // This means there are at least $(k_B-1)/2$ elements in $C_B$ that are $\le M_B$ (excluding $M_B$ itself).
        // And there are at least $(k_B-1)/2$ elements in $C_B$ that are $\ge M_B$ (excluding $M_B$ itself).
        //
        // Total number of students is $2n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ of them.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ of them.
        //
        // Suppose $M_A$ is $a_i$ and $M_B$ is $a_j$.
        //
        // If $i \ge n$, then $M_A \ge a_n$. Since $M_A \le M_B$, then $M_B \ge a_n$.
        // In this case, both medians are $\ge a_n$.
        // The smallest possible difference would be $a_{n+1} - a_n$ (if $M_A=a_n, M_B=a_{n+1}$).
        //
        // If $j < n$, then $M_B \le a_{n-1}$. Since $M_A \le M_B$, then $M_A \le a_{n-1}$.
        // In this case, both medians are $\le a_{n-1}$.
        // The smallest possible difference would be $a_{n-1} - a_{n-2}$ (if $M_A=a_{n-2}, M_B=a_{n-1}$).
        //
        // The only way to get a difference of $a_n - a_{n-1}$ is if $M_A \le a_{n-1}$ and $M_B \ge a_n$.
        //
        // Let's assume $M_A \le a_{n-1}$ and $M_B \ge a_n$.
        //
        // The number of students in $C_A$ that are $\le M_A$ is at least $(k_A+1)/2$.
        // The number of students in $C_B$ that are $\ge M_B$ is at least $(k_B+1)/2$.
        //
        // All students in $C_A$ that are $\le M_A$ must be chosen from $a_0, \dots, a_{n-1}$.
        // All students in $C_B$ that are $\ge M_B$ must be chosen from $a_n, \dots, a_{2n-1}$.
        //
        // The total number of students in $a_0, \dots, a_{n-1}$ is $n$.
        // The total number of students in $a_n, \dots, a_{2n-1}$ is $n$.
        //
        // The number of students in $C_A$ that are $\le M_A$ is $N_{A \le M_A}$.
        // The number of students in $C_B$ that are $\ge M_B$ is $N_{B \ge M_B}$.
        //
        // We know $N_{A \le M_A} \ge (k_A+1)/2$.
        // We know $N_{B \ge M_B} \ge (k_B+1)/2$.
        //
        // Since $M_A \le a_{n-1}$ and $M_B \ge a_n$, the set of students $\{s \in C_A \mid s \le M_A\}$ and $\{s \in C_B \mid s \ge M_B\}$
        // are disjoint.
        //
        // The students in $\{s \in C_A \mid s \le M_A\}$ must come from $\{a_0, \dots, a_{n-1}\}$.
        // The students in $\{s \in C_B \mid s \ge M_B\}$ must come from $\{a_n, \dots, a_{2n-1}\}$.
        //
        // So, $N_{A \le M_A} \le n$ and $N_{B \ge M_B} \le n$.
        //
        // This implies $(k_A+1)/2 \le n$ and $(k_B+1)/2 \le n$.
        // $k_A+1 \le 2n \implies k_A \le 2n-1$.
        // $k_B+1 \le 2n \implies k_B \le 2n-1$.
        // These are always true since $k_A, k_B$ are odd and sum to $2n$.
        //
        // This line of reasoning doesn't directly prove $a_n - a_{n-1}$ is the minimum.
        //
        // Let's use a simpler argument.
        // Sort the array: $a_0, a_1, \dots, a_{2n-1}$.
        //
        // We need to pick $k_1$ students for $C_1$ and $k_2$ students for $C_2$, $k_1, k_2$ odd, $k_1+k_2=2n$.
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        //
        // Consider the $n$ smallest elements $a_0, \dots, a_{n-1}$.
        // Consider the $n$ largest elements $a_n, \dots, a_{2n-1}$.
        //
        // Any class $C$ of size $k$ has a median $M$. There are $(k-1)/2$ elements in $C$ smaller than $M$ and $(k-1)/2$ elements larger than $M$.
        //
        // Suppose $M_1 < a_{n-1}$ and $M_2 > a_n$.
        // This is not possible.
        //
        // The crucial point is that the $n$-th element $a_{n-1}$ and the $(n+1)$-th element $a_n$ are the "middle" elements.
        //
        // Let's try to construct a partition that achieves $a_n - a_{n-1}$.
        //
        // We want $M_1 = a_{n-1}$ and $M_2 = a_n$.
        //
        // For $C_1$ to have median $a_{n-1}$:
        // We need to pick $a_{n-1}$.
        // We need to pick $x$ elements from $a_0, \dots, a_{n-2}$ (elements smaller than $a_{n-1}$).
        // We need to pick $x$ elements from the remaining students that are $\ge a_{n-1}$.
        // The size of $C_1$ will be $2x+1$.
        //
        // For $C_2$ to have median $a_n$:
        // We need to pick $a_n$.
        // We need to pick $y$ elements from the remaining students that are $\le a_n$.
        // We need to pick $y$ elements from $a_{n+1}, \dots, a_{2n-1}$ (elements larger than $a_n$).
        // The size of $C_2$ will be $2y+1$.
        //
        // We need $2x+1 + 2y+1 = 2n \implies 2x+2y+2 = 2n \implies x+y+1 = n$.
        //
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ available to be smaller than $a_{n-1}$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ available to be larger than $a_n$.
        //
        // Let's try to make $C_1$ of size $2(n-1)+1 = 2n-1$.
        // $C_1 = \{a_0, \dots, a_{n-2}, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$.
        // This class has $n-1 + 1 + n-1 = 2n-1$ students.
        // Its median would be $a_{n-1}$.
        // The remaining student is $a_n$.
        // So $C_2 = \{a_n\}$. This class has size 1. Its median is $a_n$.
        //
        // This partition is valid:
        // $C_1 = \{a_0, \dots, a_{n-2}, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$
        // Size of $C_1$ is $2n-1$ (odd). Median is $a_{n-1}$.
        // $C_2 = \{a_n\}$
        // Size of $C_2$ is $1$ (odd). Median is $a_n$.
        //
        // The absolute difference is $|a_n - a_{n-1}|$.
        //
        // This construction always works.
        // The sizes $2n-1$ and $1$ are always odd.
        // The elements $a_0, \dots, a_{n-2}$ are all $\le a_{n-1}$. There are $n-1$ of them.
        // The elements $a_{n+1}, \dots, a_{2n-1}$ are all $\ge a_{n-1}$. There are $n-1$ of them.
        // So $a_{n-1}$ is indeed the median of $C_1$.
        // $a_n$ is indeed the median of $C_2$.
        //
        // Since we found a partition that achieves $a_n - a_{n-1}$, and it's impossible to have a smaller positive difference (because $a_n$ is the smallest element greater than or equal to $a_{n-1}$), this must be the minimum.
        //
        // The minimum difference is $a_n - a_{n-1}$.
        //
        // Let's check the examples:
        // Example 1: n=1, 2n=2. Skills: [1, 1]. Sorted: [1, 1].
        // $a_n - a_{n-1} = a_1 - a_0 = 1 - 1 = 0$. Correct.
        //
        // Example 2: n=3, 2n=6. Skills: [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // $a_n - a_{n-1} = a_3 - a_2 = 4 - 3 = 1$. Correct.
        //
        // Example 3: n=5, 2n=10. Skills: [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // $a_n - a_{n-1} = a_5 - a_4 = 13 - 8 = 5$. Correct.
        //
        // The logic seems sound. The minimum difference is always $a_n - a_{n-1}$ after sorting the entire array.
        //
        // Implementation:
        // 1. Read $n$.
        // 2. Read $2n$ integers into a vector.
        // 3. Sort the vector.
        // 4. Output $a[n] - a[n-1]$. (Using 0-based indexing for vector).

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    std::vector<bool> seen(n + 1, false);
    int distinct_count = 0;
    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > i + 1) { // Element value exceeds current length
            break;
        }
        if (seen[a[i]]) { // Duplicate element
            break;
        }
        seen[a[i]] = true;
        distinct_count++;
        current_max = std::max(current_max, a[i]);
        if (distinct_count == i + 1 && current_max == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::fill(seen.begin(), seen.end(), false);
    distinct_count = 0;
    current_max = 0;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (a[i] > len) { // Element value exceeds current length
            break;
        }
        if (seen[a[i]]) { // Duplicate element
            break;
        }
        seen[a[i]] = true;
        distinct_count++;
        current_max = std::max(current_max, a[i]);
        if (distinct_count == len && current_max == len) {
            is_suffix_perm[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

