    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Fill A' by pairing largest A with largest B, second largest A with second largest B, etc.
    // This is equivalent to pairing a[i] with b_indexed[i].first
    // The original index of b_indexed[i].first is b_indexed[i].second
    for (int i = 0; i < m; ++i) {
        a_prime[b_indexed[i].second] = a[i];
    }

