#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check for the increasing part from left
    // We need a_i >= i-1 for 0 <= i < k
    // The maximum possible k is n-1 (0-indexed)
    // So we need a_i >= i for 0 <= i < n-1
    // The first element a[0] must be at least 0.
    // The second element a[1] must be at least 1.
    // ...
    // The i-th element a[i] must be at least i.
    // This is for the case where k is the last element.
    // If k is not the last element, say k-1 (0-indexed), then a[k-1] must be at least k-1.
    // The condition is a[i] >= i for the increasing part.
    // Let's find the maximum index `left_reach` such that a[i] >= i for all 0 <= i <= left_reach.
    int left_reach = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_reach = i;
        } else {
            break;
        }
    }

    // Check for the decreasing part from right
    // We need a_i >= n-1-i for k <= i < n
    // The maximum possible k is 0 (0-indexed)
    // So we need a[i] >= n-1-i for 0 <= i < n
    // The last element a[n-1] must be at least 0.
    // The second to last a[n-2] must be at least 1.
    // ...
    // The i-th element a[i] must be at least n-1-i.
    // Let's find the minimum index `right_reach` such that a[i] >= n-1-i for all right_reach <= i < n.
    int right_reach = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_reach = i;
        } else {
            break;
        }
    }

    // If there is any overlap between the reachable indices, it's possible.
    // An overlap means there exists an index `k` (0-indexed) such that
    // `k` is reachable from the left (a[k] >= k) AND
    // `k` is reachable from the right (a[k] >= n-1-k).
    // This means `left_reach` must be greater than or equal to `right_reach`.
    if (left_reach >= right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

