            s += ((n % 10) % 2 == 0 ? '0' : '1');
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding with '0's from the left in the original number
    // because we built the string from right to left digits.
    while (s.length() < 18) {
        s += '0';
    }
    return s;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    // The key is the 18-character parity pattern string, value is its count.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s_query;
            std::cin >> s_query;

            // Pad the query pattern with '0's from the left to make it 18 characters long.
            // This means appending '0's to the right of the string representation.
            while (s_query.length() < 18) {
                s_query = '0' + s_query; // Prepend '0'
            }
            // The get_parity_pattern function generates patterns by taking digits from right to left
            // and appending their parity to a string. So the 0th index of the string corresponds
            // to the rightmost digit's parity.
            // The query pattern is given as "010" where 0 is for the rightmost digit.
            // So, if s_query is "010", it means rightmost digit parity 0, next 1, next 0.
            // Our stored patterns are also built this way.
            // Example: 92 -> "10" (9 is odd, 2 is even).
            // If query is "010", it means rightmost digit parity 0, next 1, next 0.
            // So we need to reverse the query string to match the format of stored patterns.
            std::reverse(s_query.begin(), s_query.end());

            std::cout << pattern_counts[s_query] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for counts of 'x', 'y', 'z'
    // counts[0][i] = count of 'x' in s[0...i-1]
    // counts[1][i] = count of 'y' in s[0...i-1]
    // counts[2][i] = count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;
        // Adjust to 0-indexed
        --l; 
        --r;

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l...r]
        int count_x = counts[0][r + 1] - counts[0][l];
        int count_y = counts[1][r + 1] - counts[1][l];
        int count_z = counts[2][r + 1] - counts[2][l];

        // Check if the counts are "balanced" enough
        // The difference between max and min count should be at most 1
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
