char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Determine the most frequent bot move.
        // If counts are equal, 'P' > 'R' > 'S' lexicographically.
        // The problem statement implies any optimal answer is fine.
        // So, we can just pick one based on iteration order or any consistent rule.
        // Let's prioritize P, then R, then S if counts are equal.
        // This is equivalent to iterating through 'P', 'R', 'S' and checking counts.

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        // If counts are equal, the one checked last (P) will be chosen.
        // If R, S, P all have 0 count (empty string, not possible by constraints),
        // most_frequent_bot_move would be ' ' and max_count -1.
        // But n >= 1, so at least one char exists.

        char my_optimal_move = get_winning_move(most_frequent_bot_move);

        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << my_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

