            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            if (f1 == 0) { // Cannot move left (x-1, y), so target X must be >= current x
                min_x = std::max(min_x, x);
            }
            if (f2 == 0) { // Cannot move up (x, y+1), so target Y must be <= current y
                max_y = std::min(max_y, y);
            }
            if (f3 == 0) { // Cannot move right (x+1, y), so target X must be <= current x
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down (x, y-1), so target Y must be >= current y
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists with coordinates
            // not exceeding 10^5 by absolute value.
            // Our calculated min_x, max_x, min_y, max_y could be outside this range
            // if all robots have full movement capabilities and start far away.
            // However, any point within [min_x, max_x] x [min_y, max_y] is a valid target.
            // We can pick any point, for example (min_x, min_y).
            // The problem statement implies that if a valid point exists, one with
            // coordinates within [-10^5, 10^5] exists.
            // So, we can just output min_x and min_y, as they will be within the guaranteed range
            // if a solution exists.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

