// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means we need to remove some prime factors from p such that the resulting number
        // is no longer divisible by q, but is as large as possible.

        // Get prime factors of q.
        // We only care about prime factors of q that are also factors of p.
        // If a prime factor of q is not a factor of p, then p cannot be divisible by q,
        // which contradicts our check `p % q != 0`.
        // So, all prime factors of q must also be prime factors of p.
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        for (long long factor : q_prime_factors) {
            // For each prime factor `factor` of `q`:
            // We want to find the largest `x` that is a divisor of `p` but not divisible by `q`.
            // Consider `p_temp = p`. We divide `p_temp` by `factor` until it's no longer divisible by `q`.
            // This means we remove exactly one `factor` from `p`'s prime factorization
            // such that `p / factor` is no longer divisible by `q`.
            // More precisely, we remove `factor` from `p` until `p_temp` has a lower power of `factor`
            // than `q` has.

            long long current_p = p;
            while (current_p % factor == 0) {
                current_p /= factor;
                if (current_p % q != 0) {
                    max_x = std::max(max_x, current_p);
                }
            }
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;
    sum_r_term = (sum_r_term * modInverse(2)) % MOD;

    // Sum of (k*b + 1) from k=1 to a:
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_term_part1 = (a % MOD);
    sum_k_term_part1 = (sum_k_term_part1 * ((a + 1) % MOD)) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * modInverse(2)) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * (b % MOD)) % MOD;

    long long sum_k_term_part2 = (a % MOD);

    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

