void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'.
    // We use this to set '1's in w to '0's.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this constructed w can produce s.
    // For each s_i, check if it matches the rule based on w.
    for (int i = 0; i < n; ++i) {
        bool s_i_should_be_1 = false;
        if (i - x >= 0 && w[i - x] == '1') {
            s_i_should_be_1 = true;
        }
        if (i + x < n && w[i + x] == '1') {
            s_i_should_be_1 = true;
        }

        if ((s[i] == '1' && !s_i_should_be_1) || (s[i] == '0' && s_i_should_be_1)) {
            // Mismatch found: s[i] is '1' but our w produces '0', OR
            // s[i] is '0' but our w produces '1'.
            // The second case (s[i] == '0' && s_i_should_be_1) should not happen
            // if our logic for setting w is correct, because if s[i] was '0',
            // we would have set w[i-x] and w[i+x] to '0' if they exist.
            // So, if s_i_should_be_1 is true, it means either w[i-x] or w[i+x] is '1'.
            // But if s[i] was '0', we would have forced them to '0'.
            // This implies that if s[i] is '0', s_i_should_be_1 must be false.
            // So the only problematic case is s[i] == '1' and !s_i_should_be_1.
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

