            // If B_j = 1, (1 | 1) ^ (1 - 1) = 1 ^ 0 = 1. This does not work.
            // So we must have B_j = 0, which implies C_j = 1.
            // This means `and_const` gets a 1, `or_const` gets a 0, `xor_const` gets a 1.
            xor_const |= (1 << j);
        } else { // current_val_if_0[j] == 1 && current_val_if_1[j] == 1
            // Input bit j -> 1.
            // (0 & A_j | B_j) ^ C_j = 1
            // (1 & A_j | B_j) ^ C_j = 1
            // This implies A_j can be 0 or 1.
            // If A_j = 0: (0 | B_j) ^ C_j = 1. So B_j ^ C_j = 1.
            // If A_j = 1: (0 | B_j) ^ C_j = 1 and (1 | B_j) ^ C_j = 1.
            //   So B_j ^ C_j = 1 and (1 | B_j) ^ C_j = 1.
            //   From B_j ^ C_j = 1, C_j = 1 - B_j.
            //   Then (1 | B_j) ^ (1 - B_j) = 1.
            //   If B_j = 0, (1 | 0) ^ (1 - 0) = 1 ^ 1 = 0. Does not work.
            //   If B_j = 1, (1 | 1) ^ (1 - 1) = 1 ^ 0 = 1. This works.
            // So we must have A_j = 1, B_j = 1, C_j = 0.
            // This means `and_const` gets a 1, `or_const` gets a 1, `xor_const` gets a 0.
            or_const |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (and_const != ((1 << 10) - 1)) { // If not all 1s, then & operation is needed
        result_ops.push_back({'&', and_const});
    }
    if (or_const != 0) { // If not all 0s, then | operation is needed
        result_ops.push_back({'|', or_const});
    }
    if (xor_const != 0) { // If not all 0s, then ^ operation is needed
        result_ops.push_back({'^', xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

