#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <map>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i - 1]);
            adj[s[i - 1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;
    char current_char = '\0';

    // Find a starting character for the main chain
    // A starting character must be part of the password and have only one neighbor
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            current_char = c;
            break;
        }
    }

    // If no character has 1 neighbor, it means all characters in s have 2 neighbors (a cycle)
    // OR s has only one unique character (e.g., "a"), or two unique characters (e.g., "ababa")
    // If s has only one unique character, adj will be empty for it.
    // If s has two unique characters, say 'a' and 'b', adj['a']={b}, adj['b']={a}.
    // In these cases, any character from used_in_s can be a start.
    if (current_char == '\0' && !used_in_s.empty()) {
        current_char = *used_in_s.begin();
    }

    if (current_char != '\0') { // If there are characters in the password
        char prev_char = '\0';
        while (current_char != '\0' && visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout_str += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Add remaining characters not in the password
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    if (layout_str.length() != 26) {
        std::cout << "NO\n";
    } else {
        std::cout << "YES\n";
        std::cout << layout_str << "\n";
    }
}

