#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int x = 0; x <= 9; ++x) {
        std::vector<int> colors(n);
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_x = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                colors[i] = 1;
                s1_digits.push_back(d[i]);
            } else if (d[i] > x) {
                colors[i] = 2;
                s2_digits.push_back(d[i]);
            } else { // d[i] == x
                // Try to assign to color 2 first, if possible
                // This means d[i] is the first 'x' in S2, or after an 'x' in S2
                // If S2 is empty or its last element is <= x, assign to S2
                if (s2_digits.empty() || s2_digits.back() <= x) {
                    colors[i] = 2;
                    s2_digits.push_back(d[i]);
                } else { // Must assign to color 1
                    colors[i] = 1;
                    s1_digits.push_back(d[i]);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        // If we reach here, this coloring is valid for this x
        for (int i = 0; i < n; ++i) {
            std::cout << colors[i];
        }
        std::cout << "\n";
        return;
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

