bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for tracks to be covered
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long current_p = p[p_idx];

        // If current head cannot reach current_p even by moving left for T time
        if (current_h + T < current_p) {
            continue; // This head cannot cover current_p, try next head
        }

        // If current head can reach current_p
        // We need to find the rightmost track this head can cover, starting from current_p
        long long reach_left = current_h - T;
        long long reach_right = current_h + T;

        // Case 1: current_p is to the left of current_h
        // The head moves left to cover current_p.
        // Time spent moving left to current_p is current_h - current_p.
        // Remaining time is T - (current_h - current_p).
        // This remaining time can be used to move further left or right from current_p.
        // The rightmost point it can reach is current_p + remaining_time.
        // So, current_p + (T - (current_h - current_p)) = current_p + T - current_h + current_p = 2*current_p + T - current_h.
        // This is valid if current_p <= current_h.
        long long max_reach_from_left_move = -1;
        if (current_p <= current_h) {
            max_reach_from_left_move = current_p + (T - (current_h - current_p));
        }

        // Case 2: current_p is to the right of current_h
        // The head moves right to cover current_p.
        // Time spent moving right to current_p is current_p - current_h.
        // Remaining time is T - (current_p - current_h).
        // This remaining time can be used to move further right or left from current_p.
        // The rightmost point it can reach is current_p + remaining_time.
        // So, current_p + (T - (current_p - current_h)) = current_p + T - current_p + current_h = T + current_h.
        // This is valid if current_p >= current_h.
        long long max_reach_from_right_move = -1;
        if (current_p >= current_h) {
            max_reach_from_right_move = current_p + (T - (current_p - current_h));
        }

        // The actual rightmost point this head can cover, starting from current_p, is the maximum of these two.
        // If current_p is between reach_left and reach_right, it can cover current_p.
        // The maximum rightmost point it can cover is determined by the strategy:
        // 1. Move left to current_p, then sweep right. Max reach: current_p + (T - (current_h - current_p))
        // 2. Move right to current_p, then sweep right. Max reach: current_p + (T - (current_p - current_h))
        // The maximum of these two is the effective rightmost point.
        // Note that if current_p is to the left of current_h, only strategy 1 is relevant for covering current_p.
        // If current_p is to the right of current_h, only strategy 2 is relevant for covering current_p.
        // If current_p == current_h, both are relevant and give current_h + T.

        long long effective_reach_right = -1;
        if (current_p <= current_h) { // current_p is to the left or at current_h
            effective_reach_right = current_p + (T - (current_h - current_p));
        } else { // current_p is to the right of current_h
            effective_reach_right = current_p + (T - (current_p - current_h));
        }

        // Now, advance p_idx as long as tracks are covered by this head
        while (p_idx < m && p[p_idx] <= effective_reach_right) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

