#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long total_spells = 0;

    // We can only copy from the smallest pile (a[0]) to other piles.
    // For each other pile a[i] (where i > 0), we can add a[0] to it
    // (k - a[i]) / a[0] times.
    // The sum of these counts is the maximum number of spells.
    for (int i = 1; i < n; ++i) {
        if (a[i] < k) { // Only add if the target pile is not already at or above k
            total_spells += (k - a[i]) / min_val;
        }
    }

    std::cout << total_spells << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

