    // This means successful_a / total_sent_a >= 0.5
    // Or, 2 * successful_a >= total_sent_a
    if (2 * successful_a >= total_sent_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    // Check server 'b'
    if (2 * successful_b >= total_sent_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    return 0;
}

