#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];

    for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
        int pile_idx = i + 1; // Pile number (1-indexed)
        int haybales_in_pile = a[i];
        int cost_per_haybale = pile_idx - 1; // Days to move one haybale from pile_idx to pile 1

        if (d < cost_per_haybale) {
            // Not enough days to move even one haybale from this pile
            break; 
        }

        // Calculate how many haybales can be moved from this pile
        // Limited by available haybales and available days
        int haybales_can_move_from_this_pile = std::min(haybales_in_pile, d / cost_per_haybale);

        current_a1 += haybales_can_move_from_this_pile;
        d -= haybales_can_move_from_this_pile * cost_per_haybale;
    }

    std::cout << current_a1 << std::endl;
}

