#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is equal to n-1. If so, it means n was not present in any min(p_i, p_j)
    // for that specific p_i. This happens if p_i itself is n.
    // If n is not present in any p[i] calculated so far, it means the actual value n
    // must be assigned to one of the p[i] that currently holds n-1.
    // Since the problem guarantees a solution, there will be exactly one such p[i]
    // that should be n, and all other p[j] will be correctly determined.
    bool n_found = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n was not found, it means the actual value n was never the minimum
        // in any pair (p_i, p_j) where p_i is the larger value.
        // This implies that one of the p_i values must be n, and for that p_i,
        // all a[i][j] (j!=i) would be p[j].
        // The maximum of these p[j] would be n-1 (since n is the largest).
        // So, one of the p[i] values that is currently n-1 should actually be n.
        // Since all other values 1 to n-1 must be present, there can be only one such p[i].
        // We can just find the first occurrence of n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
