void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The number will start with '2' and end with '3'.
        // All intermediate digits will be '7'.
        // Example: n=2 -> 23
        //          n=3 -> 273
        //          n=4 -> 2773
        // This construction ensures:
        // 1. All digits are non-zero (2, 3, 7).
        // 2. The number has n digits.
        // 3. Divisibility by 2: The number ends in 3, so it's odd and not divisible by 2.
        // 4. Divisibility by 3: The sum of digits is 2 + (n-2)*7 + 3 = 5 + 7n - 14 = 7n - 9.
        //    For 7n - 9 to be divisible by 3, 7n must be divisible by 3. Since 7 is not divisible by 3,
        //    n must be divisible by 3.
        //    If n is divisible by 3, then 7n-9 is divisible by 3, and the number is divisible by 3.
        //    This construction fails if n is a multiple of 3.
        //
        // Let's try a different construction:
        // Start with '2', then (n-1) '3's.
        // Example: n=2 -> 23
        //          n=3 -> 233
        //          n=4 -> 2333
        // Digits are 2, 3. All non-zero.
        // Divisibility by 2: Ends in 3, so not divisible by 2.
        // Divisibility by 3: Sum of digits is 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    For 3n - 1 to be divisible by 3, -1 must be divisible by 3, which is false.
        //    So, 3n - 1 is never divisible by 3.
        // This construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

