    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available divided by 3 (each team needs 3 students).
        // So, the number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3
        // Therefore, k <= min(c, m, (c + m + x) / 3).
        // Let's check if this minimum is always achievable.
        // If we form k teams, we need k coders, k mathematicians, and k "third" members.
        // The k coders come from 'c'.
        // The k mathematicians come from 'm'.
        // The k "third" members can be:
        //   - students with no specialization ('x')
        //   - remaining coders (c - k)
        //   - remaining mathematicians (m - k)
        // The total number of "third" members available is x + (c - k) + (m - k).
        // We need to ensure that we have enough "third" members for k teams.
        // Each team needs 3 members. If we use k coders and k mathematicians,
        // we have used 2k students. We need k more students.
        // These k students can come from 'x', or from the remaining 'c-k' coders,
        // or from the remaining 'm-k' mathematicians.
        // The total number of students available for these 'k' third slots is
        // x + (c - k) + (m - k).
        // We need this to be at least k.
        // x + c - k + m - k >= k
        // x + c + m >= 3k
        // (c + m + x) / 3 >= k
        // This condition is already included in our minimum.
        // So, the maximum number of teams is indeed limited by the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

