void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // After this loop, a[i...n-1] is non-decreasing.
    // If i=0, the whole array is non-decreasing.
    // If i>0, then a[i-1] > a[i].

    // Now, find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // We start from `i-1` because we are looking for a prefix to the non-decreasing suffix.
    // If i=0, this part is skipped.
    int j = i; // If i=0, j remains 0. If i>0, j starts at i.
    if (i > 0) {
        j = i - 1;
        while (j > 0 && a[j-1] >= a[j]) {
            j--;
        }
        // After this loop, a[j...i-1] is non-increasing.
        // If j=0, then a[0...i-1] is non-increasing.
        // If j>0, then a[j-1] < a[j].
    }

    // The length of the prefix to erase is `j`.
    // The remaining suffix is a[j...n-1].
    // This suffix consists of a non-increasing part a[j...i-1] (if i>j)
    // followed by a non-decreasing part a[i...n-1].
    // This structure (non-increasing then non-decreasing) is a good array.
    std::cout << j << std::endl;
}

