int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m;

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute the sum of last digits for one full cycle of 10 multiples
        // The last digits of m*1, m*2, ..., m*10 are (m%10)*1%10, (m%10)*2%10, ..., (m%10)*10%10
        // This is incorrect. The last digit of m*k is (m*k)%10.
        // The sequence of last digits (m*1)%10, (m*2)%10, ... (m*k)%10 repeats every 10 terms.
        // For example, (m*1)%10, (m*2)%10, ..., (m*10)%10
        // Then (m*11)%10 = (m*10 + m*1)%10 = (m*1)%10
        // So the cycle length is 10.

        std::vector<long long> cycle_last_digits(10);
        long long sum_of_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits[i - 1] = (m * i) % 10;
            sum_of_cycle += cycle_last_digits[i - 1];
        }

        long long num_full_cycles = count / 10;
        long long remaining_terms = count % 10;

        long long total_sum = num_full_cycles * sum_of_cycle;

        for (int i = 0; i < remaining_terms; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

