int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant = d^2 - 4d
            // For real solutions, d^2 - 4d >= 0
            // d(d - 4) >= 0
            // Since d >= 0, this means d - 4 >= 0, so d >= 4.
            // If d = 0, d^2 - 4d = 0, which is also valid.
            // The problem statement says d is non-negative.
            // So, if 0 < d < 4, there are no real solutions.
            // If d = 0 or d >= 4, there are real solutions.

            double sqrt_discriminant = std::sqrt(d * d - 4 * d);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a, b >= 0.
            // Since d >= 0, d + sqrt_discriminant is always >= 0, so a1 >= 0.
            // For b1, we need d - sqrt_discriminant >= 0.
            // This is equivalent to d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, both a1 and b1 will always be non-negative
            // when d^2 - 4d >= 0.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
