int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.
                             // If last_R_pos = k, it means the frog is at cell k.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed).
                // The distance from the previous 'R' (or 0) to this 'R' is (i+1) - (last_R_pos + 1) + 1
                // which simplifies to (i+1) - last_R_pos.
                // Example: last_R_pos = -1 (at 0), current 'R' at index i=0 (cell 1). Distance = (0+1) - (-1) = 2.
                // Example: last_R_pos = 0 (at cell 1), current 'R' at index i=2 (cell 3). Distance = (2+1) - 0 = 3.
                max_dist = std::max(max_dist, (i + 1) - (last_R_pos + 1) + 1);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or 0) to n+1.
        // If last_R_pos = -1, it means no 'R' was found, so the string is all 'L's.
        // In this case, the jump is from 0 to n+1. Distance = (n+1) - 0 = n+1.
        // If last_R_pos = k, it means the last 'R' was at index k (cell k+1).
        // The jump is from cell k+1 to n+1. Distance = (n+1) - (k+1) = n - k.
        max_dist = std::max(max_dist, (n + 1) - (last_R_pos + 1) + 1);

        std::cout << max_dist << "\n";
    }
    return 0;
}

