// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: (-inf, -1]
    // Final toy must be negative and magnitude >= 1.

    // Case 1: Total toys is 1.
    if (A + B + C + D == 1) {
        return A == 1;
    }

    // Case 2: Total toys > 1.
    // To get a negative result, we need an odd number of negative factors.
    // To get magnitude >= 1, we need to be able to achieve it.

    // Count of negative toys: A + B
    long long neg_count = A + B;

    // If neg_count is even, the final product will be positive.
    // So Box 1 is impossible.
    if (neg_count % 2 == 0) {
        return false;
    }

    // If neg_count is odd, the final product will be negative.
    // Now we need to check if magnitude >= 1 is possible.

    // If there's at least one toy in Box 1 (magnitude >= 1),
    // and we can ensure that it's not "diluted" by too many Box 2/3 toys.
    // The most robust way to get magnitude >= 1 is to have a Box 1 or Box 4 toy.
    // If A > 0 or D > 0, we have at least one toy with magnitude >= 1.
    // If we can combine it with other toys such that the final magnitude is >= 1, it's possible.
    // The only way to guarantee magnitude < 1 is if all initial toys have magnitude < 1 (B+C > 0, A=D=0).
    // If A=0 and D=0, then all initial toys are in B2 or B3.
    // In this case, all products will have magnitude < 1.
    // So if A=0 and D=0, Box 1 is impossible.
    if (A == 0 && D == 0) {
        return false;
    }

    // If neg_count is odd AND (A > 0 or D > 0), then it's possible.
    // We can always arrange multiplications to keep magnitude >= 1 if we start with one.
    // E.g., if we have a toy with value X >= 1 (from B4 or B1), and other toys are Y_i.
    // We can multiply X with a toy from B2 or B3 (say 0.5). Result is 0.5X.
    // If we have another toy Z >= 1, we can multiply X*Z to get XZ >= 1.
    // The key is that if we have at least one toy with magnitude >= 1 (from A or D),
    // and we need a negative result (odd neg_count), we can achieve it.
    // We can always pair up toys from B2 and B3 to make their product small,
    // or pair up B1/B4 toys to keep magnitude large.
    // The only way to fail is if all toys are in B2/B3 (A=D=0), which we already checked.
    // Or if neg_count is even.
    return true;
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: (-1, 0)
    // Final toy must be negative and magnitude < 1.

    // Case 1: Total toys is 1.
    if (A + B + C + D == 1) {
        return B == 1;
    }

    // Case 2: Total toys > 1.
    // To get a negative result, we need an odd number of negative factors.
    long long neg_count = A + B;

    // If neg_count is even, the final product will be positive.
    // So Box 2 is impossible.
    if (neg_count % 2 == 0) {
        return false;
    }

    // If neg_count is odd, the final product will be negative.
    // Now we need to check if magnitude < 1 is possible.

    // If A=0 and D=0, all initial toys are in B2 or B3.
    // In this case, all products will have magnitude < 1.
    // Since neg_count is odd, the result will be negative and magnitude < 1.
    // So if A=0 and D=0, Box 2 is possible.
    if (A == 0 && D == 0) {
        return true;
    }

    // If A > 0 or D > 0, we have at least one toy with magnitude >= 1.
    // Can we still make the final magnitude < 1?
    // Yes, if we have enough toys with magnitude < 1 (from B or C) to "dilute" the large magnitudes.
    // We need at least one toy from B or C to multiply with a toy from A or D to reduce magnitude.
    // If B + C == 0, then all toys are in A or D.
    // If B + C == 0, and A + D > 1, then all products will have magnitude >= 1.
    // So if B + C == 0, Box 2 is impossible.
    if (B + C == 0) {
        return false;
    }

    // If neg_count is odd AND (A > 0 or D > 0) AND (B > 0 or C > 0),
    // it's possible to get a negative result with magnitude < 1.
    // Example: Take a toy X from A or D (mag >= 1). Take a toy Y from B or C (mag < 1).
    // Multiply X * Y. The result has magnitude < 1.
    // We can then combine this (mag < 1) toy with other toys.
    // If we have an odd number of negative toys, and at least one toy with mag >= 1,
    // and at least one toy with mag < 1, we can achieve a final negative toy with mag < 1.
    // We can pair up all B1/B4 toys with B2/B3 toys to reduce magnitude.
    // The only edge case is if we have only one toy with magnitude < 1 (B+C=1) and many with magnitude >= 1.
    // E.g., A=1, B=1, C=0, D=1. Neg_count=2 (even). Not possible.
    // E.g., A=1, B=1, C=0, D=0. Neg_count=2 (even). Not possible.
    // E.g., A=0, B=1, C=0, D=0. Neg_count=1 (odd). B=1. Possible.
    // E.g., A=1, B=1, C=1, D=0. Neg_count=2 (even). Not possible.
    // E.g., A=1, B=0, C=1, D=0. Neg_count=1 (odd). A=1, C=1. Multiply A_toy * C_toy. Result is negative, mag < 1. Possible.
    // The conditions are: neg_count is odd, and (A+D > 0) and (B+C > 0).
    return true;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: (0, 1)
    // Final toy must be positive and magnitude < 1.

    // Case 1: Total toys is 1.
    if (A + B + C + D == 1) {
        return C == 1;
    }

    // Case 2: Total toys > 1.
    // To get a positive result, we need an even number of negative factors.
    long long neg_count = A + B;

    // If neg_count is odd, the final product will be negative.
    // So Box 3 is impossible.
    if (neg_count % 2 == 1) {
        return false;
    }

    // If neg_count is even, the final product will be positive.
    // Now we need to check if magnitude < 1 is possible.

    // If A=0 and D=0, all initial toys are in B2 or B3.
    // In this case, all products will have magnitude < 1.
    // Since neg_count is even, the result will be positive and magnitude < 1.
    // So if A=0 and D=0, Box 3 is possible.
    if (A == 0 && D == 0) {
        return true;
    }

    // If A > 0 or D > 0, we have at least one toy with magnitude >= 1.
    // Can we still make the final magnitude < 1?
    // Yes, if we have enough toys with magnitude < 1 (from B or C) to "dilute" the large magnitudes.
    // We need at least one toy from B or C to multiply with a toy from A or D to reduce magnitude.
    // If B + C == 0, then all toys are in A or D.
    // If B + C == 0, and A + D > 1, then all products will have magnitude >= 1.
    // So if B + C == 0, Box 3 is impossible.
    if (B + C == 0) {
        return false;
    }

    // If neg_count is even AND (A > 0 or D > 0) AND (B > 0 or C > 0),
    // it's possible to get a positive result with magnitude < 1.
    // Similar logic to Box 2, but for even neg_count.
    return true;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: [1, inf)
    // Final toy must be positive and magnitude >= 1.

    // Case 1: Total toys is 1.
    if (A + B + C + D == 1) {
        return D == 1;
    }

    // Case 2: Total toys > 1.
    // To get a positive result, we need an even number of negative factors.
    long long neg_count = A + B;

    // If neg_count is odd, the final product will be negative.
    // So Box 4 is impossible.
    if (neg_count % 2 == 1) {
        return false;
    }

    // If neg_count is even, the final product will be positive.
    // Now we need to check if magnitude >= 1 is possible.

    // If A=0 and D=0, all initial toys are in B2 or B3.
    // In this case, all products will have magnitude < 1.
    // So if A=0 and D=0, Box 4 is impossible.
    if (A == 0 && D == 0) {
        return false;
    }

    // If neg_count is even AND (A > 0 or D > 0), then it's possible.
    // Similar logic to Box 1, but for even neg_count.
    return true;
}

