    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent gets some coins from N-1.
                // Chanek gets 1 + (N-1 - opponent_coins_from_N-1)
                // This is complex. Let's analyze the structure.

                // If N is even, we have two choices: take 1 or take N/2.
                // Taking N/2 is generally better if it doesn't leave the opponent in a much better position.
                // If N is a power of 2, say N = 2^k:
                //   Chanek takes N/2 = 2^(k-1). Remaining 2^(k-1).
                //   Opponent takes 2^(k-2). Remaining 2^(k-2).
                //   ...
                //   This continues until N=2. Chanek takes 1. Remaining 1.
                //   Opponent takes 1. Remaining 0.
                //   In this case, Chanek gets N/2 + N/8 + N/32 + ...
                //   Opponent gets N/4 + N/16 + ...
                //   Total Chanek: N * (1/2 + 1/8 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * (1/2) / (3/4) = N * 2/3
                //   Total Opponent: N * (1/4 + 1/16 + ...) = N * ( (1/4) / (1 - 1/4) ) = N * (1/4) / (3/4) = N * 1/3
                //   This strategy works if N is a power of 2.

                // What if N is even but not a power of 2?
                // N = 2^k * M, where M is odd and M > 1.
                // If Chanek takes N/2: N/2 = 2^(k-1) * M.
                // If Chanek takes 1: N-1. N-1 is odd. Opponent takes 1. N-2.
                // This suggests that if N is even, taking N/2 is often the best move,
                // unless taking 1 coin leads to a much better outcome.

                // Consider the case where N is even.
                // If N is a power of 2 (N = 2^k, k >= 1):
                // Chanek takes N/2. Remaining N/2.
                // Opponent takes N/4. Remaining N/4.
                // ...
                // This continues until N=2. Chanek takes 1. Remaining 1.
                // Opponent takes 1. Remaining 0.
                // Chanek gets N/2 + N/8 + ... + 1 (if k is odd) or N/2 + N/8 + ... + 2 (if k is even, last 2 is N/2^(k-1))
                // This is N * (2/3) approximately.
