#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Case 0: Already good
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // Case 1: Append one element
    // Let the appended element be x.
    // New sum: current_sum + x
    // New XOR sum: current_xor_sum ^ x
    // We need: current_sum + x = 2 * (current_xor_sum ^ x)
    // This equation is generally hard to solve for x directly because of the XOR.
    // However, we are allowed to append up to 3 elements.
    // So, we can always use the 2 or 3 element strategy.

    // Case 2: Append two elements
    // Let the appended elements be x and y.
    // New sum: current_sum + x + y
    // New XOR sum: current_xor_sum ^ x ^ y
    // We need: current_sum + x + y = 2 * (current_xor_sum ^ x ^ y)
    // A common strategy for two elements is to pick x such that it helps simplify the XOR sum,
    // and then pick y to satisfy the sum condition.
    // Let's try to make the new XOR sum equal to current_xor_sum.
    // This can be done by appending x = current_xor_sum and y = 0.
    // New XOR sum: current_xor_sum ^ current_xor_sum ^ 0 = 0.
    // New sum: current_sum + current_xor_sum + 0 = current_sum + current_xor_sum.
    // Condition: current_sum + current_xor_sum = 2 * 0 = 0.
    // This only works if current_sum + current_xor_sum = 0, which is unlikely for non-negative numbers.

    // A more robust strategy for 2 elements:
    // Let the first appended element be X_0 (current_xor_sum).
    // The new XOR sum becomes X_0 ^ X_0 = 0.
    // The new total sum becomes S_0 + X_0.
    // Now we need to append a second element, say `val`, such that:
    // (S_0 + X_0) + val = 2 * (0 ^ val)
    // (S_0 + X_0) + val = 2 * val
    // S_0 + X_0 = val
    // So, we can append X_0 and (S_0 + X_0).
    // Let b1 = current_xor_sum.
    // Let b2 = current_sum + current_xor_sum.
    // The new sum will be current_sum + b1 + b2 = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum).
    // The new XOR sum will be current_xor_sum ^ b1 ^ b2 = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum.
    // Let S' = current_sum + b1 + b2 and X' = current_xor_sum ^ b1 ^ b2.
    // We need S' = 2 * X'.
    // Substituting: 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum).
    // This is always true!
    // So, we can always append two elements: current_xor_sum and (current_sum + current_xor_sum).
    // These elements can be large, up to 10^9 (initial a_i) * 10^5 (n) + 10^9 (XOR sum) which is ~10^14, fitting in long long.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

