    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1000000007;

    // Iterate through the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute 'a_count' steps
            // when it passes this 'b'.
            // The 'b' itself will be duplicated, effectively doubling
            // the number of 'a's that need to pass the *next* 'b' to its right.
            // So, the current 'a_count' (representing 'a's to the left)
            // is added to total_steps.
            // Then, 'a_count' is doubled because this 'b' effectively
            // creates a new 'b' for each 'a' that passes it.
            total_steps = (total_steps + a_count) % mod;
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to pass all 'b's to its right.
            // It contributes 1 to the 'a_count' for future 'b's.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        if (diff == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = 0;

        // Use as many 5s as possible
        count += diff / 5;
        diff %= 5;

        // Now diff is 0, 1, 2, 3, or 4
        if (diff == 0) {
            // Already done
        } else if (diff == 1) {
            // Can be 1 (+1)
            // Or 1 (+2, -1) -> 2 presses
            // Or 1 (+5, -2, -2) -> 3 presses
            // Or 1 (+5, -1, -1, -1, -1) -> 5 presses
            // The optimal is 1 press (+1)
            count += 1;
        } else if (diff == 2) {
            // Can be 1 (+2)
            // Or 1 (+5, -1, -1, -1) -> 4 presses
            // The optimal is 1 press (+2)
            count += 1;
        } else if (diff == 3) {
            // Can be 2 (+1, +2)
            // Or 2 (+5, -2)
            // The optimal is 2 presses
            count += 2;
        } else if (diff == 4) {
            // Can be 2 (+2, +2)
            // Or 2 (+5, -1)
            // The optimal is 2 presses
            count += 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that were counted twice (i.e., points with same (x,y) coordinates)
    // These are points that are identical. If k points are identical, they form k*(k-1)/2 pairs.
    // Each such pair (P, P) satisfies both x1=x2 and y1=y2.
    // So they were counted in x_counts and y_counts.
    // We need to subtract them once.
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // Step 1: Determine necessary 0s in w based on s[i] == '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will store the s generated from our w
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    // Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

