#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for counts of 'x', 'y', 'z'
    // counts[0][i] = count of 'x' in s[0...i-1]
    // counts[1][i] = count of 'y' in s[0...i-1]
    // counts[2][i] = count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;
        // Adjust to 0-indexed
        --l; 
        // r is already exclusive for prefix sums, so it's s[l...r-1]

        int len = r - l;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l...r-1]
        int count_x = counts[0][r] - counts[0][l];
        int count_y = counts[1][r] - counts[1][l];
        int count_z = counts[2][r] - counts[2][l];

        // The condition for termination is that the counts of 'x', 'y', 'z'
        // in any 3-character window are "balanced" enough.
        // Specifically, the difference between the maximum and minimum count
        // of any character ('x', 'y', 'z') in the substring must be at most 1.
        // If this condition holds, it's always possible to arrange them into
        // "xyz", "xzy", "yxz", "yzx", "zxy", "zyx" such that no "bad" sequence
        // (xyz, yzx, zxy) exists.
        // If the counts are too unbalanced, e.g., (3,0,0) for "xxx", then
        // any 3-char window will be "xxx", which is not a permutation of "xyz".
        // But the problem states "Find any continuous subsequence (substring) of three characters ... which doesn't equal to either string "zyx", "xzy", "yxz"."
        // This means we are looking for "xyz", "yzx", "zxy" or any string that is NOT a permutation of 'x','y','z' (e.g. "xxx", "xyy").
        // If such a string exists, it can be rearranged.
        // The algorithm terminates if ALL 3-char substrings are permutations of 'x','y','z' AND are one of "zyx", "xzy", "yxz".
        // This implies that the counts of 'x', 'y', 'z' in the substring must be "balanced" enough.
        // If the counts are balanced, e.g., (k, k, k) or (k+1, k, k), then it's possible to arrange them such that
        // any 3-char window is one of the forbidden types.
        // If the counts are unbalanced, e.g., (k+2, k, k), then there must be some 3-char window that is not a permutation of 'x','y','z'
        // or is one of "xyz", "yzx", "zxy".
        // For example, if we have "xxxy", the counts are (3,1,0). A window "xxx" is not a permutation of 'x','y','z'.
        // If we have "xxyyz", counts (2,2,1). A window "xxy" is not a permutation of 'x','y','z'.
        // The key insight is that if the counts of 'x', 'y', 'z' in the *entire substring* s[l...r-1] are too different,
        // then it's impossible to make all 3-character windows be permutations of 'x','y','z' AND be one of "zyx", "xzy", "yxz".
        // If the counts are such that max_count - min_count > 1, then it's always possible to find a 3-char substring
        // that is not a permutation of 'x','y','z' (e.g., "xxx", "xxy", "xyy", etc.) or is one of "xyz", "yzx", "zxy".
        // In such a case, the algorithm can rearrange it, and since it can always find such a substring, it runs infinitely.
        // This is because if max_count - min_count > 1, say count_x >= count_y + 2, then there must be at least two 'x's
        // that are not "balanced" by a 'y' or 'z'. This implies that we can always form a sequence like "xx?" or "x?x" or "?xx"
        // where '?' is not 'y' or 'z' to balance it.
        // More precisely, if max_count - min_count > 1, then it's impossible to arrange the characters such that
        // every 3-character window is a permutation of 'x', 'y', 'z' AND is one of "zyx", "xzy", "yxz".
        // If max_count - min_count <= 1, then the counts are "balanced" (e.g., (k,k,k) or (k+1,k,k)).
        // In this case, it is possible to arrange the characters such that all 3-character windows are permutations of 'x','y','z'
        // and are one of "zyx", "xzy", "yxz". For example, "xyzxyzxyz..." or "xzyxzyxzy...".
        // If the counts are balanced, the algorithm can terminate.
        // If the counts are unbalanced, the algorithm will run infinitely.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

