                min_x = std::max(min_x, x);
            }
            if (f3 == 0) { // Cannot move right, so target X must be <= current X
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down, so target Y must be >= current Y
                min_y = std::max(min_y, y);
            }
            if (f2 == 0) { // Cannot move up, so target Y must be <= current Y
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

