// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0"; // Special case for 0, which is even
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get standard order
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Using a map to store counts of patterns.
    // The key will be the canonical 18-digit parity pattern string.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad with '0's from the left to make it 18 digits long
            std::string canonical_pattern(18 - pattern.length(), '0');
            canonical_pattern += pattern;
            pattern_counts[canonical_pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad with '0's from the left to make it 18 digits long
            std::string canonical_pattern(18 - pattern.length(), '0');
            canonical_pattern += pattern;
            pattern_counts[canonical_pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad with '0's from the left to make it 18 digits long
            std::string canonical_s(18 - s.length(), '0');
            canonical_s += s;
            std::cout << pattern_counts[canonical_s] << "\n";
        }
    }

    return 0;
}

