}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: sum_r = (b-1) * b / 2
    // This sum needs to be modulo MOD.
    // (b-1) * b can be large, so we need to take modulo at each step.
    // Division by 2 means multiplying by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004.
    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.
    sum_r_term %= MOD;
    long long sum_r = (sum_r_term * (b % MOD)) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 mod 10^9 + 7
    sum_r = (sum_r * inv2) % MOD;

    // Sum of (k * b + 1) from k=1 to a: sum_k
    // sum_k = sum_{k=1 to a} (k*b + 1)
    // sum_k = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_k = b * (a * (a+1) / 2) + a
    // This sum also needs to be modulo MOD.
    long long sum_k_term_k = (a % MOD);
    long long sum_k_term_k_plus_1 = ((a + 1) % MOD);
    long long sum_k_part1 = (sum_k_term_k * sum_k_term_k_plus_1) % MOD;
    sum_k_part1 = (sum_k_part1 * inv2) % MOD; // This is sum_{k=1 to a} k

    long long sum_k = ( (b % MOD) * sum_k_part1 ) % MOD;
    sum_k = (sum_k + (a % MOD)) % MOD; // Add 'a' for sum_{k=1 to a} 1

    // Total sum = (sum_k * sum_r) % MOD
    long long total_sum = (sum_k * sum_r) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

