    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int start_block_val = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && (i + j) < n; ++j) {
            p[i + j] = start_block_val + (k - 1 - j);
        }
        current_val -= k;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit position.
    // For each bit j (0-9), we need to know what happens to it.
    // A bit can be 0, 1, or x (the input bit).
    // We can represent this using two values:
    // val_0[j]: the j-th bit of the result if input bit x_j is 0.
    // val_1[j]: the j-th bit of the result if input bit x_j is 1.
    // Initially, for an input x:
    // if x_j is 0, result bit is 0.
    // if x_j is 1, result bit is 1.
    // So, val_0[j] = 0 and val_1[j] = 1 for all j.
    std::vector<int> val_0(10); // Stores the j-th bit if input x_j is 0
    std::vector<int> val_1(10); // Stores the j-th bit if input x_j is 1

    for (int j = 0; j < 10; ++j) {
        val_0[j] = 0;
        val_1[j] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int constant;
        std::cin >> op_char >> constant;

        for (int j = 0; j < 10; ++j) {
            int const_bit = (constant >> j) & 1;
            if (op_char == '&') {
                val_0[j] &= const_bit;
                val_1[j] &= const_bit;
            } else if (op_char == '|') {
                val_0[j] |= const_bit;
                val_1[j] |= const_bit;
            } else { // op_char == '^'
                val_0[j] ^= const_bit;
                val_1[j] ^= const_bit;
            }
        }
    }

    // Now, we have the final state for each bit j: (val_0[j], val_1[j]).
    // We need to find a minimal sequence of operations to achieve this.
    // There are 4 possible states for (val_0[j], val_1[j]):
    // 1. (0, 0): The bit is always 0, regardless of input.
    // 2. (0, 1): The bit is the same as the input bit.
    // 3. (1, 0): The bit is the inverse of the input bit.
    // 4. (1, 1): The bit is always 1, regardless of input.

    // We can achieve these states with at most 3 operations:
    // AND mask_and
    // OR mask_or
    // XOR mask_xor

    // Let's determine mask_and, mask_or, mask_xor.
    // Initialize them to values that don't change the bits initially.
    int mask_and = 1023; // All bits 1
    int mask_or = 0;     // All bits 0
    int mask_xor = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        if (val_0[j] == 0 && val_1[j] == 0) {
            // Bit j must become 0.
            // Current state: x_j -> 0.
            // To achieve this:
            // AND with 0: mask_and_j = 0.
            // OR with 0: mask_or_j = 0.
            // XOR with 0: mask_xor_j = 0.
            // If we have (x & M_and) | M_or ^ M_xor
            // If x_j=0: (0 & M_and_j) | M_or_j ^ M_xor_j = 0 | M_or_j ^ M_xor_j = M_or_j ^ M_xor_j = 0
            // If x_j=1: (1 & M_and_j) | M_or_j ^ M_xor_j = M_and_j | M_or_j ^ M_xor_j = 0
            //
            // To make bit j always 0:
            // We need to ensure that after all operations, the bit is 0.
            // The simplest way is to AND with 0 at this bit position.
            mask_and &= ~(1 << j); // Set j-th bit of mask_and to 0
        } else if (val_0[j] == 0 && val_1[j] == 1) {
            // Bit j is unchanged (x_j -> x_j).
            // Current state: x_j.
            // To achieve this:
            // AND with 1: mask_and_j = 1.
            // OR with 0: mask_or_j = 0.
            // XOR with 0: mask_xor_j = 0.
            // These are the default values, so no change needed for these masks.
        } else if (val_0[j] == 1 && val_1[j] == 0) {
            // Bit j is inverted (x_j -> !x_j).
            // Current state: !x_j.
            // To achieve this:
            // AND with 1: mask_and_j = 1.
            // OR with 0: mask_or_j = 0.
            // XOR with 1: mask_xor_j = 1.
            mask_xor |= (1 << j); // Set j-th bit of mask_xor to 1
        } else { // val_0[j] == 1 && val_1[j] == 1
            // Bit j must become 1.
            // Current state: x_j -> 1.
            // To achieve this:
            // AND with 1: mask_and_j = 1.
            // OR with 1: mask_or_j = 1.
            // XOR with 0: mask_xor_j = 0.
            mask_or |= (1 << j); // Set j-th bit of mask_or to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (mask_and != 1023) { // If any bit of mask_and is 0, we need an AND operation
        result_ops.push_back({'&', mask_and});
    }
    if (mask_or != 0) { // If any bit of mask_or is 1, we need an OR operation
        result_ops.push_back({'|', mask_or});
    }
    if (mask_xor != 0) { // If any bit of mask_xor is 1, we need an XOR operation
        result_ops.push_back({'^', mask_xor});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
