void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> one_indices;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            one_indices.push_back(i);
        }
    }

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: Substring starts with '0'
        // If s[l] is '0', then any substring s[l...r] starting with '0'
        // will have f(s[l...r]) = f(s[l+1...r]).
        // The condition is r - l + 1 = f(s[l...r]).
        // Since f(s[l...r]) is at most 2^(r-l+1)-1, and it's non-negative,
        // and r-l+1 is at least 1, the value f(s[l...r]) can be at most 19
        // for r-l+1 <= 19.
        // For r-l+1 > 19, f(s[l...r]) can be much larger.
        // However, if s[l] is '0', then f(s[l...r]) is the same as f(s[l+1...r]).
        // The length is r-l+1.
        // The maximum length for which f(s[l...r]) can be equal to r-l+1
        // is limited.
        // For example, if s[l] = '0', and s[l+1...r] has length L', then
        // f(s[l...r]) = f(s[l+1...r]). The length of s[l...r] is L'+1.
        // We need L'+1 = f(s[l+1...r]).
        // This means we are looking for substrings s[l+1...r] such that
        // its value is its length + 1.
        // This is equivalent to the original problem, but with a shifted length.
        // The maximum value of f(s[l...r]) is 2^(r-l+1)-1.
        // The maximum length of s is 2e5.
        // 2^18 is 262144. 2^17 is 131072.
        // So, if r-l+1 is around 18, f(s[l...r]) can be up to 2e5.
        // If s[l] is '0', we can skip it and effectively consider s[l+1...r]
        // with length r-l. The value is f(s[l+1...r]).
        // We need r-l+1 = f(s[l+1...r]).
        // Let k be the number of leading zeros.
        // s[l...r] = 0...01... (k zeros, then a 1)
        // f(s[l...r]) = f(s[l+k...r]).
        // Length = r-l+1.
        // We need r-l+1 = f(s[l+k...r]).
        // The maximum value of f(s[l+k...r]) is 2^(r-(l+k)+1)-1.
        // So r-l+1 <= 2^(r-l-k+1)-1.
        // This implies that r-l-k+1 must be large enough.
        // If r-l-k+1 is small (e.g., <= 18), we can iterate.
        // If r-l-k+1 is large, then r-l+1 is much smaller than 2^(r-l-k+1)-1.
        // For example, if r-l-k+1 = 19, then 2^19-1 is about 5e5.
        // r-l+1 can be at most 2e5.
        // So, we only need to check substrings where the effective length
        // (length after removing leading zeros) is small.
        // The maximum length of s is 2e5.
        // The maximum value of f(s_l...s_r) is 2^(r-l+1)-1.
        // If r-l+1 = f(s_l...s_r), then r-l+1 <= 2^(r-l+1)-1.
        // This is always true for r-l+1 >= 1.
        // The maximum value of r-l+1 is N.
        // The maximum value of f(s_l...s_r) is N.
        // So, we need f(s_l...s_r) <= N.
        // If s_l...s_r has length L, then f(s_l...s_r) <= 2^L-1.
        // If L is large, say L=20, then 2^20-1 is about 10^6.
        // If L=18, 2^18-1 is about 2.6*10^5.
        // If L=17, 2^17-1 is about 1.3*10^5.
        // So, if the effective length (length after removing leading zeros)
        // is greater than, say, 18, then f(s_l...s_r) will be too large
        // to be equal to r-l+1, unless r-l+1 is also very large.
        // But r-l+1 is at most N.
        // So, we only need to consider substrings where the effective length
        // is at most around 18-20.
        // Let's use a constant `MAX_EFFECTIVE_LEN` for this.
        // A safe upper bound for MAX_EFFECTIVE_LEN would be around 19-20,
        // since 2^18 is > 2e5.
        // Let's pick MAX_EFFECTIVE_LEN = 19.
        // This means we iterate `r` for `l` such that `r-l+1` is small.
        // This is not quite right. The `r-l+1` is the actual length.
        // The value `f(s_l...s_r)` is what matters.
        // If `s_l` is '0', we need to find the first '1' at `s_k`.
        // Then `f(s_l...s_r) = f(s_k...s_r)`.
        // The length is `r-l+1`.
        // We need `r-l+1 = f(s_k...s_r)`.
        // The length of `s_k...s_r` is `r-k+1`.
        // Let `len_eff = r-k+1`.
        // We need `r-l+1 = f(s_k...s_r)`.
        // Since `k >= l`, `r-l+1 >= r-k+1`.
        // So `f(s_k...s_r)` must be at least `len_eff`.
        // Also, `f(s_k...s_r)` is at most `2^len_eff - 1`.
        // So we need `r-l+1 <= 2^len_eff - 1`.
        // If `len_eff` is large, say `len_eff > 18`, then `2^len_eff - 1` is
        // much larger than `N`.
        // So `r-l+1` must be small.
        // This means `r-l+1` must be at most `N`.
        // If `len_eff` is large, say `len_eff = 19`, then `f(s_k...s_r)` can be up to `2^19-1`.
        // If `r-l+1 = f(s_k...s_r)`, then `r-l+1` can be up to `2^19-1`.
        // But `r-l+1` is also at most `N`.
        // So `f(s_k...s_r)` must be at most `N`.
        // This implies `len_eff` must be at most 18 (since 2^18 > 2e5).
        // So we only need to consider substrings `s_k...s_r` where `k` is the
        // first '1' and `r-k+1 <= 18`.
        // For each `l`, we find the first `k >= l` such that `s[k] == '1'`.
        // If no such `k` exists, then all `s[l...r]` are '0's, so `f(s[l...r]) = 0`.
        // `r-l+1 = 0` is impossible for `r-l+1 >= 1`. So no good substrings.
        // If `k` exists, we iterate `r` from `k` up to `min(n-1, k + 18 - 1)`.
        // For each such `r`, we calculate `val = f(s[k...r])`.
        // Then we check if `val = r-l+1`.
        // This means `l = r - val + 1`.
        // We need `l` to be in the range `[0, k]`.
        // So, for a fixed `k` and `r` (with `s[k]=='1'` and `r-k+1 <= 18`),
        // we calculate `val = f(s[k...r])`.
        // Then we calculate `target_l = r - val + 1`.
        // If `target_l >= 0` and `target_l <= k` and `s[target_l...k-1]` are all '0's,
        // then `s[target_l...r]` is a good substring.
        // The condition `s[target_l...k-1]` are all '0's is equivalent to
        // `target_l` being greater than or equal to the index of the last '1' before `k`.
        // Let `prev_one_idx[k]` be the index of the last '1' before `k`.
        // If `target_l >= prev_one_idx[k] + 1`, then all characters `s[target_l...k-1]` are '0's.
        // If `k` is the first '1' in the string, `prev_one_idx[k]` can be considered -1.
        // So, `target_l >= prev_one_idx[k] + 1`.

        // Iterate through all possible starting positions of the '1' part (k)
        for (int k_idx = 0; k_idx < one_indices.size(); ++k_idx) {
            int k = one_indices[k_idx];
            long long current_val = 0;
            // Iterate r, such that r-k+1 (effective length) is small
            for (int r = k; r < n && (r - k + 1) <= 19; ++r) { // Max effective length 19
                current_val = (current_val << 1) | (s[r] - '0');

                // If current_val exceeds N, then it can't be equal to r-l+1 <= N
                if (current_val > n) {
                    break; // Optimization: further values will also be too large
                }

                // We need r - l + 1 = current_val
                // So, l = r - current_val + 1
                int target_l = r - static_cast<int>(current_val) + 1;

                // Check if this target_l is valid
                // 1. target_l must be <= k (because k is the first '1')
                // 2. target_l must be >= 0
                // 3. All characters s[target_l...k-1] must be '0's.
                // This means target_l must be greater than the index of the last '1' before k.
                // If k_idx == 0, then k is the first '1' in the string, so prev_one_idx is -1.
                // Otherwise, prev_one_idx is one_indices[k_idx-1].
                int prev_one_idx = (k_idx == 0) ? -1 : one_indices[k_idx - 1];

                if (target_l >= 0 && target_l <= k && target_l > prev_one_idx) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

