struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, 0); // b[i] = a_0[i] - initial_a_0[i]
    std::vector<long long> min_val_at_idx(n, LLONG_MAX); // min_val_at_idx[i] = max_val_constraint[i] - current_sum_d[i]

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_at_idx[j] = std::min(min_val_at_idx[j], ops[i].val - b[j]);
            }
        }
    }

    std::vector<long long> a0(n);
    for (int i = 0; i < n; ++i) {
        if (min_val_at_idx[i] == LLONG_MAX) {
            a0[i] = 0; // No upper bound constraint, can be 0
        } else {
            a0[i] = min_val_at_idx[i];
        }
    }

    // Verify the solution
    std::vector<long long> current_a = a0;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_in_range = std::max(max_in_range, current_a[j]);
            }
            if (max_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

