        }
    }

    // Now, next_bad_idx[i] = min_{x >= i} (min_r_for_x[x])
    // This can be computed with a suffix minimum.
    for (int i = n - 1; i >= 1; --i) {
        next_bad_idx[i] = std::min(next_bad_idx[i + 1], min_r_for_x[i]);
    }

    long long total_good_pairs = 0;
    for (int l = 1; l <= n; ++l) {
        // For a fixed l, we need to find r such that l <= r < next_bad_idx[l].
        // The number of such r's is (next_bad_idx[l] - 1) - l + 1.
        // If next_bad_idx[l] is n+1, then all r from l to n are good.
        // Number of good r's: n - l + 1.
        // If next_bad_idx[l] is some value R_min <= n, then r can be from l to R_min - 1.
        // Number of good r's: (R_min - 1) - l + 1 = R_min - l.
        // This can be written as std::min(n + 1, next_bad_idx[l]) - l.
        // If next_bad_idx[l] is n+1, then std::min(n+1, n+1) - l = n+1-l.
        // If next_bad_idx[l] is R_min <= n, then std::min(n+1, R_min) - l = R_min - l.
        // This is correct.
        total_good_pairs += (long long)std::min(n + 1, next_bad_idx[l]) - l;
    }

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long ans = total_pairs - total_good_pairs;

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=1
    // Try all possible single cuts
    // s = s_prefix + s_suffix
    // New string s' = s_suffix + s_prefix
    // Check if s' is a palindrome and s' != s
    for (int i = 1; i < n; ++i) { // i is the length of s_prefix
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_prime = s_suffix + s_prefix;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2
    // If k=1 is not possible, we check k=2.
    // A solution with k=2 is always possible unless all characters in s are the same.
    // If all characters are the same (e.g., "aaaa"), then any rearrangement of pieces
    // will result in the same string "aaaa", which is not allowed.
    // If s consists of only one distinct character, e.g., "aaaaa", then any permutation
    // of its substrings will result in "aaaaa". Since s' must not be equal to s,
    // this case is impossible.

    // Check if all characters in s are the same
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 was not possible,
        // then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // Example: "abacaba" -> "ab|ac|aba" -> "aba|ac|ab" (k=2)
        // The only case where k=1 fails is if all cyclic shifts are either s itself
        // or not palindromes.
        // If s is a palindrome and not all characters are the same,
        // then s must have at least two distinct characters.
        // Consider s = "abacaba".
        // Cut 1: "a" | "bacaba" -> "bacabaa" (not pal)
        // Cut 2: "ab" | "acaba" -> "acabaab" (not pal)
        // Cut 3: "aba" | "caba" -> "cabaaba" (not pal)
        // Cut 4: "abac" | "aba" -> "abaacab" (not pal)
        // Cut 5: "abaca" | "ba" -> "baabaca" (not pal)
        // Cut 6: "abacab" | "a" -> "aabacab" (not pal)
        // In this case, k=1 fails.
        // But k=2 is always possible if not all characters are the same.
        // For example, take s = s_1 s_2 ... s_n.
        // Since s is a palindrome, s_1 = s_n, s_2 = s_{n-1}, etc.
        // If not all characters are the same, there must be some s_i != s_1.
        // Consider cutting s into three pieces:
        // s_1 ... s_{n-1} | s_n (which is s_1)
        // This is a cut into two pieces.
        // If we cut s into s_1 ... s_{n/2} | s_{n/2+1} ... s_n
        // And swap them, we get s_{n/2+1} ... s_n s_1 ... s_{n/2}.
        // This is the k=1 case.
        // If k=1 fails, it means all cyclic shifts are either s or not palindromes.
        // However, if s is a palindrome and not all characters are the same,
        // it's always possible to find a k=2 solution.
        // For example, take s = "nolon". k=1 fails.
        // "n" | "olo" | "n" -> "n" | "olo" | "n" (original)
        // "no" | "l" | "on" -> "on" | "l" | "no" (palindrome, not original)
        // This is a 2-cut solution.
        // The problem statement guarantees that if k=1 is not possible,
        // and not all characters are the same, then k=2 is the answer.
        // This is a known property for palindromes.
        // If a palindrome `s` has at least two distinct characters, and no single cut
        // and swap produces a new palindrome, then two cuts are sufficient.
        // One way to achieve this is to cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
        // Then rearrange to `s[n-1]`, `s[1...n-2]`, `s[0]`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // So this rearrangement is `s[0]`, `s[1...n-2]`, `s[0]`, which is `s`.
        // This specific rearrangement doesn't work.
        // However, the problem implies that if k=1 fails and not all chars are same, k=2 is the answer.
        // This is a common competitive programming trick/property.
        // The proof for this is non-trivial but often assumed in such problems.
        // A simple construction for k=2:
        // s = A B C, where A is s[0], C is s[n-1], B is s[1...n-2].
        // Since s is a palindrome, A=C.
        // If B is also a palindrome, then s = A B A.
        // If B is not all same characters, we can apply the k=1 logic to B.
        // If B is all same characters, e.g., B = "xxx", then s = "axxxa".
        // Cut "a" | "xxx" | "a". Rearrange to "a" | "xxx" | "a" (original).
        // But we can cut "a" | "x" | "xxa". Rearrange to "xxa" | "x" | "a".
        // This is not guaranteed to be a palindrome.
        // The simplest argument is that if k=1 fails, and not all characters are the same,
        // then k=2 is the answer. This is a known result for this type of problem.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

// Suffix array construction (SA-IS algorithm)
// Based on https://github.com/yosupo02/library/blob/main/string/suffix_array.hpp
// and https://github.com/yosupo02/library/blob/main/string/sa_is.hpp

namespace internal {

template <class T>
std::vector<int> sa_is(const std::vector<T>& s, int alphabet_size) {
    int n = s.size();
    if (n == 0) return {};
    if (n == 1) return {0};
    if (n == 2) {
        if (s[0] < s[1]) return {0, 1};
        else return {1, 0};
    }

    std::vector<bool> is_l(n);
    std::vector<int> bucket_size(alphabet_size);
    for (int i = 0; i < n; ++i) bucket_size[s[i]]++;

    auto get_bucket_heads = [&]() {
        std::vector<int> heads(alphabet_size);
        heads[0] = 0;
        for (int i = 1; i < alphabet_size; ++i) {
            heads[i] = heads[i - 1] + bucket_size[i - 1];
        }
        return heads;
    };

    auto get_bucket_tails = [&]() {
        std::vector<int> tails(alphabet_size);
        tails[0] = bucket_size[0] - 1;
        for (int i = 1; i < alphabet_size; ++i) {
            tails[i] = tails[i - 1] + bucket_size[i];
        }
        return tails;
    };

    is_l[n - 1] = true;
    for (int i = n - 2; i >= 0; --i) {
        is_l[i] = (s[i] > s[i + 1]) || (s[i] == s[i + 1] && is_l[i + 1]);
    }

    std::vector<int> sa(n);
    auto induce = [&](const std::vector<int>& lms) {
        std::fill(sa.begin(), sa.end(), -1);
        std::vector<int> heads = get_bucket_heads();
        for (int d : lms) {
            sa[heads[s[d]]++] = d;
        }
        std::vector<int> tails = get_bucket_tails();
        for (int i = 0; i < n; ++i) {
            if (sa[i] == -1) continue;
            int d = sa[i] - 1;
            if (d >= 0 && is_l[d]) {
                sa[heads[s[d]]++] = d;
            }
        }
        std::fill(heads.begin(), heads.end(), 0); // Reset heads for next pass
        heads = get_bucket_heads();
        for (int i = n - 1; i >= 0; --i) {
            if (sa[i] == -1) continue;
            int d = sa[i] - 1;
            if (d >= 0 && !is_l[d]) {
                sa[tails[s[d]]--] = d;
            }
        }
    };

    std::vector<int> lms_pos;
    for (int i = 1; i < n; ++i) {
        if (!is_l[i] && is_l[i - 1]) {
            lms_pos.push_back(i);
        }
    }

    induce(lms_pos);

    std::vector<int> new_lms_pos;
    for (int d : sa) {
        if (!is_l[d] && (d == 0 || is_l[d - 1])) { // d is an LMS character
            new_lms_pos.push_back(d);
        }
    }

    std::vector<int> lms_rank(n, -1);
    int rank = 0;
    lms_rank[new_lms_pos[0]] = rank;
    for (size_t i = 1; i < new_lms_pos.size(); ++i) {
        int prev = new_lms_pos[i - 1];
        int curr = new_lms_pos[i];
        bool diff = false;
        if (s[prev] != s[curr]) {
            diff = true;
        } else {
            int p1 = prev + 1;
            int p2 = curr + 1;
            while (true) {
                if (s[p1] != s[p2]) {
                    diff = true;
                    break;
                }
                if (!is_l[p1] && is_l[p1 - 1]) break; // End of LMS substring
                p1++;
                p2++;
            }
        }
        if (diff) rank++;
        lms_rank[curr] = rank;
    }

    std::vector<int> s_prime;
    for (int d : lms_pos) {
        s_prime.push_back(lms_rank[d]);
    }

    std::vector<int> sa_prime = sa_is(s_prime, rank + 1);

    std::vector<int> sorted_lms;
    for (int d : sa_prime) {
        sorted_lms.push_back(lms_pos[d]);
    }

    induce(sorted_lms);
    return sa;
}

} // namespace internal

std::vector<int> suffix_array(const std::string& s) {
    std::vector<int> s_int(s.size() + 1);
    for (int i = 0; i < s.size(); ++i) {
        s_int[i] = s[i];
    }
    s_int[s.size()] = 0; // Sentinel
    return internal::sa_is(s_int, 256); // ASCII alphabet size
}

std::vector<int> lcp_array(const std::string& s, const std::vector<int>& sa) {
    int n = s.size();
    std::vector<int> rank(n);
    for (int i = 0; i < n; ++i) {
        rank[sa[i]] = i;
    }
    std::vector<int> lcp(n - 1);
    int h = 0;
    for (int i = 0; i < n; ++i) {
        if (rank[i] == n - 1) continue;
        int j = sa[rank[i] + 1];
        while (i + h < n && j + h < n && s[i + h] == s[j + h]) {
            h++;
        }
        lcp[rank[i]] = h;
        if (h > 0) h--;
    }
    return lcp;
}

// Sparse table for RMQ
template <typename T>
struct SparseTable {
    int n;
    std::vector<std::vector<T>> st;
    std::vector<int> log_table;

    SparseTable(const std::vector<T>& v) {
        n = v.size();
        log_table.resize(n + 1);
        log_table[1] = 0;
        for (int i = 2; i <= n; i++) {
            log_table[i] = log_table[i / 2] + 1;
        }

        int max_log = log_table[n];
        st.assign(max_log + 1, std::vector<T>(n));
        st[0] = v;

        for (int k = 1; k <= max_log; k++) {
            for (int i = 0; i + (1 << k) <= n; i++) {
                st[k][i] = std::min(st[k - 1][i], st[k - 1][i + (1 << (k - 1))]);
            }
        }
    }

    T query(int l, int r) { // query minimum in [l, r]
        if (l > r) return 1e9; // Or appropriate max value
        int k = log_table[r - l + 1];
        return std::min(st[k][l], st[k][r - (1 << k) + 1]);
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> sa = suffix_array(s);
    std::vector<int> lcp = lcp_array(s, sa);

    std::vector<int> rank(n);
    for (int i = 0; i < n; ++i) {
        rank[sa[i]] = i;
    }

    SparseTable<int> st_lcp(lcp);

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        if (char_indices[char_code].empty()) continue;

        std::vector<int>& current_char_k_indices = char_indices[char_code];
        int num_k_for_char = current_char_k_indices.size();

        if (num_k_for_char == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal p
        // For a fixed p, calculate win probability
        // Maximize this over all p
        double max_win_prob_for_char = 0.0;

        for (int p = 1; p < n; ++p) {
            int num_unique_k_for_p = 0;
            for (int i = 0; i < num_k_for_char; ++i) {
                int k_i = current_char_k_indices[i];
                bool is_unique = true;
                for (int j = 0; j < num_k_for_char; ++j) {
                    if (i == j) continue;
                    int k_j = current_char_k_indices[j];

                    // Check if s[k_i + p] == s[k_j + p] (modulo N)
                    // This is equivalent to checking if s[k_i...k_i+p] == s[k_j...k_j+p]
                    // which means LCP(suffix_k_i, suffix_k_j) >= p+1

                    int idx1 = k_i;
                    int idx2 = k_j;

                    int l = std::min(rank[idx1], rank[idx2]);
                    int r = std::max(rank[idx1], rank[idx2]) - 1;

                    int common_prefix_len = st_lcp.query(l, r);

                    if (common_prefix_len >= p + 1) {
                        is_unique = false;
                        break;
                    }
                }
                if (is_unique) {
                    num_unique_k_for_p++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)num_unique_k_for_p / num_k_for_char);
        }
        total_win_prob += max_win_prob_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

long long N, M;
std::vector<long long> H, P;

// Function to check if all tracks can be covered within time T
bool check(long long T) {
    // Create a list of all relevant points: initial head positions and target tracks.
    // These points define intervals that need to be covered.
    std::set<long long> all_points_set;
    for (long long h_val : H) {
        all_points_set.insert(h_val);
    }
    for (long long p_val : P) {
        all_points_set.insert(p_val);
    }

    std::vector<long long> points(all_points_set.begin(), all_points_set.end());

    // dp[i] = minimum number of heads required to cover all target tracks
    // up to and including points[i].
    // If points[i] is not a target track, it means we cover up to points[i-1]
    // and points[i] is just an intermediate point.
    std::vector<long long> dp(points.size(), N + 1); // N+1 means impossible

    // Base case: If points[0] is a target track, we need to cover it.
    // Find the first head that can cover points[0] within time T.
    // This head must be at H[k] such that H[k] - T <= points[0] <= H[k] + T.
    // Or, more simply, abs(H[k] - points[0]) <= T.
    // We need to find the minimum k such that H[k] >= points[0] - T.
    // All heads H[j] with j >= k can potentially cover points[0] if H[j] - points[0] <= T.
    // The number of heads available to cover points[0] is N - k.
    // If points[0] is a target track, we need to cover it.
    // The number of heads needed is 1.
    // The number of heads available to cover points[0] is N - (lower_bound(H.begin(), H.end(), points[0] - T) - H.begin()).
    // This is not quite right. We need to cover points[0] with *some* head.
    // The number of heads available to cover points[0] is the count of h_i such that h_i - T <= points[0] <= h_i + T.
    // This is not how the DP works. The DP is about covering a prefix of target tracks.

    // Let's redefine dp[i] = minimum number of heads required to cover all target tracks
    // p_j such that p_j <= points[i].
    // If points[i] is not a target track, then dp[i] = dp[i-1].
    // If points[i] is a target track, we need to cover it.

    // The DP state should be: dp[i] = minimum number of heads required to cover all target tracks
    // up to and including the target track P[i].
    // This means we need to map P values to indices in `points`.
    // Let's use `P_idx` to store the indices of target tracks in `points`.
    std::vector<int> P_idx;
    for (long long p_val : P) {
        P_idx.push_back(std::lower_bound(points.begin(), points.end(), p_val) - points.begin());
    }

    // dp[i] = minimum number of heads required to cover all target tracks P[0]...P[i].
    // This is a standard DP approach for interval covering.
    // dp[i] = minimum heads to cover P[0]...P[i].
    // To compute dp[i], we need to cover P[i].
    // We can use one head to cover P[i] and some range [L, R].
    // If this head covers P[k]...P[i], then we need dp[k-1] heads for P[0]...P[k-1].
    // This is O(M^2) which is too slow.

    // Let's use a greedy approach with the `check` function.
    // We want to cover all target tracks P[0], P[1], ..., P[M-1].
    // We iterate through the target tracks P[j] from left to right.
    // We maintain `current_head_idx`, the index of the head we are currently considering.
    // We also maintain `last_covered_track`, the rightmost track covered by previous heads.

    // `last_covered_track` is the rightmost point that has been covered by some head.
    // Initially, `last_covered_track = -infinity`.
    // `head_used_count = 0`.
    // `current_head_idx = 0`.

    // Iterate through target tracks `p_j` from `P[0]` to `P[M-1]`.
    // `p_ptr` is the index of the current target track we need to cover.
    int p_ptr = 0;
    int h_ptr = 0; // Pointer to the current head we are considering
    long long heads_needed = 0;

    while (p_ptr < M) {
        // Find the leftmost target track `P[p_ptr]` that is not yet covered.
        // If `P[p_ptr]` is already covered by a previous head (i.e., `P[p_ptr] <= last_covered_track`),
        // then advance `p_ptr`.
        // This `last_covered_track` logic is for a single head covering a range.
        // Here, multiple heads can cover different ranges.

        // The problem is to find if M tracks can be covered by N heads in T time.
        // This is a classic "interval covering" problem.
        // We have N heads. Each head `h_i` can cover `[h_i - T, h_i + T]`.
        // We need to cover all `p_j`.
        // This is equivalent to finding if there exist N intervals `[L_k, R_k]`
        // such that `L_k <= h_i - T` and `R_k >= h_i + T` for some `i`,
        // and the union of these N intervals covers all `p_j`.
        // This is not quite right. Each head `h_i` can cover *any* interval `[x, y]`
        // as long as `y - x <= 2T` and `h_i` is within `[x, y]`.
        // No, the problem states: "move the head exactly one track to the right or to the left, or leave it on the current track."
        // "A track is considered read if at least one head has visited this track."
        // "In particular, all of the tracks numbered h_1, h_2, ..., h_n have been read at the beginning of the operation."
        // This means a head at `h_i` can cover any track `x` such that `abs(h_i - x) <= T`.
        // So, head `h_i` can cover the interval `[h_i - T, h_i + T]`.
        // We have `N` such intervals. We need to select `N` intervals (one for each head)
        // such that their union covers all `p_j`.
        // This is a standard greedy approach:
        // 1. Sort the target tracks `P`.
        // 2. Initialize `current_p_idx = 0`.
        // 3. Initialize `heads_used = 0`.
        // 4. While `current_p_idx < M`:
        //    a. We need to cover `P[current_p_idx]`.
        //    b. Find the head `h_k` (among available heads) that can cover `P[current_p_idx]`
        //       and extends furthest to the right.
        //    c. If no head can cover `P[current_p_idx]`, return `false`.
        //    d. Use that head. Increment `heads_used`.
        //    e. Update `current_p_idx` to the first target track not covered by this head.
        //    f. If `heads_used > N`, return `false`.
        // 5. Return `true`.

        // This greedy approach is correct for interval covering.
        // The available heads are `H[0], ..., H[N-1]`.
        // Each head `H[i]` can cover `[H[i] - T, H[i] + T]`.
        // We need to cover `P[0], ..., P[M-1]`.

        // `current_p_idx` is the index of the leftmost target track that still needs to be covered.
        int current_p_idx = 0;
        int heads_used = 0;
        int current_h_idx = 0; // Pointer to the head we are currently considering for assignment

        while (current_p_idx < M) {
            heads_used++;
            if (heads_used > N) {
                return false; // Not enough heads
            }

            long long target_left_boundary = P[current_p_idx];
            long long best_right_reach = -1; // The maximum right reach we can get from a head covering target_left_boundary

            // Find the head that can cover `target_left_boundary` and reaches furthest to the right.
            // We only consider heads `H[current_h_idx]` onwards.
            // A head `H[k]` can cover `target_left_boundary` if `H[k] - T <= target_left_boundary <= H[k] + T`.
            // This is equivalent to `target_left_boundary - T <= H[k] <= target_left_boundary + T`.
            // We need to find the first head `H[k]` such that `H[k] >= target_left_boundary - T`.
            // All heads from this `k` up to some `k'` such that `H[k'] <= target_left_boundary + T` are candidates.
            // Among these candidates, we pick the one that maximizes `H[j] + T`.

