void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (char pivot_char = '0'; pivot_char <= '9'; ++pivot_char) {
        std::vector<int> colors(n);
        bool possible = true;
        char last_digit_color1 = '0'; // Smallest possible digit
        char last_digit_color2 = '0'; // Smallest possible digit

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < pivot_char) {
                // Must be color 1
                if (current_digit < last_digit_color1) {
                    possible = false;
                    break;
                }
                colors[i] = 1;
                last_digit_color1 = current_digit;
            } else if (current_digit > pivot_char) {
                // Must be color 2
                if (current_digit < last_digit_color2) {
                    possible = false;
                    break;
                }
                colors[i] = 2;
                last_digit_color2 = current_digit;
            } else { // current_digit == pivot_char
                // Can be either color 1 or color 2
                // Prioritize color 2 if it maintains non-decreasing order for S2
                // This ensures that if a digit can be 2, it is 2, which helps satisfy last_digit_color1 <= first_digit_color2
                if (current_digit >= last_digit_color2) {
                    colors[i] = 2;
                    last_digit_color2 = current_digit;
                } else if (current_digit >= last_digit_color1) {
                    colors[i] = 1;
                    last_digit_color1 = current_digit;
                } else {
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            // Final check: last digit of S1 must be <= first digit of S2
            // This is implicitly handled by the logic above.
            // If a digit `d` is assigned color 1, it must be `d >= last_digit_color1`.
            // If a digit `d` is assigned color 2, it must be `d >= last_digit_color2`.
            // The critical part is that `last_digit_color1` (which is the max digit in S1)
            // must be <= `first_digit_color2` (which is the min digit in S2).
            // Our greedy choice for `pivot_char` handles this:
            // All digits assigned color 1 are <= `pivot_char`.
            // All digits assigned color 2 are >= `pivot_char`.
            // So, `max(S1) <= pivot_char <= min(S2)` is guaranteed.
            // The only remaining condition is that `S1` and `S2` themselves are sorted,
            // which is checked by `current_digit >= last_digit_color1` and `current_digit >= last_digit_color2`.

            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

