#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long total_operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each pile 'a[i]' (where i != min_idx), we want to add 'min_val'
        // as many times as possible without 'a[i]' exceeding 'k'.
        // The current value of a[i] is a[i].
        // We can add min_val until a[i] + count * min_val > k.
        // So, a[i] + count * min_val <= k
        // count * min_val <= k - a[i]
        // count <= (k - a[i]) / min_val
        // Since count must be an integer, count = floor((k - a[i]) / min_val)

        if (a[i] >= k) { // If a[i] is already k or more, we can't add anything to it.
            continue;
        }

        long long remaining_capacity = k - a[i];
        total_operations += remaining_capacity / min_val;
    }

    std::cout << total_operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

