            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long ans = 0;
        ans += diff / 5;
        diff %= 5;
        if (diff == 1 || diff == 2) {
            ans += 1;
        } else if (diff == 3 || diff == 4) {
            ans += 2;
        }
        std::cout << ans << "\n";
    }
    return 0;
}

