#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem asks for a different permutation p' with the same fingerprint.
    // The fingerprint is the sorted list of adjacent sums.
    // If we reverse the permutation p to get p_rev, the adjacent sums are:
    // p_n + p_{n-1}, p_{n-1} + p_{n-2}, ..., p_2 + p_1.
    // These are exactly the same sums as for p:
    // p_1 + p_2, p_2 + p_3, ..., p_{n-1} + p_n,
    // just in a different order.
    // Therefore, F(p_rev) = F(p).
    //
    // The only case where p_rev might be the same as p is if p is a palindrome.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For example, if n=3, p=[1,2,3], p_rev=[3,2,1]. Different.
    // If n=4, p=[1,2,3,4], p_rev=[4,3,2,1]. Different.
    //
    // A permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2).
    // For a permutation of length n >= 2 to be a palindrome, it would mean:
    // p_1 = p_n
    // p_2 = p_{n-1}
    // ...
    // But all elements in a permutation must be distinct.
    // So p_1 = p_n implies p_1 is not distinct from p_n, which means p_1 and p_n must be the same element.
    // This is only possible if n=1, where p_1 is the only element.
    // Since n >= 2, p_1 and p_n must be distinct elements.
    // Therefore, p_1 != p_n.
    // This means that p cannot be a palindrome for n >= 2.
    //
    // Thus, reversing any permutation p of length n >= 2 will always yield a different permutation p_rev.
    // And as shown, F(p_rev) = F(p).
    // So, simply reversing the given permutation p is a valid solution.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

