#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d; // d can be up to 100, but total days can accumulate
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        // Distance from pile i+1 to pile 1 is i
        long long distance = i; 

        // If we don't have enough days to move even one haybale from this pile, skip
        if (remaining_days < distance) {
            break; 
        }

        // Number of haybales available in pile i+1 (0-indexed a[i])
        long long haybales_available = a[i];

        // Calculate how many haybales we can move from this pile
        // Each haybale costs 'distance' days
        long long haybales_to_move = std::min(haybales_available, remaining_days / distance);

        current_a1 += haybales_to_move;
        remaining_days -= haybales_to_move * distance;
    }

    std::cout << current_a1 << std::endl;
}

