#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // If a[i] was 1 or -1, it contributes to has_one/has_minus_one for elements to its left.
            // But we are iterating from right to left, so we need to update has_one/has_minus_one
            // based on elements *to the left of current i* that are still available.
            // The current has_one/has_minus_one flags are for elements 0 to i.
            // When we move to i-1, we need to remove a[i]'s contribution.
            // This logic is tricky if we update flags this way.
            // A simpler approach is to precompute has_one/has_minus_one for prefixes.
            // Or, just check the conditions based on the current state of has_one/has_minus_one
            // which represent if there's a 1 or -1 *before* index i.
            // The current has_one/has_minus_one are for elements 0 to i.
            // When we check a[i], we need to know if there's a 1 or -1 in a[0...i-1].
            // So, we update has_one/has_minus_one *after* checking a[i].
        } else if (a[i] < b[i]) {
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // Update has_one/has_minus_one for the next iteration (i-1)
        // These flags should reflect elements from 0 to i-1.
        // Since we are iterating i from n-1 down to 0,
        // the flags `has_one` and `has_minus_one` should represent
        // if there is a 1 or -1 in `a[0...i-1]`.
        // So, before processing `a[i]`, these flags should represent `a[0...i-1]`.
        // Let's re-evaluate the loop structure.

        // The current `has_one` and `has_minus_one` flags are for elements `a[0...i]`.
        // When checking `a[i]`, we need to know if there's a `1` or `-1` at an index `k < i`.
        // So, the flags should be updated *after* checking `a[i]`, but *before* moving to `i-1`.
        // Or, initialize them to false, and update them as we iterate from left to right.
        // Let's re-think the loop direction.

        // If we iterate from left to right (i = 0 to n-1):
        // For a[0], it must be a[0] == b[0]. If not, impossible.
        // Then, update has_one/has_minus_one based on a[0].
        // For a[1], if a[1] < b[1], need has_one from a[0]. If a[1] > b[1], need has_minus_one from a[0].
        // Then, update has_one/has_minus_one based on a[1] (for future elements a[2...]).
        // This seems more natural.

        // Let's restart the logic with left-to-right iteration.
    }

    // Reset flags for left-to-right pass
    has_one = false;
    has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) {
            // No change needed for a[i].
            // Update flags for elements to its right.
        } else if (a[i] < b[i]) {
            // a[i] needs to be increased. Requires a '1' from an index k < i.
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // a[i] needs to be decreased. Requires a '-1' from an index k < i.
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // Update has_one/has_minus_one for elements a[i+1...n-1]
        // based on the current a[i].
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

