int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is 0, it means all other elements in the row are 0.
        // This can only happen if n=1 (not possible by constraints) or if p[i]=1
        // and all other p[j] are also 1 (not possible for a permutation).
        // Or if p[i] is 1 and all other p[j] are > 1, then min(p[i], p[j]) = 1.
        // So max_val_in_row will be at least 1 if n > 1.
        // The only case where max_val_in_row could be 0 is if n=1, but n >= 2.
        // So max_val_in_row will be at least 1.
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all other elements are less than n-1.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if p[i] is the largest element (n), and all other p[j] are < n.
    // Then max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = n-1.
    // So if p[i] was n, our current logic would assign it n-1.
    // We need to find if there's a missing 'n' in the values assigned to p.
    // The values in p should be a permutation of 1 to n.
    // If we have assigned n-1 to some p[i], and n is not present in p,
    // it means that p[i] should actually be n.

    // Count occurrences of each number from 1 to n.
    std::vector<bool> seen(n + 1, false);
    for (int val : p) {
        if (val >= 1 && val <= n) { // Ensure val is within expected range
            seen[val] = true;
        }
    }

    bool n_is_missing = true;
    if (n >= 1) { // Check if n is in the range of seen indices
        n_is_missing = !seen[n];
    }

    if (n_is_missing) {
        // If 'n' is missing, it means one of the elements that was supposed to be 'n'
        // was incorrectly assigned 'n-1' by our logic.
        // This happens because max_{j!=k} min(p[k], p[j]) = max_{j!=k} p[j] = n-1
        // when p[k] = n.
        // So we need to find an element that was assigned n-1 and change it to n.
