#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_price_suffix = a[n - 1]; // Minimum price encountered so far from the right

        // Iterate from right to left, starting from the second to last element
        // The last element (a[n-1]) can never be a bad price as there are no later days.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_price_suffix) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_price_suffix,
                // it means a[i] is less than or equal to some price to its right.
                // This a[i] itself becomes a new candidate for min_price_suffix
                // for elements further to its left.
                min_price_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

