    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available (c + m + x) divided by 3.
        // 2. The number of coders available (c), since each team needs at least one coder.
        // 3. The number of mathematicians available (m), since each team needs at least one mathematician.
        // So, k <= (c + m + x) / 3, k <= c, k <= m.
        // This means k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.

        long long max_possible_teams = std::min({c, m, (c + m + x) / 3});

        std::cout << max_possible_teams << "\n";
    }
    return 0;
}

