#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of (h/2) / n = h / (2n).

    // Let x_k be the distance from the apex to the k-th cut.
    // The area of the triangle from the apex to a cut at distance x is A(x) = x^2 / (2h).
    // We want the area from the apex to the k-th cut to be k times the area of one piece.
    // So, A(x_k) = k * (h / (2n)).
    // x_k^2 / (2h) = k * h / (2n)
    // x_k^2 = k * h^2 / n
    // x_k = sqrt(k * h^2 / n) = h * sqrt(k / n)

    // We need to find n-1 cuts, for k = 1, 2, ..., n-1.
    std::cout << std::fixed << std::setprecision(12);
    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
