int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use in the alternating sequence to generate k distinct differences.
                       // The differences will be k, k-1, ..., 1.
                       // For example, if k=3, we use 1, 4, 2, 3. Differences are 3, 2, 1.
                       // The numbers used are 1, 2, 3, 4. So right = k+1.

    bool use_left = true;
    for (int i = 0; i < k + 1; ++i) {
        if (use_left) {
            std::cout << left << " ";
            left++;
        } else {
            std::cout << right << " ";
            right--;
        }
        use_left = !use_left;
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these numbers in increasing order to ensure that
    // the new differences generated are all 1.
    // This does not introduce any new distinct differences if k >= 1.
    // If k=1, we have 1, 2. Then append 3, 4, ..., n. Differences are all 1.
    // If k > 1, we already have differences 1, 2, ..., k. Appending 1s doesn't change the set of distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

