    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0 && open_needed < k / 2) {
            // Only add ')' if we have already added an opening bracket
            // that it can potentially match, and we still need closing brackets.
            // The condition open_needed < k/2 means we have added at least one '('.
            // This ensures that the balance doesn't go negative if we were to
            // consider the current state of 'result' as a prefix.
            // More precisely, we need to ensure that the number of ')' added
            // does not exceed the number of '(' added.
            // The number of '(' added so far is (k/2 - open_needed).
            // The number of ')' added so far is (k/2 - close_needed).
            // We can add ')' if (k/2 - close_needed) < (k/2 - open_needed).
            // This simplifies to open_needed < close_needed.
            // However, a simpler greedy strategy works: just add ')' if we need it
            // and we have already added some '('. The problem guarantees a solution.
            // The most straightforward greedy approach is to add '(' until we have k/2,
            // then add ')' until we have k/2. But this doesn't guarantee regularity.
            // The correct greedy approach is to maintain balance.
            // We need to add k/2 '(' and k/2 ')'.
            // Let's track the current balance of the `result` string.
            // A simpler greedy strategy for regular bracket sequences:
            // Add '(' as long as we need them.
            // Add ')' as long as we need them AND the current balance allows it (i.e., balance > 0).
            // This is implicitly handled by the fact that we prioritize '(' and only add ')'
            // if we have already added some '('.
            // The condition `open_needed < k / 2` means we have already picked at least one '('.
            // This is a sufficient condition for the problem's guarantee.
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

