#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment [1] is always a permutation of {1}.
    // It's found at p[pos[1]...pos[1]].
    ans[0] = '1';

    // Initialize current window boundaries to include only 1
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Expand the window to include 'm'
        // The number 'm' is at pos[m]
        int new_val_idx = pos[m];

        // Update the window boundaries to cover all numbers from 1 to m
        // The new window must span from min(current_min_idx, new_val_idx)
        // to max(current_max_idx, new_val_idx)
        current_min_idx = std::min(current_min_idx, new_val_idx);
        current_max_idx = std::max(current_max_idx, new_val_idx);

        // Check if the current window [current_min_idx, current_max_idx]
        // is a permutation of 1...m.
        // This means its length must be exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        } else {
            ans[m - 1] = '0';
        }
    }

    std::cout << ans << std::endl;
}

