            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d >= 4.0, so d^2 - 4d >= 0
            // x^2 - dx + d = 0
            // x = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Since d >= 4, d - sqrt(d^2 - 4d) is always non-negative.
            // d^2 >= d^2 - 4d
            // sqrt(d^2) >= sqrt(d^2 - 4d)
            // d >= sqrt(d^2 - 4d) (since d is non-negative)
            // So, d - sqrt(d^2 - 4d) >= 0.
            // Both a and b will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_ok: prefix_ok[i] is true if a[0]...a[i] can form a strictly increasing sequence
    // starting from 0, 1, 2, ...
    // i.e., a[j] >= j for all j from 0 to i.
    std::vector<bool> prefix_ok(n);
    prefix_ok[0] = (a[0] >= 0); // a[0] must be >= 0
    for (int i = 1; i < n; ++i) {
        prefix_ok[i] = prefix_ok[i-1] && (a[i] >= i);
    }

    // Calculate suffix_ok: suffix_ok[i] is true if a[i]...a[n-1] can form a strictly decreasing sequence
    // ending with ..., 2, 1, 0.
    // i.e., a[j] >= (n-1)-j for all j from i to n-1.
    std::vector<bool> suffix_ok(n);
    suffix_ok[n-1] = (a[n-1] >= 0); // a[n-1] must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        suffix_ok[i] = suffix_ok[i+1] && (a[i] >= (n - 1) - i);
    }

    // Check if there exists a peak k (0-indexed) such that
    // a[0]...a[k] can be made strictly increasing (0, 1, ..., k)
    // AND a[k]...a[n-1] can be made strictly decreasing (k, k-1, ..., 0)
    // The condition for a peak k is that a[k] must be >= k AND a[k] must be >= (n-1)-k.
    // This is equivalent to a[k] >= max(k, (n-1)-k).
    // However, the prefix_ok and suffix_ok already check the minimum values for the elements.
    // We just need to ensure that the peak element a[k] can satisfy both conditions simultaneously.
    // The conditions are:
    // 1. a[j] >= j for j <= k (covered by prefix_ok[k])
    // 2. a[j] >= (n-1)-j for j >= k (covered by suffix_ok[k])
    // If both prefix_ok[k] and suffix_ok[k] are true, then a[k] can be made to be max(k, (n-1)-k)
    // or any value greater than that, as long as it satisfies the strict inequalities.
    // The crucial part is that a[k] must be strictly greater than a[k-1] and a[k+1].
    // If we set a[j]' = j for j < k and a[j]' = (n-1)-j for j > k,
    // then a[k-1]' = k-1 and a[k+1]' = (n-1)-(k+1).
    // We need a[k]' > k-1 and a[k]' > (n-1)-(k+1).
    // The smallest possible value for a[k]' that satisfies these is max(k, (n-1)-k).
    // Since a[k] >= k and a[k] >= (n-1)-k are already checked by prefix_ok[k] and suffix_ok[k],
    // if both are true, then a[k] is large enough to be the peak.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (prefix_ok[k] && suffix_ok[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

