int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (smaller elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ... will also be > a[i]
        // We want to use the smallest possible a[j] that satisfies a[j] > a[i]
        // to leave larger elements for later positions that might need even larger values.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element for placement
        } else {
            // No more elements available that are greater than a[i]
            // Since a is sorted, no subsequent a[k] (k > i) will find a match either.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<Element> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareA);

    // Sort B in ascending order
    std::sort(B.begin(), B.end(), compareB);

    // Create the result array A'
    // A'_i will be A[j].value where B[i].original_index == B[j].original_index
    // The goal is to assign A_sorted[i] to the position corresponding to B_sorted[m-1-i].original_index
    std::vector<long long> A_prime(m);
    for (int i = 0; i < m; ++i) {
        // A[i] is the i-th smallest element from original A
        // B[m-1-i] is the i-th largest element from original B
        // We want to pair A[i] with B[m-1-i]
        // The value A[i].value should go to the position B[m-1-i].original_index
        A_prime[B[m - 1 - i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

