// Function to check if a sub-array is a permutation
// It checks if all elements are distinct and if the maximum element equals its length.
// This implies it contains all numbers from 1 to length exactly once.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return false; // A permutation must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len; // Max element must be equal to length
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix distinct counts and suffix distinct counts
    std::vector<int> prefix_distinct_count(n);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] <= n && !seen_prefix[a[i]]) { // a[i] can be up to n-1, so n+1 size is fine
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        prefix_distinct_count[i] = current_distinct_prefix;
    }

    std::vector<int> suffix_distinct_count(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] <= n && !seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        suffix_distinct_count[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check conditions for p1 (first l1 elements)
        // 1. Max element in p1 must be l1
        // 2. Number of distinct elements in p1 must be l1
        bool p1_is_candidate = (prefix_max[l1 - 1] == l1) && (prefix_distinct_count[l1 - 1] == l1);

        // Check conditions for p2 (last l2 elements)
        // 1. Max element in p2 must be l2
        // 2. Number of distinct elements in p2 must be l2
        bool p2_is_candidate = (suffix_max[l1] == l2) && (suffix_distinct_count[l1] == l2);

        if (p1_is_candidate && p2_is_candidate) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 != 1) { // N/2 is odd and N/2 > 1
                    // Taking N/2 leaves an odd number for opponent, which is good.
                    // But if N/2 is odd, taking 1 leaves N-1 (odd) for opponent.
                    // If N/2 is odd, taking N/2 is better than taking 1.
                    // Example: N=6. Take 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // It seems taking N/2 is always better if N/2 is odd and N/2 > 1.
                    // The only exception is N=2, where N/2=1.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 = 1
                    // Taking N/2 leaves an even number for opponent.
                    // Taking 1 leaves an odd number for opponent.
                    // If N/2 is even, taking 1 is better to leave an odd number for opponent.
                    // Example: N=4.
                    // Take 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 1+1=2. Opponent: 1+1=2.
                    // Take N/2 (2): N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 2+1=3. Opponent: 1.
                    // This logic is flawed. The goal is to maximize own coins.
                    // If N/2 is even, taking N/2 is better for current player.
                    // If N/2 is odd, taking N/2 is better for current player.
                    // The only time taking 1 is better is if it sets up a better future for current player.
                    // This happens when N is even, and N/2 is odd, and N/2 > 1.
                    // In this case, taking N/2 gives a large chunk.
                    // Taking 1 leaves N-1 (odd) for opponent. Opponent takes 1. N-2 (even).
                    // This is a greedy choice. Take N/2 if it's available and large.
                    // The only time we might not take N/2 is if N/2 is even, and taking 1 leads to a better outcome.
                    // If N is even:
                    // Option 1: Take N/2. Chanek gets N/2. Remaining N/2.
                    // Option 2: Take 1. Chanek gets 1. Remaining N-1.
                    // If N/2 is odd (and N/2 > 1):
                    //   Taking N/2 is better. Chanek gets N/2. Opponent faces odd N/2.
                    //   Taking 1: Chanek gets 1. Opponent faces odd N-1.
                    //   N/2 is always greater than 1. So take N/2.
                    // If N/2 is even:
                    //   Taking N/2: Chanek gets N/2. Opponent faces even N/2.
                    //   Taking 1: Chanek gets 1. Opponent faces odd N-1.
                    //   Here, taking N/2 is generally better because N/2 is much larger than 1.
                    //   The only exception is N=2, where N/2=1.
                    //   For N=4, N/2=2 (even).
                    //     Take 2: Chanek gets 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Total Chanek: 2+1=3.
                    //     Take 1: Chanek gets 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Total Chanek: 1+1=2.
                    //   So for N=4, taking N/2 is better.
                    //   It seems the greedy strategy is always to take N/2 if N is even and N > 2.
                    //   If N=2, take 1.
                    //   If N is odd, take 1.

                    // Re-evaluating the greedy strategy:
                    // If N is odd: Chanek takes 1. N becomes N-1 (even).
                    // If N is even:
                    //   If N=2: Chanek takes 1. N becomes 1 (odd).
                    //   If N > 2: Chanek takes N/2. N becomes N/2.
                    // This is the simplest greedy strategy. Let's test it.

                    // The example for N=6:
                    // Chanek takes 3. N=3. Chanek: 3.
                    // Opponent takes 1. N=2. Opponent: 1.
                    // Chanek takes 1. N=1. Chanek: 3+1=4.
                    // Opponent takes 1. N=0. Opponent: 1+1=2.
                    // Chanek gets 4. This matches the example.

                    // The example for N=5:
                    // Chanek takes 1. N=4. Chanek: 1.
                    // Opponent takes 2. N=2. Opponent: 2.
                    // Chanek takes 1. N=1. Chanek: 1+1=2.
                    // Opponent takes 1. N=0. Opponent: 2+1=3.
                    // Chanek gets 2. This matches the example.

                    // This simple greedy strategy seems to work for the examples.
                    // Let's implement this.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    n -= 1;
                } else {
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

