char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char ch : s) {
            counts[ch]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure deterministic output if counts are equal
        // R, P, S is a common order, or alphabetical. Let's use R, P, S.
        // The problem statement implies any optimal answer is fine.
        // R beats S, S beats P, P beats R.
        // If we play P, we beat R.
        // If we play R, we beat S.
        // If we play S, we beat P.
        // So if bot plays R most, we play P.
        // If bot plays S most, we play R.
        // If bot plays P most, we play S.

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }

        // If counts are equal, the problem says any optimal answer is fine.
        // The current logic picks 'P' over 'S' if counts are equal, and 'S' over 'R' if counts are equal.
        // For example, if R=2, S=2, P=1, it will pick S.
        // If R=2, S=1, P=2, it will pick P.
        // This is fine.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum, X = current_xor_sum
    // We want S' = 2 * X'
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Case 1: Append 0 elements.
    // If S == 2 * X, then the array is already good.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // Case 2: Append 2 elements.
    // Let's try to append two elements.
    // We need S + b1 + b2 = 2 * (X ^ b1 ^ b2)
    // A simple strategy is to make X' equal to X.
    // If we append b1 = X, then X' = X ^ X = 0.
    // Then we need S + X = 2 * 0 = 0. This is generally not possible since S and X are non-negative.
    // So, we need X' to be non-zero.

    // Consider appending two elements: b1 and b2.
    // Let b1 = current_xor_sum.
    // Then the new XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
    // The new sum becomes current_sum + current_xor_sum.
    // The condition would be current_sum + current_xor_sum = 2 * 0 = 0.
    // This is only true if current_sum = 0 and current_xor_sum = 0, which means all initial elements were 0.
    // If all elements are 0, then current_sum = 0, current_xor_sum = 0, and 0 = 2*0, so it's already good (handled by Case 1).
    // So, this strategy of making XOR sum 0 doesn't work for non-zero initial sums.

    // Let's try to append two elements such that the final XOR sum is some value Y, and the final sum is 2Y.
    // A common trick for XOR problems is to make the XOR sum equal to the sum.
    // This is not exactly what we need, but related.
    // We need S' = 2 * X'.
    // Let's try to append b1 and b2 such that X' = current_xor_sum.
    // This means b1 ^ b2 = 0, so b1 = b2.
    // If we append b1 and b1, then X' = current_xor_sum ^ b1 ^ b1 = current_xor_sum.
    // The sum becomes S + 2*b1.
    // We need S + 2*b1 = 2 * current_xor_sum.
    // 2*b1 = 2 * current_xor_sum - S.
    // b1 = current_xor_sum - S/2.
    // This requires S to be even, and current_xor_sum - S/2 to be non-negative.
    // This is not guaranteed.

    // Let's try a different approach.
    // We need S' = 2 * X'.
    // Let's append two elements: b1 and b2.
    // A simple choice for b1 is current_xor_sum.
    // After appending b1 = current_xor_sum:
    // New sum: S_1 = current_sum + current_xor_sum
    // New XOR sum: X_1 = current_xor_sum ^ current_xor_sum = 0
    // Now we need to append one more element, b2, such that:
    // S_1 + b2 = 2 * (X_1 ^ b2)
    // S_1 + b2 = 2 * (0 ^ b2)
    // S_1 + b2 = 2 * b2
    // S_1 = b2
    // So, b2 = current_sum + current_xor_sum.
    // This means we append current_xor_sum and (current_sum + current_xor_sum).
    // Let's verify this.
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
    // Final sum S' = current_sum + b1 + b2
    // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S' = 2 * (current_sum + current_xor_sum)
    // Final XOR sum X' = current_xor_sum ^ b1 ^ b2
    // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X' = 0 ^ (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum
    // Is S' = 2 * X'?
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum). Yes!
    // This strategy always works and uses 2 elements.
    // The elements are non-negative since current_sum and current_xor_sum are non-negative.
    // The values can be large, up to 10^9 * 10^5 + 10^9 ~ 10^14 + 10^9, which fits in long long.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

