int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1000000007;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will cause this 'b' to duplicate
            // and move past it.
            // The number of 'a's currently accumulated (count_a)
            // represents the number of 'a's that will interact with
            // this 'b' (and any 'b's generated from it).
            // Each such interaction adds count_a steps.
            total_steps = (total_steps + count_a) % mod;
            // After this 'b' has been "processed" by all 'a's to its left,
            // it effectively doubles the number of 'a's that will interact
            // with 'b's further to the left.
            // This is because the original 'b' and the new 'b' (from 'ab' -> 'bba')
            // will both be available to interact with 'a's to their left.
            // So, the effective count of 'a's for the next 'b' to the left doubles.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to interact with 'b's to their left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

