int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[char_idx][i] stores the count of char_idx ('x', 'y', 'z')
    // in the prefix s[0...i-1].
    // char_idx 0 for 'x', 1 for 'y', 2 for 'z'.
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;
        // Adjust to 0-indexed
        --l; 
        // r is already exclusive for prefix sum, so it's s[l...r-1]

        if (r - l < 3) { // Substring length less than 3, no 3-char subsequences
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l];

        // The condition for termination is that the counts of 'x', 'y', 'z'
        // differ by at most 1.
        // This means max_count - min_count <= 1.
        int max_count = std::max({count_x, count_y, count_z});
        int min_count = std::min({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

