#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;
    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int split_val = 0; split_val <= 9; ++split_val) {
        std::vector<int> colors(n);
        bool possible = true;

        int last_d1 = -1; // Last digit in sequence 1
        int first_d2 = -1; // First digit in sequence 2 (among those > split_val)

        // First pass: assign colors based on split_val
        // Digits < split_val are 1
        // Digits > split_val are 2
        // Digits == split_val are initially 1
        for (int i = 0; i < n; ++i) {
            if (d[i] < split_val) {
                colors[i] = 1;
            } else if (d[i] > split_val) {
                colors[i] = 2;
            } else { // d[i] == split_val
                colors[i] = 1; // Tentatively assign to color 1
            }
        }

        // Second pass: adjust colors for digits == split_val
        // Find the first occurrence of a digit > split_val.
        // All subsequent digits == split_val must be color 2.
        // All preceding digits == split_val must be color 1.
        // This ensures that the transition from color 1 to color 2 for split_val happens at most once.
        int first_greater_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (d[i] > split_val) {
                first_greater_idx = i;
                break;
            }
        }

        if (first_greater_idx != -1) {
            for (int i = first_greater_idx; i < n; ++i) {
                if (d[i] == split_val) {
                    colors[i] = 2;
                }
            }
        }

        // Validate the constructed coloring
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;

        for (int i = 0; i < n; ++i) {
            if (colors[i] == 1) {
                s1_digits.push_back(d[i]);
            } else {
                s2_digits.push_back(d[i]);
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible = false;
                break;
            }
        }
        if (!possible) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible = false;
                break;
            }
        }
        if (!possible) continue;

        // Check if last(S1) <= first(S2)
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible = false;
            }
        }
        if (!possible) continue;

        // If all checks pass, print the coloring and return
        for (int i = 0; i < n; ++i) {
            std::cout << colors[i];
        }
        std::cout << "\n";
        return;
    }

    // If no split_val works
    std::cout << "-\n";
}

