// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
        } else {
            std::vector<long long> q_prime_factors = get_prime_factors(q);
            long long max_x = 0;

            for (long long factor : q_prime_factors) {
                long long current_p = p;
                while (current_p % q == 0) {
                    current_p /= factor;
                }
                max_x = std::max(max_x, current_p);
            }
            std::cout << max_x << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
