#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& str) {
    int n = str.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && str[z[i]] == str[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-array for s[i...n-1] + s[0...i-1]
    std::vector<std::vector<int>> z_arrays(n);
    for (int i = 0; i < n; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = compute_z_array(shifted_s);
    }

    // Group indices by their starting character s[k]
    std::map<char, std::vector<int>> indices_by_char;
    for (int k = 0; k < n; ++k) {
        indices_by_char[s[k]].push_back(k);
    }

    double total_probability = 0.0;

    // Iterate over each possible first character c_0
    for (auto const& [c0_char, k_indices] : indices_by_char) {
        int num_k_for_c0 = k_indices.size();

        if (num_k_for_c0 == 1) {
            // If only one k matches c_0, Vasya wins immediately for this c_0
            total_probability += 1.0 / n;
            continue;
        }

        // If multiple k's match c_0, Vasya needs to pick a second position p
        // to maximize win probability for this c_0.
        // The probability for this c_0 is (1/n) * (max_win_prob_for_this_c0).

        double max_win_prob_for_this_c0 = 0.0;

        // Iterate over all possible second positions p (1-indexed, so p-1 is 0-indexed)
        // p can be from 1 to n-1 (since p=0 is t[0], which is already known)
        for (int p_minus_1 = 1; p_minus_1 < n; ++p_minus_1) {
            // For a fixed c_0 and a fixed p, count how many k's are uniquely determined.
            // A k is uniquely determined if (s[k], s[(k+p) % n]) is unique among the candidates.

            // Group candidate k's by their (s[k], s[(k+p) % n]) pair
            std::map<char, std::vector<int>> candidates_by_c_p;
            for (int k_idx : k_indices) {
                candidates_by_c_p[s[(k_idx + p_minus_1) % n]].push_back(k_idx);
            }

            int num_unique_k_for_this_p = 0;
            for (auto const& [cp_char, k_sub_indices] : candidates_by_c_p) {
                if (k_sub_indices.size() == 1) {
                    num_unique_k_for_this_p++;
                }
            }

            max_win_prob_for_this_c0 = std::max(max_win_prob_for_this_c0, 
                                                 (double)num_unique_k_for_this_p / num_k_for_c0);
        }

        total_probability += (1.0 / n) * num_k_for_c0 * max_win_prob_for_this_c0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_probability << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for simpler logic, swap if necessary
        if (n > m) {
            std::swap(n, m);
        }

        // Case 1: k < m. Cannot reach (n, m) in k moves if k is less than the maximum coordinate.
        // This is because each move changes at most one coordinate by 1 (in absolute value)
        // if we consider only one direction, or both by 1.
        // The minimum number of moves to reach (n, m) is max(n, m).
        // So if k < m, it's impossible.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= m.
        // We want to maximize diagonal moves.
        // The maximum number of diagonal moves is limited by the target coordinates.
        // We can make min(n, m) diagonal moves to reach (n, m) if n=m.
        // Or we can make n diagonal moves to reach (n, n) and then m-n straight moves to (n, m).
        // This takes n + (m-n) = m moves.
