    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // These elements are a[0]...a[median_idx-1]
    // If a[i] > s, we must decrease it to s.
    // Since a is sorted, if a[i] > s, then a[i+1], ..., a[median_idx-1] are also >= a[i] > s.
    // We only need to consider elements that are currently greater than s.
    // If a[i] <= s, it already satisfies the condition.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These elements are a[median_idx+1]...a[n-1]
    // If a[i] < s, we must increase it to s.
    // Since a is sorted, if a[i] < s, then a[i-1], ..., a[median_idx+1] are also <= a[i] < s.
    // We only need to consider elements that are currently less than s.
    // If a[i] >= s, it already satisfies the condition.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

