// Using long long for sums to prevent overflow
// Using int for indices as n <= 2e5

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] unused, a[1] will be set for each query
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_val[i] stores the total y accumulated when starting at x=i and performing step_sub
    // dp_next_x[i] stores the next x value after performing step_sub from x=i
    // dp_val[i] and dp_next_x[i] are computed for the case where a[i] is the value used in step_sub
    std::vector<long long> dp_val(n + 1);
    std::vector<int> dp_next_x(n + 1);
    std::vector<bool> visited(n + 1, false); // For cycle detection during DP calculation

    // Iterate backwards from n to 1 to fill DP tables
    for (int i = n; i >= 1; --i) {
        // The value a[i] is used for the step_sub operation
        long long current_a_val = a[i];
        int next_x_after_sub = i - current_a_val;

        if (next_x_after_sub <= 0) {
            // Terminates immediately after step_sub
            dp_val[i] = current_a_val;
