                }

                state[k] = 1; // Mark as visiting

                long long val1 = a[k];
                long long x_after_add_ll = (long long)k + val1;
                long long y_accumulated = val1;

                if (x_after_add_ll <= 0 || x_after_add_ll > n) {
                    dp_y[k] = y_accumulated;
