                            dp_y[k] = -1;
                            dp_final_x[k] = 0; // Dummy
                        } else {
                            dp_y[k] = y_accumulated + dp_y[x_after_sub];
                            dp_final_x[k] = dp_final_x[x_after_sub];
                        }
                    }
                }
                state[k] = 2; // Mark as computed
            };

            // Precompute for k = 2 to n
            for (int k = 2; k <= n; ++k) {
                compute_dp(k, compute_dp);
            }

            // For each query i (1 to n-1), set a[1] = i and compute dp for k=1
            for (int i = 1; i < n; ++i) {
                a[1] = i;
                // Reset state for k=1 for each query
                state[1] = 0;
                compute_dp(1, compute_dp);
                std::cout << dp_y[1] << "\n";
            }

            return 0;
        }
    }
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type; // 1 for add, 2 for max
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> min_initial_val(n, std::numeric_limits<long long>::min());
    std::vector<long long> max_initial_val(n, std::numeric_limits<long long>::max());

    // Process operations in reverse to determine constraints on initial_a
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 2) { // Max query
            long long current_max_val = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_initial_val[j] = std::min(max_initial_val[j], current_max_val);
            }
        } else { // Add operation
            long long d = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_initial_val[j] -= d;
                max_initial_val[j] -= d;
            }
        }
    }

    // Initialize initial_a based on constraints
    for (int i = 0; i < n; ++i) {
        if (min_initial_val[i] > max_initial_val[i]) {
            // This should not happen if a solution exists, but good to check
            // If it happens, it means a contradiction in constraints.
            // For this problem, we can just pick max_initial_val[i]
            // and let the verification step catch it.
            initial_a[i] = max_initial_val[i];
        } else {
            initial_a[i] = max_initial_val[i]; // Pick the largest possible value
        }

        // Ensure initial_a[i] is within [-10^9, 10^9]
        initial_a[i] = std::max(initial_a[i], -1000000000LL);
        initial_a[i] = std::min(initial_a[i], 1000000000LL);
    }

    // Verify the solution
    std::vector<long long> current_a = initial_a;
    std::vector<long long> delta_prefix_sum(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) { // Add operation
            delta_prefix_sum[op.l] += op.val;
            if (op.r + 1 < n) {
                delta_prefix_sum[op.r + 1] -= op.val;
            }
        } else { // Max query
            long long current_delta = 0;
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = 0; j < n; ++j) {
                current_delta += delta_prefix_sum[j];
                if (j >= op.l && j <= op.r) {
                    max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta);
                }
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

