struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a[0] + a[1]
    // max_f = a[n-1] + a[n-2]
    // goodness = (a[n-1] + a[n-2]) - (a[0] + a[1])
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for this case is to put a[0] in one subsequence (S1)
    // and all other elements a[1]...a[n-1] in the other subsequence (S2).
    // This ensures that a[0] is always paired with +h, and other pairs are without +h.
    //
    // min_f:
    //   - a[0] + a[1] + h (a[0] in S1, a[1] in S2)
    //   - a[1] + a[2] (a[1], a[2] in S2)
    //   min_f = min(a[0] + a[1] + h, a[1] + a[2])
    //
    // max_f:
    //   - a[0] + a[n-1] + h (a[0] in S1, a[n-1] in S2)
    //   - a[n-1] + a[n-2] (a[n-1], a[n-2] in S2)
    //   max_f = max(a[0] + a[n-1] + h, a[n-1] + a[n-2])
    //
    // goodness = max_f - min_f

    long long min_f2_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    long long max_f2_val = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 1].value + elements[n - 2].value);
    long long goodness2 = max_f2_val - min_f2_val;

    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Case 3: A special partition where a[0] and a[1] are in different subsequences,
    // and a[n-1] and a[n-2] are in different subsequences.
    // This is relevant if h is small enough that a[0]+a[1]+h is not too large.
    // Consider putting a[0] in S1, a[1] in S2, and all others in S2.
    // This is exactly partition2.
    //
    // What if we put a[0] in S1, a[n-1] in S2, and others in S1?
    // S1: {a[0], a[1], ..., a[n-2]}
    // S2: {a[n-1]}
    // min_f:
    //   - a[0] + a[1] (in S1)
    //   - a[0] + a[n-1] + h (a[0] in S1, a[n-1] in S2)
    //   min_f = min(a[0] + a[1], a[0] + a[n-1] + h)
    // max_f:
    //   - a[n-2] + a[n-3] (in S1)
    //   - a[n-2] + a[n-1] + h (a[n-2] in S1, a[n-1] in S2)
    //   max_f = max(a[n-2] + a[n-3], a[n-2] + a[n-1] + h)
    //
    // This is symmetric to partition2 if we swap S1 and S2 labels.
    // The key is that one element is isolated.
    //
    // The only other "interesting" partition is when a[0] and a[n-1] are in different groups,
    // and a[0] and a[1] are in the same group, and a[n-1] and a[n-2] are in the same group.
    // This means S1 = {a[0], a[1], ..., a[k]} and S2 = {a[k+1], ..., a[n-1]} for some k.
    // This is not what the problem implies. The problem allows non-continuous subsequences.
    //
    // The critical observation is that the minimum possible value of f is either:
    //   1. a[0] + a[1] (if a[0] and a[1] are in the same group)
    //   2. a[0] + a[1] + h (if a[0] and a[1] are in different groups)
    // The maximum possible value of f is either:
    //   1. a[n-1] + a[n-2] (if a[n-1] and a[n-2] are in the same group)
    //   2. a[n-1] + a[n-2] + h (if a[n-1] and a[n-2] are in different groups)
    //   3. a[0] + a[n-1] + h (if a[0] and a[n-1] are in different groups)
    //
    // Let's consider the four boundary values:
    // min_val_same = a[0] + a[1]
    // min_val_diff = a[0] + a[1] + h
    // max_val_same = a[n-1] + a[n-2]
    // max_val_diff = a[n-1] + a[0] + h (this is the largest possible sum with +h, involving smallest and largest elements)
    //
    // The overall minimum f will be min(min_val_same, min_val_diff)
    // The overall maximum f will be max(max_val_same, max_val_diff)
    //
    // If we put all elements in one group (partition1):
    // min_f = a[0] + a[1]
    // max_f = a[n-1] + a[n-2]
    // goodness = (a[n-1] + a[n-2]) - (a[0] + a[1])
    //
    // If we put a[0] in group 1 and all others in group 2 (partition2):
    // min_f = min(a[0] + a[1] + h, a[1] + a[2])
    // max_f = max(a[0] + a[n-1] + h, a[n-1] + a[n-2])
    // goodness = max_f - min_f
    //
    // If we put a[n-1] in group 1 and all others in group 2 (symmetric to partition2):
    // min_f = min(a[0] + a[n-1] + h, a[0] + a[1])
    // max_f = max(a[n-2] + a[n-1] + h, a[n-2] + a[n-3])
    // goodness = max_f - min_f
    // This is not necessarily better than partition2.
    //
    // What if we put a[0] and a[n-1] in different groups, and all other elements in one of those groups?
    // E.g., S1 = {a[0]}, S2 = {a[1], ..., a[n-1]}. This is partition2.
    // E.g., S1 = {a[n-1]}, S2 = {a[0], ..., a[n-2]}.
    //   min_f = min(a[0] + a[n-1] + h, a[0] + a[1])
    //   max_f = max(a[n-2] + a[n-1] + h, a[n-2] + a[n-3])
    //   goodness = max_f - min_f
    //
    // Let's compare goodness1 and goodness2.
    // If goodness1 <= goodness2, then partition1 is better or equal.
    // Otherwise, partition2 is better.

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

