int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // dp[i] will store the maximum 'r' such that all (l, r') with r' <= r
    // and l <= i are "bad" (do not contain any s_x = s_{x+k} = s_{x+2k} pattern).
    // More precisely, dp[i] stores the smallest r_min such that for any l <= i,
    // all (l, r) with r < r_min are "bad".
    // Or, dp[i] stores the maximum r_max such that for any l <= i,
    // all (l, r) with r > r_max are "good".
    // Let's define dp[i] as the smallest index j such that the substring s[i...j]
    // contains a pattern s_x = s_{x+k} = s_{x+2k} where x >= i.
    // If no such pattern exists for x >= i, dp[i] = n.
    // This is not quite right.

    // Let's define `next_bad_r[i]` as the smallest `r` such that `s[i...r]`
    // contains a pattern `s_x = s_{x+k} = s_{x+2k}` with `x >= i`.
    // If no such `r` exists, `next_bad_r[i] = n`.
    // This means for a fixed `l`, any `r` such that `l <= r < next_bad_r[l]`
    // is an "invalid" pair (l, r).
    // The number of such `r` values is `next_bad_r[l] - l`.
    // So, `invalid_pairs = sum_{l=0}^{n-1} (next_bad_r[l] - l)`.

    std::vector<int> next_bad_r(n + 1, n); // next_bad_r[i] stores the smallest r >= i
                                          // such that there exists x, k with i <= x < x+2k <= r
                                          // and s_x = s_{x+k} = s_{x+2k}.
                                          // Initialize with n, meaning no such pattern found yet.

    // Iterate backwards to compute next_bad_r efficiently.
    // next_bad_r[i] = min(next_bad_r[i+1], current_min_r_for_x_eq_i)
    // current_min_r_for_x_eq_i is the smallest r such that s[i...r] contains a pattern starting at i.

    // We need to find the smallest r for each x.
    // Let `min_r_for_x[x]` be the smallest `r` such that `s[x...r]` contains a pattern
    // `s_x = s_{x+k} = s_{x+2k}` for some `k`.
    // If no such `k` exists, `min_r_for_x[x] = n`.
    std::vector<int> min_r_for_x(n, n);

    for (int x = 0; x < n; ++x) {
        // Check k=1, k=2, k=3
        // For k=1: x, x+1, x+2
        if (x + 2 < n && s[x] == s[x+1] && s[x+1] == s[x+2]) {
            min_r_for_x[x] = std::min(min_r_for_x[x], x + 2);
        }
        // For k=2: x, x+2, x+4
        if (x + 4 < n && s[x] == s[x+2] && s[x+2] == s[x+4]) {
            min_r_for_x[x] = std::min(min_r_for_x[x], x + 4);
        }
        // For k=3: x, x+3, x+6
        if (x + 6 < n && s[x] == s[x+3] && s[x+3] == s[x+6]) {
            min_r_for_x[x] = std::min(min_r_for_x[x], x + 6);
        }
    }

    // Now compute next_bad_r[l]
    // next_bad_r[l] = min_{x=l}^{n-1} (min_r_for_x[x])
    // This can be computed efficiently by iterating backwards.
    // next_bad_r[l] = min(next_bad_r[l+1], min_r_for_x[l])
    // Base case: next_bad_r[n] = n (no patterns starting at or after n)

    for (int l = n - 1; l >= 0; --l) {
        next_bad_r[l] = std::min(next_bad_r[l+1], min_r_for_x[l]);
    }

    for (int l = 0; l < n; ++l) {
        invalid_pairs += (next_bad_r[l] - l);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_coverage_left(n);
    std::vector<long long> head_coverage_right(n);
    for (int i = 0; i < n; ++i) {
        head_coverage_left[i] = h[i] - T;
        head_coverage_right[i] = h[i] + T;
    }

    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        long long current_head_reach_left = head_coverage_left[h_idx];
        long long current_head_reach_right = head_coverage_right[h_idx];

        // Find the first p_i that this head can cover
        // This is implicitly handled by the outer loop advancing p_idx
        // and the inner loop checking p[p_idx] >= current_head_reach_left

        // Greedily cover as many p_i as possible with this head
        // starting from p_idx
        while (p_idx < m && p[p_idx] <= current_head_reach_right) {
            p_idx++;
        }
        if (p_idx == m) { // All p_i covered
            return true;
        }
    }
    return p_idx == m; // True if all p_i were covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p_m and h_1, or h_n and p_1
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i is now treated and out of line

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_chain = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cry from child i in office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry from previous chain reactions
            children[j].p -= total_d_cry_from_chain;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_chain += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

