int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n, 0); // Length of consecutive zeros to the left, including current
    std::vector<int> right_zero_run(n, 0); // Length of consecutive zeros to the right, including current
    std::vector<int> left_one_run(n, 0);  // Length of consecutive ones to the left, including current
    std::vector<int> right_one_run(n, 0); // Length of consecutive ones to the right, including current

    // Calculate left runs
    if (a[0] == 0) left_zero_run[0] = 1; else left_one_run[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right runs
    if (a[n - 1] == 0) right_zero_run[n - 1] = 1; else right_one_run[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0
            if (left_one_run[i - 1] > 0 && right_one_run[i + 1] > 0) { // 1...1 0 1...1 pattern
                int k_val = std::min(left_one_run[i - 1], right_one_run[i + 1]);
                max_k = std::max(max_k, k_val);
                // This 0 will turn into 1 after k_val steps.
                // The final value at this position will be 1.
                final_a[i] = 1;
            }
        } else { // Current element is 1
            if (left_zero_run[i - 1] > 0 && right_zero_run[i + 1] > 0) { // 0...0 1 0...0 pattern
                int k_val = std::min(left_zero_run[i - 1], right_zero_run[i + 1]);
                max_k = std::max(max_k, k_val);
                // This 1 will turn into 0 after k_val steps.
                // The final value at this position will be 0.
                final_a[i] = 0;
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

