    // such that `a''` has `ones_a_prime_count` '1's.
    // Since `ones_b_count <= ones_a_count + parity_a`, it means `ones_b_count <= ones_a_prime_count`.
    // So, we can always form a string `a''` with `ones_a_prime_count` '1's and length at least `|b|`.
    // Then, we can remove prefix characters from `a''` to get `b`.
    // This logic seems sound.

    // Example 1: a = 01011, b = 0110
    // ones_a_count = 3, parity_a = 1
    // max_ones_possible_from_a = 3 + 1 = 4
    // ones_b_count = 2
    // 2 <= 4, so YES.

    // Example 2: a = 0011, b = 1110
    // ones_a_count = 2, parity_a = 0
    // max_ones_possible_from_a = 2 + 0 = 2
    // ones_b_count = 3
    // 3 > 2, so NO.

    if (ones_b_count <= max_ones_possible_from_a) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Prefix sums for left side (jars 0 to n-1)
    // S_L - B_L for eating k jars from left (0 to k-1)
    std::map<int, int> left_balance_to_k;
    left_balance_to_k[0] = 0; // 0 jars eaten, balance 0
    int current_balance_left = 0;
    for (int k = 1; k <= n; ++k) {
        if (a[k - 1] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        if (left_balance_to_k.find(current_balance_left) == left_balance_to_k.end()) {
            left_balance_to_k[current_balance_left] = k;
        }
    }

    // S_R - B_R for eating k jars from right (2n-1 down to 2n-k)
    // Note: The problem statement uses 1-indexed jars, 1 to 2n.
    // Karlsson is between n and n+1.
    // Left jars are 1 to n. Right jars are n+1 to 2n.
    // In 0-indexed array a[0]...a[2n-1]:
    // Left jars are a[0]...a[n-1]. Right jars are a[n]...a[2n-1].
    // Eating k jars from left means a[0]...a[k-1] are eaten.
    // Eating k jars from right means a[2n-1]...a[2n-k] are eaten.

    // The target balance for (S_L - B_L) + (S_R - B_R) is initial_balance.
    // So, (S_R - B_R) = initial_balance - (S_L - B_L).

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Case 1: No jars eaten from the right side (R=0)
    // We need (S_L - B_L) = initial_balance.
    if (left_balance_to_k.count(initial_balance)) {
        min_jars_eaten = std::min(min_jars_eaten, left_balance_to_k[initial_balance]);
    }

    // Iterate through possible number of jars eaten from the right side (R)
    // R goes from 1 to n.
    int current_balance_right = 0; // S_R - B_R
    for (int k_right = 1; k_right <= n; ++k_right) {
        // Jars are a[2n-1], a[2n-2], ..., a[2n-k_right]
        if (a[2 * n - k_right] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }

        int target_left_balance = initial_balance - current_balance_right;
        if (left_balance_to_k.count(target_left_balance)) {
            min_jars_eaten = std::min(min_jars_eaten, left_balance_to_k[target_left_balance] + k_right);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

