int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation always has the same fingerprint.
        // If p is [p_1, p_2, ..., p_n], its adjacent sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
        // Its reverse p' is [p_n, p_{n-1}, ..., p_1].
        // Its adjacent sums are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
        // These are the same set of sums, just in reverse order. Sorting them will yield the same fingerprint.
        // The only case where p' might be equal to p is if p is a palindrome.
        // However, a permutation of distinct integers from 1 to n cannot be a palindrome for n > 1.
        // For example, if p_1 = p_n, then p_1 and p_n are the same value, but they must be distinct elements of the permutation.
        // This is only possible if n=1, but the problem states n >= 2.
        // Thus, for n >= 2, p_i != p_{n-i+1} for at least one i (e.g., p_1 != p_n).
        // Therefore, reversing the permutation always yields a different permutation.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

