void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The first digit is 2.
        // The remaining n-1 digits are 3.
        // This forms the number 233...3 (n-1 times 3).
        // Let's check this construction:
        // 1. s > 0: Yes, it starts with 2.
        // 2. s consists of n digits: Yes, 1 '2' and n-1 '3's.
        // 3. No digit in s equals 0: Yes, only 2 and 3 are used.
        // 4. s is not divisible by any of its digits:
        //    Digits are 2 and 3.
        //    Is s divisible by 2?
        //    s = 2 * 10^(n-1) + 3 * (10^(n-1) - 1) / 9
        //    The last digit of s is 3, which is odd. So s is not divisible by 2.
        //    Is s divisible by 3?
        //    The sum of digits is 2 + (n-1)*3.
        //    If n=2, sum = 2+3 = 5. 5 is not divisible by 3.
        //    If n=3, sum = 2+3+3 = 8. 8 is not divisible by 3.
        //    If n=4, sum = 2+3+3+3 = 11. 11 is not divisible by 3.
        //    In general, sum of digits = 2 + 3n - 3 = 3n - 1.
        //    For s to be divisible by 3, 3n - 1 must be divisible by 3.
        //    However, 3n is always divisible by 3, so 3n - 1 will always have a remainder of 2 when divided by 3.
        //    Thus, s is never divisible by 3.
        // This construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

