#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_so_far = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_so_far) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_so_far, it means a[i] is
            // a new minimum (or equal to the current minimum) for the suffix
            // ending at i. Update min_so_far.
            min_so_far = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

