int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // This is because if p[i] were n-1, then all other p[j] would have to be >= n-1
        // for max_val_in_row to be n-1. But there's only one n-1 in the permutation.
        // If p[i] is n-1, then for some p[j] (which is n), min(p[i], p[j]) = min(n-1, n) = n-1.
        // If p[i] is n, then for any p[j], min(p[i], p[j]) = p[j].
        // So max_val_in_row would be max(p[j] for j!=i) = n-1.
        // Thus, if max_val_in_row is n-1, p[i] must be n.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_R_idx = -1; // Represents the last position where an 'R' was encountered, or -1 for cell 0.
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_dist = std::max(max_dist, i - last_R_idx);
                last_R_idx = i;
            }
        }
        // After the loop, consider the jump from the last 'R' to n+1.
        // The distance is (n+1) - (last_R_idx + 1) = n - last_R_idx.
        // Or, more simply, the distance from last_R_idx to the "end" (n).
        // The cells are 0, 1, ..., n, n+1.
        // If last_R_idx is the index of the last 'R' in string s (0-indexed),
        // then the cell is last_R_idx + 1.
        // The target is cell n+1.
        // The distance from cell (last_R_idx + 1) to cell (n+1) is (n+1) - (last_R_idx + 1) = n - last_R_idx.
        // This is equivalent to the distance from last_R_idx (0-indexed string position) to n (0-indexed string end).
        max_dist = std::max(max_dist, (int)s.length() - last_R_idx);
        std::cout << max_dist << "\n";
    }
    return 0;
}

