int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k_max = n / m; // Maximum k such that k*m <= n

        // Calculate the sum of last digits for k=1 to k=10
        // This forms one full cycle of last digits
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 terms
        long long num_full_cycles = k_max / 10;

        // Sum from full cycles
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining terms after full cycles
        long long remaining_terms = k_max % 10;

        // Add sum for remaining terms
        for (int i = 1; i <= remaining_terms; ++i) {
            total_sum += (static_cast<long long>(i) * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

