        // The elements $a_0, \dots, a_{i-1}$ are $i$ elements.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are $2n-1-j$ elements.
        //
        // The total number of elements that must be "small" for $a_i$ is $k_1$.
        // The total number of elements that must be "large" for $a_j$ is $k_2$.
        //
        // The elements $a_0, \dots, a_{i-1}$ can only serve as "small" elements for $a_i$ or $a_j$.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ can only serve as "large" elements for $a_i$ or $a_j$.
        //
        // The number of elements $a_0, \dots, a_{i-1}$ is $i$.
        // The number of elements $a_{j+1}, \dots, a_{2n-1}$ is $2n-1-j$.
        //
        // We need to satisfy $k_1 \le i + (\text{elements from } a_{i+1} \dots a_{j-1} \text{ assigned to } C_1 \text{ and } \le a_i)$.
        // We need to satisfy $k_2 \le (2n-1-j) + (\text{elements from } a_{i+1} \dots a_{j-1} \text{ assigned to } C_2 \text{ and } \ge a_j)$.
        //
        // The simplest argument is that $a_{n-1}$ and $a_n$ are the two "middle" elements.
        // Any other pair of elements $(a_i, a_j)$ with $i < j$ will either have $i < n-1$ or $j > n$.
        // If $i < n-1$, then $a_i < a_{n-1}$.
        // If $j > n$, then $a_j > a_n$.
        //
        // If $i < n-1$ and $j > n$, then $a_j - a_i > a_n - a_{n-1}$.
        // If $i < n-1$ and $j = n$, then $a_j - a_i = a_n - a_i > a_n - a_{n-1}$.
        // If $i = n-1$ and $j > n$, then $a_j - a_i = a_j - a_{n-1} > a_n - a_{n-1}$.
        //
        // The only remaining case is $i \ge n-1$ and $j \le n$.
        // Since $i < j$, this implies $i=n-1$ and $j=n$.
        // So the minimum difference must be $a_n - a_{n-1}$.

        long long diff = a[n] - a[n - 1];
        std::cout << diff << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: D = d^2 - 4d
            // For real solutions, D >= 0. This is true for d >= 4 or d = 0.
            // a = (d + sqrt(D)) / 2
            // b = (d - sqrt(D)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Check if a and b are non-negative.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is clearly positive. So a > 0.
            // For b, we need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square them:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, and we are in the d >= 4 case, b will always be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

