            ans3 = "Ya";
        }
    }

    // Box 4: [1, inf) - Positive, magnitude >= 1
    // Possible if final product is positive AND magnitude >= 1.
    // Final product positive: (A+B) is even.
    // Final product magnitude >= 1:
    //   - If A+D > 0 (at least one toy has magnitude >= 1).
    //     - If B+C == 0, product magnitude >= 1.
    //     - If B+C > 0, we can arrange multiplications to get magnitude >= 1.
    //       Example: (small * small) * ... * large. If we have at least one toy from A or D, and at least one from B or C.
    //       If A+D > 0 and B+C > 0, we can always make the magnitude >= 1.
    //       Consider a toy $x_L$ with $|x_L| \ge 1$ and a toy $x_S$ with $|x_S| < 1$.
    //       If we multiply $x_L$ by $x_S$, the result $x_L x_S$ can be made to have magnitude $\ge 1$ if we choose $x_L$ large enough.
    //       For example, if $x_L=100$, $x_S=0.5$, then $x_L x_S = 50$.
    //       So, if A+D > 0 and B+C > 0, we can achieve magnitude >= 1.
    //   - The only case where we cannot achieve magnitude >= 1 is if A+D == 0.
    if ((A + B) % 2 == 0) { // Final product can be positive
        if (A + D == 0) { // All initial toys have magnitude < 1
            // Product magnitude must be < 1. Cannot be in Box 4.
        } else { // At least one toy has magnitude >= 1.
            // If B+C == 0, product magnitude >= 1.
            // If B+C > 0, we can make product magnitude >= 1.
            ans4 = "Ya";
        }
    }

    // Box 2: (-1, 0) - Negative, magnitude < 1
    // Possible if final product is negative AND magnitude < 1.
    // Final product negative: (A+B) is odd.
    // Final product magnitude < 1:
    //   - If A+D == 0, product magnitude < 1.
    //   - If A+D > 0 and B+C > 0, we can make product magnitude < 1.
    //   - Cannot be magnitude < 1 if B+C == 0.
    if ((A + B) % 2 == 1) { // Final product can be negative
        if (B + C == 0) { // All initial toys have magnitude >= 1
            // Product magnitude must be >= 1. Cannot be in Box 2.
        } else { // At least one toy has magnitude < 1.
            // If A+D == 0, product magnitude < 1.
            // If A+D > 0, we can make product magnitude < 1.
            ans2 = "Ya";
        }
    }

    // Box 1: (-inf, -1] - Negative, magnitude >= 1
    // Possible if final product is negative AND magnitude >= 1.
    // Final product negative: (A+B) is odd.
    // Final product magnitude >= 1:
    //   - If A+D > 0.
    //     - If B+C == 0, product magnitude >= 1.
    //     - If B+C > 0, we can make product magnitude >= 1.
    //   - Cannot be magnitude >= 1 if A+D == 0.
    if ((A + B) % 2 == 1) { // Final product can be negative
        if (A + D == 0) { // All initial toys have magnitude < 1
            // Product magnitude must be < 1. Cannot be in Box 1.
        } else { // At least one toy has magnitude >= 1.
            // If B+C == 0, product magnitude >= 1.
            // If B+C > 0, we can make product magnitude >= 1.
            ans1 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

