void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if it's possible to form the strictly increasing left part
    // For a_1 < a_2 < ... < a_k, we need a_i >= i-1 for i=1..k
    // We can decrease elements, so we need to check if the current a_i is at least i-1.
    // If a_i < i-1, we cannot make it i-1 or greater.
    // The maximum possible length of the strictly increasing prefix is limited by this.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Check if it's possible to form the strictly decreasing right part
    // For a_k > a_{k+1} > ... > a_n, we need a_i >= n-i for i=k..n
    // (using 0-indexed array, so a_i >= (n-1)-i for i=k..n-1)
    // The maximum possible length of the strictly decreasing suffix is limited by this.
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1) - i) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of maximum possible left_len and right_len is greater than n,
    // it means there's an overlap, and we can find a peak k.
    // Specifically, if left_len + right_len > n, it means there's at least one index
    // that can be part of both the increasing prefix and the decreasing suffix.
    // This index can be chosen as the peak k.
    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

