    // First, ensure the median element itself is s.
    // This is a mandatory change.
    operations += std::abs(a[mid_idx] - s);

    // If the current median is less than s, we need to increase it.
    // All elements to its right (a[mid_idx+1]...a[n-1]) that are less than s
    // must also be increased to at least s to maintain the sorted order
    // and ensure s is the median.
    if (a[mid_idx] < s) {
        for (int i = mid_idx + 1; i < n; ++i) {
            if (a[i] < s) {
                operations += (s - a[i]);
