                // Since the array is sorted, if a[i] >= s, all subsequent elements are also >= s.
                // No further operations needed for elements to the right.
                break;
            }
        }
    }
    // If the current median is greater than s, we need to decrease it.
    // All elements to its left (a[0]...a[mid_idx-1]) that are greater than s
    // must also be decreased to at most s to maintain the sorted order
    // and ensure s is the median.
    else if (a[mid_idx] > s) {
        for (int i = mid_idx - 1; i >= 0; --i) {
            if (a[i] > s) {
