    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor ^= a[i];
    }

    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append at most 3 elements.
        // Let's try to append two elements.
        // The first element will be current_xor.
        // After appending current_xor:
        // New sum = current_sum + current_xor
        // New xor = current_xor ^ current_xor = 0
        // Now we need (current_sum + current_xor) = 2 * 0, which means current_sum + current_xor = 0.
        // This is generally not true since elements are non-negative.
        // So, we need to append a third element, say X.
        // Let's append current_xor first.
        // S_1 = current_sum + current_xor
        // X_1 = current_xor ^ current_xor = 0
        // Now we need to append one more element, say Y, such that:
        // S_1 + Y = 2 * (X_1 ^ Y)
        // (current_sum + current_xor) + Y = 2 * (0 ^ Y)
        // (current_sum + current_xor) + Y = 2 * Y
        // current_sum + current_xor = Y
        // So, the second element to append is current_sum + current_xor.

        // The two elements to append are:
        // b1 = current_xor
        // b2 = current_sum + current_xor

        // Let's verify this:
        // Initial: sum = current_sum, xor = current_xor
        // After appending b1 = current_xor:
        // sum' = current_sum + current_xor
        // xor' = current_xor ^ current_xor = 0
        // After appending b2 = current_sum + current_xor:
        // sum'' = sum' + b2 = (current_sum + current_xor) + (current_sum + current_xor) = 2 * (current_sum + current_xor)
        // xor'' = xor' ^ b2 = 0 ^ (current_sum + current_xor) = current_sum + current_xor
        // Check condition: sum'' == 2 * xor''
        // 2 * (current_sum + current_xor) == 2 * (current_sum + current_xor)
        // This is always true.

        std::cout << 2 << std::endl;
        std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
    }
}

