    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // can potentially interact with this 'b'.
            // Each 'a' to its left will eventually pass this 'b'.
            // When an 'a' passes a 'b', it effectively doubles the 'a_count'
            // for future 'b's to its left.
            // The number of steps added by this 'b' is the current 'a_count'.
            total_steps = (total_steps + a_count) % mod;
            // After this 'b' is processed, it effectively doubles the 'a_count'
            // for any 'a's further to the left.
            // This is because 'ab' -> 'bba'. The 'a' moves past the 'b',
            // and the 'b' effectively creates another 'a' (conceptually,
            // by doubling the 'a_count' for future 'b's).
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to interact with 'b's to their right.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

