// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // The problem statement implies padding with 0s from the left for shorter numbers.
    // This means the pattern should effectively be 18 characters long, padded with '0's.
    // Since we store patterns as they are, and query patterns are also given,
    // we need to ensure consistency.
    // The map key should be a fixed-length string for efficient lookup.
    // Let's pad to 18 characters.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern to 18 characters with '0's from the left
            // to match the fixed-length keys in the map.
            // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // And "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means both are effectively extended to max length (18) with '0's.
            // Our `to_parity_pattern` function generates a string from right to left, then pads to 18.
            // So, a query pattern like "010" should be treated as "00...0010" (18 chars).
            // The input pattern `s` is given from left to right.
            // Example: s = "010".
            // The 1st digit from right is 0, 2nd is 1, 3rd is 0.
            // Our `to_parity_pattern` for 92 (01) would be "01" (right to left).
            // So, we need to reverse the query pattern and then pad.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }

            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

