int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_total_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n - i' items are taken from the right
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // These are w[n-j]...w[n-1]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add extra energy for consecutive actions
        if (i > j) { // More items taken from left than right
            // The last 'i - j' items must have been taken from the left consecutively
            // (after all 'j' right items and 'j' left items were taken in alternation)
            // This means 'i - j - 1' extra Ql penalties
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items taken from right than left
            // The last 'j - i' items must have been taken from the right consecutively
            // This means 'j - i - 1' extra Qr penalties
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no extra penalties from this rule.

        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

