int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available divided by 3.
        // 2. The number of coders (each team needs at least one coder).
        // 3. The number of mathematicians (each team needs at least one mathematician).
        // So, the number of teams cannot exceed min( (c+m+x)/3, c, m ).
        // This is because if we form k teams, we need k coders, k mathematicians,
        // and a total of 3k students.
        // The minimum of c, m, and (c+m+x)/3 gives an upper bound.
        // We can always form min(c, m, (c+m+x)/3) teams.
        // Let's verify this.
        // Suppose we want to form k teams.
        // We need k coders and k mathematicians.
        // The remaining k students (3k total - k coders - k mathematicians)
        // can be filled by any remaining coders, mathematicians, or unspecialized students.
        // The total number of students available for these 'third' slots is (c-k) + (m-k) + x.
        // We need to ensure that (c-k) + (m-k) + x >= k.
        // This simplifies to c + m + x >= 3k.
        // So, k <= (c+m+x)/3.
        // Combining all conditions:
        // k <= c
        // k <= m
        // k <= (c+m+x)/3
        // Therefore, k <= min(c, m, (c+m+x)/3).
        // The maximum possible k is exactly this minimum.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

