void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    std::vector<int> ans(n);
    bool possible = false;

    for (int pivot_val = 0; pivot_val <= 9; ++pivot_val) {
        int last1 = -1; // Last digit placed in color 1
        int last2 = -1; // Last digit placed in color 2
        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot_val) {
                // Must be color 1
                if (d[i] < last1) {
                    current_possible = false;
                    break;
                }
                ans[i] = 1;
                last1 = d[i];
            } else if (d[i] > pivot_val) {
                // Must be color 2
                if (d[i] < last2) {
                    current_possible = false;
                    break;
                }
                ans[i] = 2;
                last2 = d[i];
            } else { // d[i] == pivot_val
                // Can be either color 1 or color 2
                // Prefer color 2 if it maintains non-decreasing property for S2
                // This ensures that if there are multiple pivot_val digits,
                // those that go to S2 are >= last2, and those that go to S1 are >= last1.
                // By putting them into S2 if possible, we keep S1 "smaller" for future digits.
                if (d[i] >= last2) { // Can place in S2
                    ans[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) { // Can place in S1
                    ans[i] = 1;
                    last1 = d[i];
                } else { // Cannot place in either
                    current_possible = false;
                    break;
                }
            }
        }

        if (current_possible) {
            possible = true;
            for (int i = 0; i < n; ++i) {
                std::cout << ans[i];
            }
            std::cout << "\n";
            break;
        }
    }

    if (!possible) {
        std::cout << "-\n";
    }
}

