void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 0 means cannot move left (x-1, y).
        // If it cannot move left, it must end up at a point X >= its current x.
        // So, X must be >= x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // f3 = 0 means cannot move right (x+1, y).
        // If it cannot move right, it must end up at a point X <= its current x.
        // So, X must be <= x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 0 means cannot move down (x, y-1).
        // If it cannot move down, it must end up at a point Y >= its current y.
        // So, Y must be >= y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // f2 = 0 means cannot move up (x, y+1).
        // If it cannot move up, it must end up at a point Y <= its current y.
        // So, Y must be <= y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
        // So we can pick any valid point, e.g., (min_x, min_y).
