#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the subarray is just [1].
        // For m > 1, we need to include m.
        // The number m is at pos[m].
        // To form a permutation of 1...m, the subarray must span from
        // the minimum index seen so far (current_min_idx) to the maximum index
        // seen so far (current_max_idx), after including m.
        // The length of this subarray must be exactly m.

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The length of the current segment [current_min_idx, current_max_idx]
        // is current_max_idx - current_min_idx + 1.
        // For m to be beautiful, this length must be equal to m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

