bool is_good(const std::vector<int>& b) {
    if (b.empty()) {
        return true;
    }
    int n = b.size();
    std::vector<int> p_min(n);
    std::vector<int> s_max(n);

    p_min[0] = b[0];
    for (int i = 1; i < n; ++i) {
        p_min[i] = std::min(p_min[i - 1], b[i]);
    }

    s_max[n - 1] = b[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        s_max[i] = std::max(s_max[i + 1], b[i]);
    }

    std::set<int> seen_elements;
    for (int i = 0; i < n; ++i) {
        if (seen_elements.count(b[i])) {
            return false; // Duplicate found
        }
        seen_elements.insert(b[i]);

        if (i + 1 < n) { // Check for elements to the right
            if (b[i] > p_min[i + 1]) {
                return false; // b[i] is greater than some element to its right
            }
        }
        if (i - 1 >= 0) { // Check for elements to the left
            if (b[i] < s_max[i - 1]) {
                return false; // b[i] is smaller than some element to its left
            }
        }
    }
    return true;
}

