            max_win_prob_for_first_char = std::max(max_win_prob_for_first_char, current_p_win_prob);
        }
        total_prob += max_win_prob_for_first_char / possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0; // Value if input is 0
    int current_val_1023 = 1023; // Value if input is 1023

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Determine the final operations
    // For each bit position i (0 to 9):
    // Let x_i be the i-th bit of the input.
    // Let f(x_i) be the i-th bit of the output.
    // We know f(0) = (current_val_0 >> i) & 1
    // We know f(1) = (current_val_1023 >> i) & 1

    // Case 1: f(0) = 0, f(1) = 0  =>  f(x_i) = 0 for all x_i. This means the bit is always 0.
    // Case 2: f(0) = 0, f(1) = 1  =>  f(x_i) = x_i for all x_i. This means the bit is unchanged.
    // Case 3: f(0) = 1, f(1) = 0  =>  f(x_i) = 1 - x_i for all x_i. This means the bit is flipped.
    // Case 4: f(0) = 1, f(1) = 1  =>  f(x_i) = 1 for all x_i. This means the bit is always 1.

    int and_mask = 1023; // Bits that are always 0 (Case 1) will be 0 in this mask.
                         // Bits that are unchanged (Case 2) will be 1.
                         // Bits that are flipped (Case 3) will be 1.
                         // Bits that are always 1 (Case 4) will be 1.
                         // So, this mask will have 0s for Case 1, and 1s for Cases 2, 3, 4.
                         // Effectively, it's a mask of bits that are NOT forced to 0.

    int or_mask = 0;     // Bits that are always 1 (Case 4) will be 1 in this mask.
                         // Bits that are unchanged (Case 2) will be 0.
                         // Bits that are flipped (Case 3) will be 0.
                         // Bits that are always 0 (Case 1) will be 0.
                         // Effectively, it's a mask of bits that are forced to 1.

    int xor_mask = 0;    // Bits that are flipped (Case 3) will be 1 in this mask.
                         // Bits that are unchanged (Case 2) will be 0.
                         // Bits that are always 0 (Case 1) will be 0.
                         // Bits that are always 1 (Case 4) will be 0.
                         // Effectively, it's a mask of bits that are flipped.

    for (int i = 0; i < 10; ++i) {
        int bit_0 = (current_val_0 >> i) & 1;
        int bit_1023 = (current_val_1023 >> i) & 1;

        if (bit_0 == 0 && bit_1023 == 0) { // Case 1: f(x_i) = 0
            and_mask &= ~(1 << i); // Force this bit to 0
        } else if (bit_0 == 0 && bit_1023 == 1) { // Case 2: f(x_i) = x_i
            // Bit is unchanged, and_mask already has 1, or_mask already has 0, xor_mask already has 0
        } else if (bit_0 == 1 && bit_1023 == 0) { // Case 3: f(x_i) = 1 - x_i
            xor_mask |= (1 << i); // Flip this bit
        } else { // bit_0 == 1 && bit_1023 == 1, Case 4: f(x_i) = 1
            or_mask |= (1 << i); // Force this bit to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (and_mask != 1023) { // If any bit is forced to 0
        result_ops.push_back({'&', and_mask});
    }
    if (or_mask != 0) { // If any bit is forced to 1
        result_ops.push_back({'|', or_mask});
    }
    if (xor_mask != 0) { // If any bit is flipped
        result_ops.push_back({'^', xor_mask});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;

    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent gets to play on N-1 (odd).
                // Opponent will take 1. Then Chanek plays on N-2.
                // Chanek gets 1 + (what Chanek gets from N-2)

                // Option 2: Take N/2 coins
                // Remaining N/2. Opponent gets to play on N/2.
                // Chanek gets N/2 + (what Chanek gets from N/2)

                // If N is a power of 2 (and N > 2), say N = 2^k.
                // Taking 1: Chanek gets 1. N becomes 2^k-1 (odd).
                // Opponent takes 1. N becomes 2^k-2 (even).
                // Chanek gets 1 + (result from 2^k-2)
                // Taking N/2: Chanek gets 2^(k-1). N becomes 2^(k-1).
                // Chanek gets 2^(k-1) + (result from 2^(k-1))

                // Consider N = 4:
                // Take 1: Chanek gets 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+1=2. Opponent: 1+1=2.
                // Take N/2 (2): Chanek gets 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // Chanek chooses to take N/2.

                // Consider N = 6:
                // Take 1: Chanek gets 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Take N/2 (3): Chanek gets 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Both moves lead to 4 for Chanek.

                // The strategy for Chanek when N is even:
                // If N is a power of 2 (and N > 2), taking N/2 is always better.
                // Example: N=4. Take 2. Remaining 2. Chanek gets 2 + (what Chanek gets from 2).
                // From 2, Chanek gets 1. Total 2+1=3.
                // If N=4, take 1. Remaining 3. Opponent takes 1. Remaining 2. Chanek gets 1 + (what Chanek gets from 2).
                // From 2, Chanek gets 1. Total 1+1=2.
                // So for N=4, Chanek takes 2.

                // If N is even but not a power of 2, it means N has an odd factor greater than 1.
                // Example: N=6.
                // Take 1: Chanek gets 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Take N/2 (3): Chanek gets 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // In this case, both moves yield 4 for Chanek.

                // The optimal strategy for Chanek when N is even:
                // If N is a power of 2 (N = 2^k, k >= 2), Chanek takes N/2.
                // Otherwise (N is even but not a power of 2), Chanek takes 1.
                // This is because if N is even and not a power of 2, N/2 will still be even or odd.
                // If N/2 is odd, opponent takes 1, leaving N/2-1 (even).
                // If N/2 is even, opponent can take N/4 or 1.
                // Taking 1 coin leaves N-1 (odd), forcing opponent to take 1.
                // This ensures that Chanek gets to play on an even number again (N-2).
                // This seems to be the general strategy.

                // Let's check if N is a power of 2.
                if ((n & (n - 1)) == 0 && n > 2) { // N is a power of 2 and N > 2
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2, or N=2
                    // For N=2, (n & (n-1)) == 0 is true, but n > 2 is false. So it falls here.
                    // If N=2, Chanek takes 1. N=1.
                    // If N=6, Chanek takes 1. N=5.
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                // Opponent also wants to maximize their coins.
                // Same logic as Chanek.
                if ((n & (n - 1)) == 0 && n > 2) { // N is a power of 2 and N > 2
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2, or N=2
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

