#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // s_L[k] = balance of jars 1 to k (1s - 2s)
    // We are interested in jars from n down to 1.
    // Let's define balance_L[k] as the balance of jars from index n-k+1 to n.
    // This is equivalent to processing jars from n-1 down to 0 (0-indexed).
    // Let's use 0-indexed arrays for convenience. Jars are a[0]...a[2n-1].
    // Karlsson is between a[n-1] and a[n].
    // Left jars: a[0]...a[n-1]. Right jars: a[n]...a[2n-1].

    // Calculate balances for suffixes of the left part (a[0]...a[n-1])
    // bal_L[k] = balance of jars a[n-k]...a[n-1]
    // k is the number of jars removed from the left (from n-1 down to n-k)
    // So, if k jars are removed, the remaining jars are a[0]...a[n-k-1].
    // The balance of these remaining jars is what we need.
    // Let's define `left_bal_map[balance]` = `k` (number of jars removed from left)
    // `k` is the number of jars from `a[n-k]` to `a[n-1]` that are removed.
    // The balance of these `k` removed jars is `current_bal_L`.
    // The balance of the *remaining* `n-k` jars is `total_initial_bal_L - current_bal_L`.
    // We need to store `k` for `total_initial_bal_L - current_bal_L`.

    // Let's re-evaluate.
    // We want to find min(i+j) such that balance(remaining_left) + balance(remaining_right) = 0.
    // Remaining left: a[0]...a[n-i-1]. Remaining right: a[n+j]...a[2n-1].
    // Let `bal_prefix_L[k]` be the balance of `a[0]...a[k-1]`.
    // Let `bal_suffix_R[k]` be the balance of `a[2n-k]...a[2n-1]`.
    // The balance of remaining left jars is `bal_prefix_L[n-i]`.
    // The balance of remaining right jars is `bal_suffix_R[2n-(n+j)] = bal_suffix_R[n-j]`.
    // No, this is not right. `bal_suffix_R[k]` is balance of `k` jars from the right end.
    // So, if `j` jars are removed from the right, `2n-j` jars remain.
    // The remaining jars are `a[n+j]...a[2n-1]`.
    // Let `bal_R_from_n_plus_j[k]` be the balance of `a[n+j]...a[2n-1]`.
    // This is `bal_R_from_n_plus_j[k]` where `k = (2n-1) - (n+j) + 1 = n-j`.
    // So we need `bal_prefix_L[n-i]` and `bal_suffix_R[n-j]`.
    // `bal_prefix_L[k]` is balance of `a[0]...a[k-1]`.
    // `bal_suffix_R[k]` is balance of `a[2n-k]...a[2n-1]`.

    // Let's define `bal_L[k]` as the balance of jars `a[0]...a[k-1]` (prefix of length k).
    // Let `bal_R[k]` as the balance of jars `a[2n-k]...a[2n-1]` (suffix of length k).
    // `bal_L[0] = 0`, `bal_R[0] = 0`.
    // `bal_L[k] = bal_L[k-1] + (a[k-1] == 1 ? 1 : -1)` for `k=1...n`.
    // `bal_R[k] = bal_R[k-1] + (a[2n-k] == 1 ? 1 : -1)` for `k=1...n`.

    // We remove `i` jars from the left (a[n-1], a[n-2], ..., a[n-i]).
    // The remaining left jars are `a[0]...a[n-i-1]`. Their balance is `bal_L[n-i]`.
    // We remove `j` jars from the right (a[n], a[n+1], ..., a[n+j-1]).
    // The remaining right jars are `a[n+j]...a[2n-1]`. Their balance is `bal_R[n-j]`.
    // We need `bal_L[n-i] + bal_R[n-j] = 0`.
    // This means `bal_L[n-i] = -bal_R[n-j]`.

    // Let's compute `bal_L_vals[k]` = balance of `a[0]...a[k-1]` for `k=0...n`.
    // Let's compute `bal_R_vals[k]` = balance of `a[2n-k]...a[2n-1]` for `k=0...n`.
    std::vector<int> bal_L_vals(n + 1);
    std::vector<int> bal_R_vals(n + 1);

    bal_L_vals[0] = 0;
    for (int k = 0; k < n; ++k) {
        bal_L_vals[k + 1] = bal_L_vals[k] + (a[k] == 1 ? 1 : -1);
    }

    bal_R_vals[0] = 0;
    for (int k = 0; k < n; ++k) {
        bal_R_vals[k + 1] = bal_R_vals[k] + (a[2 * n - 1 - k] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left (i)
    // to achieve a certain balance for the remaining left jars.
    // `left_remaining_bal_to_i[balance]` = `i`
    std::map<int, int> left_remaining_bal_to_i;
    for (int i = 0; i <= n; ++i) { // i is number of jars removed from left (0 to n)
        // Remaining left jars are a[0]...a[n-i-1]. Their balance is bal_L_vals[n-i].
        int current_remaining_bal = bal_L_vals[n - i];
        if (left_remaining_bal_to_i.find(current_remaining_bal) == left_remaining_bal_to_i.end()) {
            left_remaining_bal_to_i[current_remaining_bal] = i;
        }
    }

    int min_total_removed = 2 * n; // Max possible is 2n

    // Iterate through possible number of jars removed from the right (j)
    for (int j = 0; j <= n; ++j) {
        // Remaining right jars are a[n+j]...a[2n-1]. Their balance is bal_R_vals[n-j].
        int current_remaining_bal_R = bal_R_vals[n - j];
        int target_remaining_bal_L = -current_remaining_bal_R;

        if (left_remaining_bal_to_i.count(target_remaining_bal_L)) {
            int i = left_remaining_bal_to_i[target_remaining_bal_L];
            min_total_removed = std::min(min_total_removed, i + j);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The smallest possible value for a_1' is 0.
                            // For a_i', it must be >= a_{i-1}'.
                            // We want to make a_i' as small as possible to allow more room for a_{i+1}'.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long lower_bound_for_current_a_prime = prev_val;

        // Case 1: a_i' = a_i + c_i, where 0 <= c_i <= x.
        // This means a_i' is in range [a_i, (a_i + x) % m] if (a_i + x) % m >= a_i,
        // or [a_i, m-1] U [0, (a_i + x) % m] if (a_i + x) % m < a_i.
        // Effectively, a_i' can be any value in [a_i, (a_i + x)] (modulo m).

        // We need a_i' >= lower_bound_for_current_a_prime.
        // If current_a >= lower_bound_for_current_a_prime, then we can potentially set a_i' = current_a.
        // This requires 0 operations on a_i.
        // The maximum value a_i can take with x operations is (current_a + x) % m.
        // If current_a >= lower_bound_for_current_a_prime, we can just use current_a as a_i'.
        // This is the smallest possible value for a_i' that satisfies a_i' >= lower_bound_for_current_a_prime
        // and requires 0 operations.
        // So, we set prev_val = current_a.

        // However, if current_a < lower_bound_for_current_a_prime, we must increment current_a.
        // We need to increment current_a by at least (lower_bound_for_current_a_prime - current_a).
        // Let diff = lower_bound_for_current_a_prime - current_a.
        // If diff <= x, then we can achieve a_i' = lower_bound_for_current_a_prime by incrementing current_a by diff.
        // This is valid. So, we set prev_val = lower_bound_for_current_a_prime.

        // What if current_a + x wraps around m?
        // The values reachable from current_a with at most x operations are:
        // [current_a, current_a + x] (if current_a + x < m)
        // [current_a, m-1] U [0, (current_a + x) % m] (if current_a + x >= m)

        // We need to find the smallest a_i' >= lower_bound_for_current_a_prime such that a_i' is reachable.
        // If current_a >= lower_bound_for_current_a_prime:
        //   We can choose a_i' = current_a. This requires 0 operations.
        //   This is valid as long as 0 <= x.
        //   So, we set prev_val = current_a.
        // Else (current_a < lower_bound_for_current_a_prime):
        //   We must increment current_a.
        //   The target value for a_i' must be at least lower_bound_for_current_a_prime.
        //   Can we reach lower_bound_for_current_a_prime from current_a with at most x operations?
        //   This means (current_a + c_i) % m = lower_bound_for_current_a_prime for some c_i <= x.
        //   If current_a + x < m:
        //     Then the reachable values are [current_a, current_a + x].
        //     If lower_bound_for_current_a_prime is in this range, we can use it.
        //     But we are in the case current_a < lower_bound_for_current_a_prime.
        //     So we need current_a + x >= lower_bound_for_current_a_prime.
        //     If this holds, we can set a_i' = lower_bound_for_current_a_prime.
        //     Else, it's impossible.
        //   If current_a + x >= m (wraps around):
        //     The reachable values are [current_a, m-1] U [0, (current_a + x) % m].
        //     If lower_bound_for_current_a_prime is in [current_a, m-1], this is impossible because current_a < lower_bound_for_current_a_prime.
        //     So lower_bound_for_current_a_prime must be in [0, (current_a + x) % m].
        //     If this holds, we can set a_i' = lower_bound_for_current_a_prime.
        //     Else, it's impossible.

        // Let's simplify.
        // We need to find a_i' such that:
        // 1. a_i' >= prev_val
        // 2. a_i' can be obtained from a[i] by adding c_i, where 0 <= c_i <= x.
        //    This means a_i' is in the set { (a[i] + c) % m | 0 <= c <= x }.

        // Consider the value `a[i]`.
        // If `a[i]` itself is greater than or equal to `prev_val`, we can potentially use `a[i]` as `a_i'`.
        // This requires 0 operations on `a[i]`. Since `0 <= x`, this is always allowed.
        // So, if `a[i] >= prev_val`, we can set `a_i' = a[i]`.
        // We then update `prev_val = a[i]` for the next iteration.

        // If `a[i] < prev_val`, we *must* increment `a[i]`.
        // We need to reach at least `prev_val`.
        // The number of increments needed to reach `prev_val` from `a[i]` is `(prev_val - a[i])`.
        // If `(prev_val - a[i]) <= x`, then we can achieve `a_i' = prev_val` by incrementing `a[i]` by `(prev_val - a[i])`.
        // This is valid. So, we set `prev_val = prev_val`. (It doesn't change).
        //
        // What if `(prev_val - a[i]) > x`?
        // This means we cannot reach `prev_val` by simply incrementing `a[i]` without wrapping around `m`.
        // For example, if `a[i]=0, prev_val=5, x=2, m=10`. We need to reach 5.
        // `0+0=0, 0+1=1, 0+2=2`. Max reachable is 2. We cannot reach 5.
        //
        // However, there's another way to reach `prev_val` if `a[i]` is small and `prev_val` is large,
        // but `a[i]` can wrap around `m` and then reach `prev_val`.
        // Example: `a[i]=6, prev_val=0, x=1, m=7`.
        // `a[i] >= prev_val` is true. We set `prev_val = 6`.
        //
        // Example: `a[i]=0, prev_val=6, x=1, m=7`.
        // `a[i] < prev_val`.
        // `(prev_val - a[i]) = 6`. `x = 1`. `6 > 1`.
        // So we cannot reach `prev_val` by `a[i] + c_i`.
        // But we can reach `(a[i] + x) % m = (0 + 1) % 7 = 1`.
        // The values reachable are `[0, 1]`.
        // `prev_val = 6` is not in `[0, 1]`. So this is impossible.
        //
        // The condition for `a_i'` to be reachable from `a[i]` with at most `x` operations and `a_i' >= prev_val` is:
        //
        // If `a[i] >= prev_val`:
        //   We can choose `a_i' = a[i]`. This requires 0 operations.
        //   This is always valid if `0 <= x`.
        //   So, `prev_val` remains `a[i]`.
        // Else (`a[i] < prev_val`):
        //   We must increment `a[i]`.
        //   The target `a_i'` must be at least `prev_val`.
        //   The values `a[i]` can become are `(a[i] + c) % m` for `0 <= c <= x`.
        //   If we increment `a[i]` to `prev_val`, the number of operations needed is `(m - a[i] + prev_val) % m`.
        //   Let `needed_ops = (m - a[i] + prev_val) % m`.
        //   If `needed_ops <= x`, then we can achieve `a_i' = prev_val`.
        //   So, `prev_val` remains `prev_val`.
        //   If `needed_ops > x`, it means we cannot reach `prev_val` from `a[i]` even by wrapping around `m` and using `x` operations.
        //   In this case, it's impossible to satisfy the condition for this `x`. Return `false`.

        if (current_a >= lower_bound_for_current_a_prime) {
            // We can potentially use current_a as a_i'.
            // This requires 0 operations.
            // The maximum value current_a can become is (current_a + x) % m.
            // If (current_a + x) % m < current_a, it means it wrapped around.
            // The reachable values are [current_a, m-1] U [0, (current_a + x) % m].
            // If lower_bound_for_current_a_prime is in [0, (current_a + x) % m],
            // and current_a is not in [lower_bound_for_current_a_prime, (current_a + x) % m] (which is true if current_a < lower_bound_for_current_a_prime),
            // then we can use lower_bound_for_current_a_prime.
            //
            // Let's re-evaluate.
            // We need to find a value `val` such that `val >= prev_val` and `val` is reachable from `a[i]` with at most `x` operations.
            // We want to pick the smallest such `val` to make it easier for subsequent elements.
            //
            // Option 1: `a[i]` itself is `val`. This requires 0 operations.
            // If `a[i] >= prev_val`, then we can set `a_i' = a[i]`. This is the smallest possible `a_i'` that satisfies `a_i' >= prev_val` and `c_i=0`.
            // So, if `a[i] >= prev_val`, we set `prev_val = a[i]`.
            //
            // Option 2: `a[i]` needs to be incremented.
            // This happens if `a[i] < prev_val`.
            // We need to find `c_i` such that `0 < c_i <= x` and `(a[i] + c_i) % m >= prev_val`.
            // The smallest such `(a[i] + c_i) % m` would be `prev_val`.
            // To reach `prev_val` from `a[i]`, we need `c_i = (prev_val - a[i] + m) % m` operations.
            // If `c_i <= x`, then we can set `a_i' = prev_val`.
            // So, if `a[i] < prev_val` AND `(prev_val - a[i] + m) % m <= x`, we set `prev_val = prev_val`.
            //
            // If neither of these conditions is met, it means we cannot make `a_i'` satisfy `a_i' >= prev_val` with at most `x` operations.
            // This happens if `a[i] < prev_val` AND `(prev_val - a[i] + m) % m > x`.
            // In this case, `x` is too small. Return `false`.

            // Simplified logic:
            // If a[i] >= prev_val:
            //   We can use a[i] as a_i'. This requires 0 operations.
            //   However, we also have the option to increment a[i] to some value (a[i]+c)%m.
            //   If (a[i] + x) % m < a[i], it means we can reach values from a[i] up to m-1, and from 0 up to (a[i]+x)%m.
            //   If prev_val is in [0, (a[i]+x)%m], then we can potentially use prev_val as a_i'.
            //   This would be better than using a[i] if prev_val < a[i].
            //   But we are in the case a[i] >= prev_val.
            //   So, if a[i] >= prev_val, we can always use a[i] as a_i'.
            //   But if (a[i] + x) % m < a[i] (meaning wrap-around occurred) AND prev_val is in [0, (a[i]+x)%m],
            //   then we can choose a_i' = prev_val. This is better.
            //   So, if a[i] >= prev_val:
            //     If (a[i] + x) % m < a[i] (wrap-around) AND prev_val <= (a[i] + x) % m:
            //       We can choose a_i' = prev_val.
            //     Else:
            //       We must choose a_i' = a[i].
            //   This is equivalent to:
            //   If a[i] >= prev_val:
            //     If (a[i] + x) % m < a[i] (wrap-around) AND prev_val <= (a[i] + x) % m:
            //       // We can make a_i' = prev_val. This is the smallest possible.
            //       // prev_val remains prev_val.
            //       continue;
            //     Else:
            //       // We must make a_i' = a[i].
            //       prev_val = a[i];
            //   Else (a[i] < prev_val):
            //     If (a[i] + x) % m >= prev_val:
            //       // We can make a_i' = prev_val.
            //       // prev_val remains prev_val.
            //       continue;
            //     Else:
            //       // Cannot make a_i' >= prev_val.
            //       return false;

            // Let's try this logic:
            // If a[i] >= prev_val:
            //   We can potentially use a[i] as a_i'. This requires 0 operations.
            //   However, if (a[i] + x) % m < a[i] (meaning a[i] + x wraps around m),
            //   and prev_val is in the range [0, (a[i] + x) % m],
            //   then we can choose a_i' = prev_val. This is better because it's smaller.
            //   So, if (a[i] + x) % m < a[i] AND prev_val <= (a[i] + x) % m:
            //     // prev_val remains prev_val.
            //     continue;
            //   Else:
            //     // We must use a[i] as a_i'.
            //     prev_val = a[i];
            // Else (a[i] < prev_val):
            //   We must increment a[i].
            //   We need to check if we can reach prev_val.
            //   This means (a[i] + c) % m = prev_val for some c <= x.
            //   The number of operations needed to reach prev_val from a[i] is `(m - a[i] + prev_val) % m`.
            //   If `(m - a[i] + prev_val) % m <= x`:
            //     // We can reach prev_val.
            //     // prev_val remains prev_val.
            //     continue;
            //   Else:
            //     // Cannot reach prev_val.
            //     return false;

            // This logic seems correct and covers all cases.
            // Let's test with examples.
            // N=5, M=7, A=[0, 6, 1, 3, 2]
            // Try x=0:
            // i=0, a[0]=0. prev_val=0. a[0] >= prev_val. (0+0)%7=0. 0 < 0 is false. prev_val = 0.
            // i=1, a[1]=6. prev_val=0. a[1] >= prev_val. (6+0)%7=6. 6 < 6 is false. prev_val = 6.
            // i=2, a[2]=1. prev_val=6. a[2] < prev_val. (7-1+6)%7 = 12%7 = 5. 5 > 0. False.
            // So x=0 fails.

            // Try x=1:
            // i=0, a[0]=0. prev_val=0. a[0] >= prev_val. (0+1)%7=1. 1 < 0 is false. prev_val = 0.
            // i=1, a[1]=6. prev_val=0. a[1] >= prev_val. (6+1)%7=0. 0 < 6 is true. prev_val=0.
            //   (a[1]+x)%m = 0. prev_val=0. Is prev_val <= (a[1]+x)%m? 0 <= 0. Yes.
            //   So prev_val remains 0.
            // i=2, a[2]=1. prev_val=0. a[2] >= prev_val. (1+1)%7=2. 2 < 1 is false. prev_val = 1.
            // i=3, a[3]=3. prev_val=1. a[3] >= prev_val. (3+1)%7=4. 4 < 3 is false. prev_val = 3.
            // i=4, a[4]=2. prev_val=3. a[4] < prev_val. (7-2+3)%7 = 8%7 = 1. 1 <= x (1). Yes.
            //   So prev_val remains 3.
            // All elements processed. x=1 works.

            // This logic seems correct.

            if (current_a >= lower_bound_for_current_a_prime) {
                // current_a can be used as a_i' (0 operations).
                // Check if we can use lower_bound_for_current_a_prime instead (by incrementing current_a and wrapping around).
                // This happens if (current_a + x) % m < current_a (meaning wrap-around occurred)
                // AND lower_bound_for_current_a_prime is reachable in the wrapped-around part [0, (current_a + x) % m].
                if ((current_a + x) % m < current_a && lower_bound_for_current_a_prime <= (current_a + x) % m) {
                    // We can achieve lower_bound_for_current_a_prime. Keep it.
                } else {
                    // We must use current_a.
                    prev_val = current_a;
                }
            } else { // current_a < lower_bound_for_current_a_prime
                // We must increment current_a.
                // Check if lower_bound_for_current_a_prime is reachable from current_a with at most x operations.
                // This means (current_a + c) % m = lower_bound_for_current_a_prime for some c <= x.
                // The number of operations needed is `(m - current_a + lower_bound_for_current_a_prime) % m`.
                long long needed_ops = (m - current_a + lower_bound_for_current_a_prime) % m;
                if (needed_ops > x) {
                    return false; // Cannot reach lower_bound_for_current_a_prime.
                }
                // If we can reach it, prev_val remains lower_bound_for_current_a_prime.
            }
        }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations is m-1 (e.g., change 0 to m-1).
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x will always be an index, so int is fine for x.

// Memoization tables
// dp_x[i] stores the final x value if starting at index i
// dp_y[i] stores the final y value (additional y accumulated) if starting at index i
// visited[i] is used to detect cycles and mark states as being processed
std::vector<int> dp_x;
std::vector<long long> dp_y;
std::vector<bool> visited; // true if currently in recursion stack for this i, used for cycle detection

int N;
std::vector<long long> A_values; // a_1 is not used directly, a_2 to a_N are stored at indices 1 to N-1

// Recursive function to calculate final (x, y) starting from a given index `start_x`
// `current_a1` is the value of a[1] for the current run.
// This function returns the final y value.
long long solve(int start_x, long long current_a1) {
    // Base cases for termination
    if (start_x <= 0 || start_x > N) {
        return 0; // No additional y accumulated if already out of bounds
    }

    // Check memoization table
    if (dp_x[start_x] != 0) { // dp_x[start_x] == 0 means not computed yet or it's a special case (like 0 for x_final)
                              // We use 0 as a sentinel for 'not computed'.
                              // If a valid path ends at x=0, dp_x[start_x] would be 0.
                              // To distinguish, we can use a special value like -2 for 'not computed'
                              // or check visited array first.
        if (dp_x[start_x] == -1) { // -1 indicates a cycle or non-terminating path
            return -1;
        }
        return dp_y[start_x];
    }

    // Cycle detection
    if (visited[start_x]) {
        // Found a cycle, this path does not terminate
        dp_x[start_x] = -1; // Mark as non-terminating
        dp_y[start_x] = -1;
        return -1;
    }

    visited[start_x] = true; // Mark as currently being processed

    long long val_at_start_x;
    if (start_x == 1) {
        val_at_start_x = current_a1;
    } else {
        val_at_start_x = A_values[start_x - 1]; // A_values stores a_2 at index 1, a_3 at index 2, etc.
                                                 // So a_k is at A_values[k-1]
    }

    // Step 2: x_new = start_x + val_at_start_x, y_new = val_at_start_x
    int x_after_step2 = start_x + val_at_start_x;
    long long y_accumulated_step2 = val_at_start_x;

    // Check termination after step 2
    if (x_after_step2 <= 0 || x_after_step2 > N) {
        visited[start_x] = false; // Unmark before returning
        dp_x[start_x] = x_after_step2;
        dp_y[start_x] = y_accumulated_step2;
        return y_accumulated_step2;
    }

    long long val_at_x_after_step2;
    if (x_after_step2 == 1) {
        val_at_x_after_step2 = current_a1;
    } else {
        val_at_x_after_step2 = A_values[x_after_step2 - 1];
    }

    // Step 3: x_final = x_after_step2 - val_at_x_after_step2, y_final = y_accumulated_step2 + val_at_x_after_step2
    int next_start_x = x_after_step2 - val_at_x_after_step2;
    long long y_accumulated_step3 = y_accumulated_step2 + val_at_x_after_step2;

    // Recursively call for the next state
    long long result_from_next_state = solve(next_start_x, current_a1);

    visited[start_x] = false; // Unmark after processing

    if (result_from_next_state == -1) {
        dp_x[start_x] = -1; // Mark as non-terminating
        dp_y[start_x] = -1;
        return -1;
    } else {
        dp_x[start_x] = next_start_x; // This is not strictly correct, it should be the final x.
                                      // But we only care about y, and dp_x[start_x] != 0 is enough to indicate computed.
                                      // For correctness, dp_x[start_x] should store the final x value.
                                      // Let's adjust: dp_x[start_x] stores the final x, dp_y[start_x] stores the final y.
                                      // The final y is y_accumulated_step3 + result_from_next_state.
        dp_y[start_x] = y_accumulated_step3 + result_from_next_state;
        return dp_y[start_x];
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A_values.resize(N); // a_2 to a_N, stored at indices 1 to N-1. A_values[0] is unused.
    for (int i = 1; i < N; ++i) {
        std::cin >> A_values[i];
    }

    // For each i from 1 to N-1, we set a[1] = i and run the program.
    for (int i = 1; i < N; ++i) {
        // Reset memoization tables for each new a[1]
        dp_x.assign(N + 1, 0); // 0 means not computed
        dp_y.assign(N + 1, 0);
        visited.assign(N + 1, false);

        // The program starts with x=1, y=0.
        // The solve function calculates the total y accumulated from a given start_x.
        // So, for the initial state (x=1, y=0), the total y is just what solve(1, i) returns.
        long long result = solve(1, i);
        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a(n); // The initial array we are trying to find
    std::vector<long long> min_val_at_idx(n, LLONG_MAX); // min_val_at_idx[j] = m_i - current_delta_j_i for type 2 ops

    // Initialize min_val_at_idx based on type 2 operations
    // For each type 2 operation (l, r, m), we know that for any j in [l, r],
    // a[j] + current_delta_j_i <= m.
    // So, a[j] <= m - current_delta_j_i.
    // We want to find the tightest upper bound for a[j].
    // This means a[j] <= min(m_i - current_delta_j_i) over all relevant type 2 ops.

    std::vector<long long> current_delta(n, 0); // current_delta[j] = sum of d's applied to a[j] so far
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_at_idx[j] = std::min(min_val_at_idx[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If an index j was never part of a type 2 query, its min_val_at_idx[j] is LLONG_MAX.
    // We can set a[j] to 0 in such cases, as it won't affect any max query.
    // For indices that were part of type 2 queries, we set a[j] to the tightest upper bound.
    for (int j = 0; j < n; ++j) {
        if (min_val_at_idx[j] == LLONG_MAX) {
            a[j] = 0;
        } else {
            a[j] = min_val_at_idx[j];
        }
    }

    // Verify the solution
    std::vector<long long> b = a; // b will store the current state of the array during verification
    current_delta.assign(n, 0); // Reset current_delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] += ops[i].val;
                current_delta[j] += ops[i].val; // Keep track of delta for type 2 checks
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, b[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
            // Additional check: for any j in [l, r], a[j] + current_delta[j] must be <= m_i.
            // Since we set a[j] = m_i - current_delta[j] for the tightest bound,
            // this means a[j] + current_delta[j] = m_i.
            // If max_val == m_i, then there must be at least one j_0 in [l, r] such that
            // a[j_0] + current_delta[j_0] = m_i.
            // Our construction ensures this by setting a[j_0] = m_i - current_delta[j_0] for such j_0.
            // For other j in [l, r], a[j] + current_delta[j] <= m_i is also guaranteed by construction.
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If ones_a is odd, we can append '1'. This increases ones_a by 1.
    // If ones_a is even, we can append '0'. This keeps ones_a the same.
    // So, if ones_a is odd, it can become even.
    // If ones_a is even, it stays even.
    // This means the maximum number of ones we can achieve is ones_a if ones_a is even,
    // or ones_a + 1 if ones_a is odd.
    // In other words, the maximum number of ones we can achieve is ones_a + (ones_a % 2).
    // Let's call this max_ones_a_reachable.

    int max_ones_a_reachable = ones_a + (ones_a % 2);

    // To transform a into b, b must be a suffix of some string generated from a.
    // This implies that the length of b must be less than or equal to the length of a
    // after some number of append operations.
    // The minimum length of a string we can generate that could potentially contain b as a suffix
    // is |b|.
    // The maximum number of '1's in b must be less than or equal to the maximum number of '1's
    // we can generate in a string of length at least |b|.

    if (ones_b <= max_ones_a_reachable && a.length() >= b.length()) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    for (size_t i = 0; i + 1 < s.length(); ++i) {
        adj[s[i] - 'a'].insert(s[i+1]);
        adj[s[i+1] - 'a'].insert(s[i]);
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting point for a chain
    // A starting point is a character that has exactly one neighbor
    // or any character if all characters have 0 or 2 neighbors (e.g., a cycle or single character)
    int start_char_idx = -1;
    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() == 1) {
            start_char_idx = i;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars have 0 or 2 neighbors.
    // If there are chars with 2 neighbors, it implies a cycle or multiple disjoint chains/cycles.
    // We need to pick one such character to start building a chain.
    // If all chars have 0 neighbors, start_char_idx remains -1.
    if (start_char_idx == -1) {
        for (int i = 0; i < 26; ++i) {
            if (adj[i].size() == 0 && s.find((char)('a' + i)) != std::string::npos) {
                // This character is in the password but has no adjacencies.
                // This happens if the password is a single character.
                // We can start with it.
                start_char_idx = i;
                break;
            } else if (adj[i].size() == 2) {
                // This character is part of a cycle or a chain that has been fully defined.
                // We can start with it.
                start_char_idx = i;
                break;
            }
        }
    }

    // If start_char_idx is still -1, it means the password was empty or only contained characters
    // that were not part of any adjacency (e.g., "a" where 'a' has no neighbors).
    // In this problem, |s| >= 1, so there's always at least one character.
    // If s="a", adj['a'] is empty, start_char_idx will be 'a'-'a' = 0.

    if (start_char_idx != -1) {
        int current_char_idx = start_char_idx;
        int prev_char_idx = -1; // Sentinel for the first character in the chain

        while (current_char_idx != -1 && !visited[current_char_idx]) {
            visited[current_char_idx] = true;
            layout += (char)('a' + current_char_idx);

            int next_char_idx = -1;
            for (char neighbor_char : adj[current_char_idx]) {
                int neighbor_idx = neighbor_char - 'a';
                if (neighbor_idx != prev_char_idx) {
                    next_char_idx = neighbor_idx;
                    break;
                }
            }
            prev_char_idx = current_char_idx;
            current_char_idx = next_char_idx;
        }
    }

    // Check if all characters from the password have been included in the layout
    std::set<char> password_chars;
    for (char c : s) {
        password_chars.insert(c);
    }
    for (char c : password_chars) {
        if (layout.find(c) == std::string::npos) {
            // This means there's a disjoint chain/cycle not connected to the one we built.
            // This is impossible for a single linear keyboard.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unvisited characters
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    if (layout.length() != 26) {
        // This should not happen if the logic is correct, but as a safeguard.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of k from 1 to a: a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = (sum_k * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The sum is sum_{k=1 to a} sum_{r=1 to b-1} (k*b*r + r)
    // = sum_{k=1 to a} sum_{r=1 to b-1} (k*b*r) + sum_{k=1 to a} sum_{r=1 to b-1} (r)
    // = (sum_{k=1 to a} k) * (sum_{r=1 to b-1} r) * b + (sum_{k=1 to a} 1) * (sum_{r=1 to b-1} r)
    // = sum_k * sum_r * b + a * sum_r
    // = sum_r * (sum_k * b + a)

    long long term1 = (sum_k * (b % MOD)) % MOD;
    long long term2 = a % MOD;
    long long inner_sum = (term1 + term2) % MOD;

    long long total_sum = (sum_r * inner_sum) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for minimizing goodness in this case is to put a[0] in one subsequence
    // and a[1]...a[n-1] in the other, or a[n-1] in one and a[0]...a[n-2] in the other.
    // Or, more generally, put a[0] and a[n-1] in different subsequences.
    //
    // Let's consider a partition where a[0] is in subsequence 1 and a[1]...a[n-1] are in subsequence 2.
    // min_f:
    //   - a[i] + a[j] (same subsequence): min is a[1].value + a[2].value (if n >= 3)
    //   - a[i] + a[j] + h (different subsequences): min is a[0].value + a[1].value + h
    // So, min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h) if n >= 3.
    // If n=2, only a[0]+a[1]+h is possible.
    //
    // max_f:
    //   - a[i] + a[j] (same subsequence): max is a[n-2].value + a[n-1].value
    //   - a[i] + a[j] + h (different subsequences): max is a[0].value + a[n-1].value + h
    // So, max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)

    // Let's analyze the specific partition: a[0] in group 1, a[1]...a[n-1] in group 2.
    // This is one of the "boundary" partitions.
    // The values of f are:
    // 1. a[0] + a[i] + h for i = 1...n-1
    // 2. a[i] + a[j] for i,j = 1...n-1, i!=j (if n >= 3)
    //
    // min_f_val:
    //   - From type 1: a[0].value + a[1].value + h
    //   - From type 2: a[1].value + a[2].value (if n >= 3)
    // So, min_f_val = (n == 2) ? (a[0].value + a[1].value + h) : std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    //
    // max_f_val:
    //   - From type 1: a[0].value + a[n-1].value + h
    //   - From type 2: a[n-2].value + a[n-1].value (if n >= 3)
    // So, max_f_val = (n == 2) ? (a[0].value + a[1].value + h) : std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);

    // The key insight is that the minimum possible value of f is either a[0]+a[1] or a[0]+a[1]+h.
    // The maximum possible value of f is either a[n-2]+a[n-1] or a[n-2]+a[n-1]+h or a[0]+a[n-1]+h.
    //
    // Consider the partition where a[0] is in group 1, and a[1], ..., a[n-1] are in group 2.
    // Let's call this partition P_0.
    // Values of f:
    //   - a[0] + a[i] + h for i = 1, ..., n-1
    //   - a[i] + a[j] for 1 <= i < j <= n-1 (if n >= 3)
    //
    // min_f_P0:
    //   - a[0].value + a[1].value + h
    //   - If n >= 3: a[1].value + a[2].value
    //   So, min_f_P0 = (n == 2) ? (a[0].value + a[1].value + h) : std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    //
    // max_f_P0:
    //   - a[0].value + a[n-1].value + h
    //   - If n >= 3: a[n-2].value + a[n-1].value
    //   So, max_f_P0 = (n == 2) ? (a[0].value + a[1].value + h) : std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    //
    // goodness_P0 = max_f_P0 - min_f_P0;

    // The problem states that the minimum goodness is achieved by one of two types of partitions:
    // 1. All elements in one subsequence. (Already handled as goodness1)
    // 2. a[0] in one subsequence, and a[1], ..., a[n-1] in the other.
    //    This is because to minimize max_f - min_f, we want to make the range of values as small as possible.
    //    The smallest sum is a[0]+a[1]. The largest sum is a[n-2]+a[n-1].
    //    If we put a[0] and a[1] in different groups, then a[0]+a[1]+h is a value.
    //    If we put a[0] and a[n-1] in different groups, then a[0]+a[n-1]+h is a value.
    //    If we put a[n-2] and a[n-1] in different groups, then a[n-2]+a[n-1]+h is a value.
    //
    // The critical observation is that the minimum possible value of f is either a[0]+a[1] or a[0]+a[1]+h.
    // The maximum possible value of f is either a[n-2]+a[n-1] or a[n-2]+a[n-1]+h or a[0]+a[n-1]+h.
    //
    // Consider the partition where a[0] is in group 1, and a[1], ..., a[n-1] are in group 2.
    // The values of f are:
    //   - a[0] + a[i] + h for i = 1, ..., n-1
    //   - a[i] + a[j] for 1 <= i < j <= n-1 (if n >= 3)
    //
    // The minimum value of f in this partition is:
    //   min_f_val = (n == 2) ? (a[0].value + a[1].value + h) : std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    // The maximum value of f in this partition is:
    //   max_f_val = (n == 2) ? (a[0].value + a[1].value + h) : std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    //
    // The goodness for this partition is max_f_val - min_f_val.
    // Let's call this goodness2.

    long long min_f_val_P0;
    if (n == 2) {
        min_f_val_P0 = a[0].value + a[1].value + h;
    } else {
        min_f_val_P0 = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    }

    long long max_f_val_P0;
    if (n == 2) {
        max_f_val_P0 = a[0].value + a[1].value + h;
    } else {
        max_f_val_P0 = std::max(a[0].value + a[n - 1].value + h, a[n - 2].value + a[n - 1].value);
    }
    long long goodness2 = max_f_val_P0 - min_f_val_P0;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...n-1].
    // The new string is s[i...n-1] + s[0...i-1].
    // We need this new string to be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the cut point, s[i] is the start of the second piece
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string new_s = s_suffix + s_prefix;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // For k=2, we make two cuts, resulting in 3 pieces: A, B, C.
    // s = A + B + C.
    // We can reorder them. The problem statement implies we can reorder any way.
    // However, the example "nolon" -> "onlno" uses A=no, B=l, C=on, reordered to C+B+A.
    // This is equivalent to reversing the order of pieces.
    // If we cut s into A, B, C, then C+B+A is a candidate.
    // If s is a palindrome, and we cut it into A, B, C, then A_rev, B_rev, C_rev are also pieces.
    // If s is a palindrome, then s[0...i-1] is the reverse of s[n-i...n-1].
    // Consider s = A + B + C.
    // If s is a palindrome, then A is the reverse of C_rev, B is the reverse of B_rev, C is the reverse of A_rev.
    // More simply, if s is a palindrome, then s[0...i-1] is the reverse of s[n-i...n-1].
    // If we cut s into s[0...i-1] and s[i...n-1], and s[i...n-1] is a palindrome,
    // then s[0...i-1] + s[i...n-1] is a palindrome.
    // If s is a palindrome, and all characters are the same (e.g., "aaaaa"),
    // then any reordering of pieces will result in the same string "aaaaa".
    // In this case, it's impossible to get a different string.
    // We can check this by seeing if all characters in s are the same.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Why?
    // If s is a palindrome and not all characters are the same, then s must have at least two distinct characters.
    // If n is odd, the middle character is unique.
    // Example: "nolon". n=5. s[0]='n', s[1]='o', s[2]='l'.
    // Cut into "no", "l", "on". Reorder to "on", "l", "no". This is "onlno", which is a palindrome and != "nolon".
    // This is 2 cuts.
    //
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be some character s[i] such that s[i] != s[0].
    // This implies that s[0...n/2 - 1] is not a string of identical characters.
    //
    // Let's take the first half of the string: s_half = s.substr(0, n / 2).
    // If s_half consists of all identical characters (e.g., "aaa" for "aaabaaa"),
    // then s must be of the form "aaa...a" + (middle char if n odd) + "aaa...a".
    // This means all characters in s are the same, which we've already handled.
    // So, if not all characters in s are the same, then s_half must contain at least two distinct characters.
    //
    // If s_half is not a palindrome, then we can cut s into s_half and s.substr(n/2).
    // Then swap them. This would be a k=1 solution.
    // But we already checked k=1. So, if we reach here, it means for any cut,
    // the swapped string is either not a palindrome or is equal to s.
    //
    // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
    // then s.substr(0, n-1) (i.e., s without its last character) is NOT a palindrome.
    // Example: "abacaba". s.substr(0,6) = "abacab", not a palindrome.
    // Example: "otto". s.substr(0,3) = "ott", not a palindrome.
    //
    // If s is a palindrome and not all characters are the same, then s.substr(0, n-1) is not a palindrome.
    // This is because if s.substr(0, n-1) were a palindrome, then s[0] == s[n-2], s[1] == s[n-3], etc.
    // Since s is a palindrome, s[0] == s[n-1], s[1] == s[n-2], etc.
    // Combining these, s[n-1] == s[n-2], s[n-2] == s[n-3], etc.
    // This would imply s[0] == s[1] == ... == s[n-1], meaning all characters are the same.
    // But we've already handled the "all same char" case.
    //
    // So, if we reach this point, s is a palindrome, not all characters are the same,
    // and no k=1 solution exists.
    // This implies that s.substr(0, n-1) is NOT a palindrome.
    //
    // Consider cutting s into three pieces:
    // P1 = s[0]
    // P2 = s[1 ... n-2]
    // P3 = s[n-1]
    // Since s is a palindrome, P1 == P3.
    // The original string is P1 + P2 + P3.
    // We can reorder them to P3 + P2 + P1.
    // This new string is s[n-1] + s[1...n-2] + s[0].
    // Since s[n-1] == s[0], this is effectively s[0] + s[1...n-2] + s[0].
    // This is a palindrome because s[1...n-2] is a palindrome (as s is a palindrome).
    // So, s[n-1] + s[1...n-2] + s[0] is a palindrome.
    // Is this new string different from s?
    // s = s[0] + s[1...n-2] + s[n-1]
    // new_s = s[n-1] + s[1...n-2] + s[0]
    // If new_s == s, then s[0] + s[1...n-2] + s[n-1] == s[n-1] + s[1...n-2] + s[0].
    // This is always true because s[0] == s[n-1].
    // This specific reordering (P3+P2+P1) doesn't produce a different string.
    //
    // The example "nolon" -> "onlno" uses cuts "no", "l", "on".
    // This is s[0...1], s[2], s[3...4].
    // Reordered to s[3...4], s[2], s[0...1].
    // This is a general strategy: cut s into s[0...i-1], s[i...j-1], s[j...n-1].
    // Then reorder to s[j...n-1], s[i...j-1], s[0...i-1].
    // This is a palindrome if s[j...n-1] is the reverse of s[0...i-1] and s[i...j-1] is a palindrome.
    // Since s is a palindrome, s[j...n-1] is the reverse of s[0...n-j-1].
    // So we need s[0...n-j-1] == s[0...i-1]. This means n-j-1 = i-1, or n-j = i.
    // So j = n-i.
    // The cuts are at i and n-i.
    // Pieces are s[0...i-1], s[i...n-i-1], s[n-i...n-1].
    // Reorder to s[n-i...n-1] + s[i...n-i-1] + s[0...i-1].
    // This is a palindrome if s[i...n-i-1] is a palindrome.
    // And it's different from s if s[0...i-1] != s[n-i...n-1].
    // But s[0...i-1] is always the reverse of s[n-i...n-1] because s is a palindrome.
    // So this reordering is always a palindrome.
    // We need it to be different from s.
    // s = s[0...i-1] + s[i...n-i-1] + s[n-i...n-1]
    // new_s = s[n-i...n-1] + s[i...n-i-1] + s[0...i-1]
    // Since s[0...i-1] is the reverse of s[n-i...n-1], let P1 = s[0...i-1] and P3 = s[n-i...n-1].
    // Then P3 = reverse(P1).
    // s = P1 + P2 + reverse(P1)
    // new_s = reverse(P1) + P2 + P1
    // If new_s == s, then P1 + P2 + reverse(P1) == reverse(P1) + P2 + P1.
    // This is true if P1 == reverse(P1), i.e., P1 is a palindrome.
    // If P1 is a palindrome, then new_s == s.
    // So we need to find an `i` such that s[0...i-1] is NOT a palindrome.
    //
    // If s is a palindrome and not all characters are the same, then there must exist some `i`
    // such that s[0...i-1] is not a palindrome.
    // For example, if s = "abacaba", n=7.
    // i=1: s[0] = "a", palindrome.
    // i=2: s[0...1] = "ab", not a palindrome.
    // So we can choose i=2.
    // P1 = "ab", P2 = "aca", P3 = "aba".
    // s = "ab" + "aca" + "aba"
    // new_s = "aba" + "aca" + "ab" = "abaacaab". This is a palindrome.
    // And "abaacaab" != "abacaba".
    // So k=2 works.
    //
    // The only case where this fails is if for ALL i from 1 to n/2, s[0...i-1] is a palindrome.
    // If s[0] is a palindrome ("a").
    // If s[0...1] is a palindrome ("aa").
    // If s[0...2] is a palindrome ("aaa").
    // ...
    // If s[0...n/2-1] is a palindrome.
    // This implies s[0] == s[1] == ... == s[n/2-1].
    // Since s is a palindrome, this means all characters in s are the same.
    // But we've already handled the "all same char" case.
    //
    // Therefore, if s is a palindrome and not all characters are the same,
    // there must exist an `i` (1 <= i <= n/2) such that s[0...i-1] is NOT a palindrome.
    // For such an `i`, we can make two cuts:
    // 1. After s[i-1]
    // 2. After s[n-i-1]
    // This creates three pieces:
    // P1 = s[0...i-1]
    // P2 = s[i...n-i-1]
    // P3 = s[n-i...n-1]
    // Since s is a palindrome, P3 is the reverse of P1, and P2 is a palindrome.
    // The new string formed by P3 + P2 + P1 is a palindrome.
    // This new string is different from s because P1 is not a palindrome.
    // (If P1 were a palindrome, then P1 = reverse(P1) = P3, so P1+P2+P3 == P3+P2+P1).
    //
    // So, if we reach this point (not all chars same, k=1 failed), then k=2 is always the answer.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // Case 1: Substring starts with '0'
            // The value of a binary string starting with '0' is the same as the value
            // of the string without leading zeros.
            // For example, f(00101) = f(101) = 5.
            // The length of the substring is r - l + 1.
            // We are looking for r - l + 1 = f(s_l...s_r).
            // If s_l = '0', then f(s_l...s_r) = f(s_{l+1}...s_r) if s_{l+1} is '1',
            // or f(s_{l+k}...s_r) if s_{l+k} is the first '1'.
            // If the substring is all zeros, e.g., "000", f("000") = 0.
            // Length is 3. 3 != 0.
            // The only way f(s_l...s_r) = 0 is if s_l...s_r consists of all '0's.
            // In this case, r - l + 1 = 0, which is impossible for a non-empty string.
            // So, if s_l = '0', we must have some '1's in the substring for f to be positive.
            // If f(s_l...s_r) = K, then the substring must have length K.
            // The maximum value of K for a substring of length up to N is N.
            // The maximum length of a binary string that can represent a value up to N is roughly log2(N).
            // For N = 2e5, log2(2e5) is about 17.6. So, max length is around 18.
            // This means if s_l = '0', and the actual value is K, then the substring
            // s_l...s_r must have length K.
            // The '0's before the first '1' don't change the value.
            // So, if s_l = '0', we can count how many leading zeros there are.
            // Let's say s_i is '0'. We are looking for substrings s_i...s_j.
            // The value is val(s_i...s_j). The length is j - i + 1.
            // We need j - i + 1 = val(s_i...s_j).
            // The value val(s_i...s_j) is at most 2^(j-i+1) - 1.
            // For small lengths, say up to 18, we can iterate.
            // For larger lengths, val(s_i...s_j) will be much larger than j-i+1.
            // Example: s = "0001000"
            // i=0, s[0]='0'.
            //   j=0, s[0]='0'. val=0, len=1. No.
            //   j=1, s[0..1]="00". val=0, len=2. No.
            //   j=2, s[0..2]="000". val=0, len=3. No.
            //   j=3, s[0..3]="0001". val=1, len=4. No.
            //   j=4, s[0..4]="00010". val=2, len=5. No.
            //   j=5, s[0..5]="000100". val=4, len=6. Yes! (s_1..s_6 in 1-indexed)
            //   j=6, s[0..6]="0001000". val=8, len=7. No.
            //
            // The maximum length of a substring we need to check explicitly is limited.
            // If a substring has length L, its value is at most 2^L - 1.
            // We need L = val.
            // If L > 20 (approx), then 2^L - 1 is much larger than L.
            // For example, if L=20, 2^20 - 1 = 1048575.
            // So, if s[i] = '0', we can iterate j from i up to min(n-1, i + MAX_LEN_TO_CHECK).
            // MAX_LEN_TO_CHECK can be around 60, because 2^60 is huge.
            // But the value can be at most N. So, we only care about values up to N.
            // The maximum length of a binary string whose value is <= N is log2(N).
            // For N=2e5, log2(2e5) is about 17.6. So, we only need to check substrings
            // whose actual value is up to N.
            // If s[i] = '0', we can count consecutive zeros.
            // Let's say s[i...k-1] are all '0's and s[k] is '1'.
            // Then for any substring s[i...j], its value is val(s[k...j]).
            // We need j - i + 1 = val(s[k...j]).
            // Let num_leading_zeros = k - i.
            // We need j - i + 1 = val(s[k...j]).
            // This means val(s[k...j]) - (j - k + 1) = num_leading_zeros.
            // We can iterate j from k up to min(n-1, k + MAX_VAL_LEN).
            // MAX_VAL_LEN is around 18.
            // For each such j, calculate val(s[k...j]).
            // If val(s[k...j]) - (j - k + 1) == num_leading_zeros, then it's a good substring.
            // This is for a fixed starting '0' at index i.
            // This approach is $O(N \cdot \log N)$.

            int current_zeros = 0;
            int j = i;
            while (j < n && s[j] == '0') {
                current_zeros++;
                j++;
            }
            // Now s[j] is either '1' or we reached end of string.
            // If we reached end of string, all '0's, no good substrings.
            if (j == n) {
                break; // All remaining characters are '0's
            }

            // Now s[j] is '1'.
            // We are considering substrings s[i...k] where k >= j.
            // The value of s[i...k] is val(s[j...k]).
            // The length is k - i + 1.
            // We need k - i + 1 = val(s[j...k]).
            // This is equivalent to val(s[j...k]) - (k - j + 1) = i - j.
            // No, this is wrong. It should be val(s[j...k]) - (k - j + 1) = current_zeros.
            // Let L_prime = k - j + 1 be the length of s[j...k].
            // We need L_prime + current_zeros = val(s[j...k]).
            // So, val(s[j...k]) - L_prime = current_zeros.

            long long current_val = 0;
            for (int k = j; k < n; ++k) {
                current_val = (current_val << 1) | (s[k] - '0');
                int L_prime = k - j + 1; // Length of s[j...k]

                // Optimization: If current_val becomes too large, it can't be equal to L_prime + current_zeros.
                // The maximum possible value for L_prime + current_zeros is N.
                // If current_val > N, then it's too large.
                // Also, if current_val is very large, it will grow exponentially.
                // L_prime + current_zeros grows linearly.
                // So, current_val - L_prime will quickly exceed current_zeros.
                // The maximum value of current_val we care about is N.
                // If current_val exceeds N, we can stop for this 'j'.
                // N is 2e5.
                if (current_val > n + current_zeros + 1) { // +1 for safety margin
                    break;
                }

                if (current_val - L_prime == current_zeros) {
                    good_substrings_count++;
                }
            }
            i = j - 1; // Continue outer loop from the last '0' before '1'
                       // The outer loop will increment i, so it will start from 'j' in the next iteration.
        } else { // s[i] == '1'
            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                current_val = (current_val << 1) | (s[j] - '0');
                int len = j - i + 1;

                // Optimization: If current_val exceeds N, it's too large.
                // The maximum length is N.
                // If current_val > N, then current_val != len.
                // Also, if current_val becomes too large, it will grow exponentially.
                // len grows linearly.
                // So, current_val will quickly exceed len.
                // The maximum value of current_val we care about is N.
                // If current_val exceeds N, we can stop for this 'i'.
                if (current_val > n + 1) { // +1 for safety margin
                    break;
                }

                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for tracks to read
    for (int i = 0; i < n; ++i) { // Iterate through each head
        if (p_idx == m) { // All tracks have been covered
            break;
        }

        long long current_head_pos = h[i];

        // Find the first track p_j that this head can potentially cover.
        // It must be within T distance from current_head_pos.
        // Also, it must be p_idx or later.

        // If current_head_pos is already to the right of p[p_idx] + T,
        // this head cannot cover p[p_idx] or any earlier tracks.
        // This head can only cover tracks p_k such that p_k <= current_head_pos + T.
        // And p_k >= current_head_pos - T.
        // We are trying to cover tracks from left to right.
        // So, if p[p_idx] is too far to the left for this head, we skip this head.
        // This head can only cover tracks starting from p_idx.
        // If p[p_idx] > current_head_pos + T, this head cannot reach p[p_idx].
        // In this case, this head is useless for p[p_idx] and subsequent tracks
        // if we are trying to cover p[p_idx] with this head.
        // However, this head might be able to cover tracks to its left.
        // The greedy strategy is to cover the leftmost uncovered track.
        // If current_head_pos is too far right to cover p[p_idx] (i.e., p[p_idx] < current_head_pos - T),
        // then this head cannot cover p[p_idx]. We need to use a previous head or this head is useless for p[p_idx].
        // But we are iterating heads from left to right, so previous heads are already assigned.
        // So if p[p_idx] < current_head_pos - T, this head cannot cover p[p_idx].
        // This means p[p_idx] must have been covered by a previous head, which is not true if p_idx is not m.
        // This implies that the current head cannot cover p[p_idx] and we need to move to the next head.
        // This is incorrect. The head can move left.

        // The strategy is: for the current head h[i], find the rightmost track it can cover.
        // This track must be >= p[p_idx].
        // The head can move from h[i] to any track x such that |h[i] - x| <= T.
        // So it can cover tracks in range [h[i] - T, h[i] + T].
        // We want to cover p[p_idx], p[p_idx+1], ...
        // The current head h[i] can cover tracks starting from p[p_idx].
        // The leftmost track it can cover is max(p[p_idx], h[i] - T).
        // The rightmost track it can cover is h[i] + T.
        // We want to cover as many tracks as possible, starting from p[p_idx].
        // So, we find the rightmost track p_k that is <= h[i] + T.
        // And also, p_k must be reachable from h[i] in T seconds.
        // This means p_k >= p[p_idx].
        // And p_k must be within [h[i] - T, h[i] + T].

        // If p[p_idx] is too far to the right for this head (i.e., p[p_idx] > h[i] + T),
        // then this head cannot cover p[p_idx]. We need to use a later head.
        // This head is effectively useless for covering p[p_idx] and beyond.
        // So we continue to the next head.
        // This is also incorrect. The head can move left.

        // Correct greedy strategy:
        // For the current head h[i], it can cover a range [h[i]-T, h[i]+T].
        // We want to cover p[p_idx], p[p_idx+1], ...
        // If p[p_idx] is not within [h[i]-T, h[i]+T], this head cannot cover p[p_idx].
        // Specifically, if p[p_idx] > h[i] + T, this head is too far left.
        // If p[p_idx] < h[i] - T, this head is too far right.
        // The problem states heads can change relative order.
        // This means we can assign any head to any range.
        // But we are iterating heads from left to right (h_i are sorted).
        // It's optimal to use head h_i to cover the leftmost possible tracks.
        // So, if h[i] is too far to the right to cover p[p_idx] (i.e., p[p_idx] < h[i] - T),
        // then this head cannot cover p[p_idx]. This implies that p[p_idx] must have been covered by a previous head.
        // But we are processing p_idx as the first *uncovered* track.
        // So, if p[p_idx] < h[i] - T, it means p[p_idx] cannot be covered by h[i].
        // This implies that p[p_idx] must have been covered by a previous head.
        // This is a contradiction if p_idx is the first uncovered track.
        // So, if p[p_idx] < h[i] - T, it means it's impossible to cover p[p_idx] with current or later heads.
        // This is because later heads are even further to the right.
        // So, if p[p_idx] < h[i] - T, return false.

        // If p[p_idx] is within [h[i] - T, h[i] + T], then h[i] can cover p[p_idx].
        // We want to cover as many tracks as possible with this head.
        // The rightmost track this head can cover is h[i] + T.
        // So, we advance p_idx as long as p[p_idx] <= h[i] + T.
        // This is the standard greedy approach for interval covering.

        // Let's refine the greedy strategy:
        // For each head h[i], we want to cover the leftmost available tracks.
        // The head h[i] can cover any track x such that |h[i] - x| <= T.
        // This means x is in the range [h[i] - T, h[i] + T].
        // We need to cover p[p_idx], p[p_idx+1], ...
        // If p[p_idx] is to the left of h[i] - T, then h[i] cannot reach p[p_idx] by moving right.
        // And since h[i] is the current head, and heads are sorted, any h[j] for j > i will be even further right.
        // So if p[p_idx] < h[i] - T, it's impossible to cover p[p_idx] with this head or any subsequent head.
        // This means `p[p_idx]` must have been covered by a previous head.
        // But `p_idx` points to the first *uncovered* track.
        // So, if `p[p_idx] < h[i] - T`, it means we failed to cover `p[p_idx]`. Return false.

        // If p[p_idx] >= h[i] - T, then h[i] can potentially cover p[p_idx].
        // The head h[i] can cover all tracks p_k such that p_k >= p[p_idx] AND p_k <= h[i] + T.
        // So, we advance p_idx as long as p_idx < m and p[p_idx] <= h[i] + T.
        // This covers a contiguous block of tracks starting from p[p_idx].

        // Example: h = [2, 5, 6], p = [1, 3, 6, 8], T = 2
        // i=0, h[0]=2. p_idx=0, p[0]=1.
        // p[0]=1 is not < h[0]-T (2-2=0). So 1 >= 0. OK.
        // Max reach for h[0] is h[0]+T = 2+2 = 4.
        // Advance p_idx while p[p_idx] <= 4:
        // p[0]=1 <= 4. p_idx becomes 1.
        // p[1]=3 <= 4. p_idx becomes 2.
        // p[2]=6 > 4. Stop.
        // Now p_idx = 2. Tracks 1, 3 covered.

        // i=1, h[1]=5. p_idx=2, p[2]=6.
        // p[2]=6 is not < h[1]-T (5-2=3). So 6 >= 3. OK.
        // Max reach for h[1] is h[1]+T = 5+2 = 7.
        // Advance p_idx while p[p_idx] <= 7:
        // p[2]=6 <= 7. p_idx becomes 3.
        // p[3]=8 > 7. Stop.
        // Now p_idx = 3. Tracks 1, 3, 6 covered.

        // i=2, h[2]=6. p_idx=3, p[3]=8.
        // p[3]=8 is not < h[2]-T (6-2=4). So 8 >= 4. OK.
        // Max reach for h[2] is h[2]+T = 6+2 = 8.
        // Advance p_idx while p[p_idx] <= 8:
        // p[3]=8 <= 8. p_idx becomes 4.
        // Now p_idx = 4. All tracks covered.

        // Loop finishes. p_idx == m. Return true.

        // This greedy strategy seems correct.
        // If p[p_idx] < current_head_pos - T, then this head cannot reach p[p_idx] by moving right.
        // Since h is sorted, all subsequent heads h[j] (j > i) will be even further to the right.
        // So, if p[p_idx] < current_head_pos - T, it's impossible to cover p[p_idx] with any remaining head.
        // This means we failed.
        if (p[p_idx] < current_head_pos - T) {
            return false;
        }

        // If we reach here, p[p_idx] >= current_head_pos - T.
        // This head can cover p[p_idx] (and potentially more tracks to its right).
        // The rightmost track this head can cover is current_head_pos + T.
        long long max_reach = current_head_pos + T;

        // Advance p_idx to cover all tracks reachable by this head.
        while (p_idx < m && p[p_idx] <= max_reach) {
            p_idx++;
        }
    }

    return p_idx == m; // True if all tracks are covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance between tracks (10^10 - 1) + (10^10 - 1) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

