void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we want to add min_val to it as many times as possible.
        // The current value of a[i] is a[i].
        // We can add min_val until a[i] + min_val * count > k.
        // So, a[i] + min_val * count <= k
        // min_val * count <= k - a[i]
        // count <= (k - a[i]) / min_val
        // Since count must be an integer, count = floor((k - a[i]) / min_val)
        if (a[i] < k) { // Only add if there's room
            operations += (k - a[i]) / min_val;
        }
    }
    std::cout << operations << std::endl;
}

