    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s, t;
        std::cin >> s >> t;

        bool possible = false;
        // Iterate through all possible characters 'a' through 'z'
        // and check if any of them exists in both strings.
        // If a character exists in both strings, then it's possible
        // to make both strings equal to a string consisting only of that character.
        // For example, if 'a' is in s and 'a' is in t,
        // s can become "aaa...a" and t can become "aaa...a".
        // This is because any character can propagate its value
        // to fill the entire string.

        // A more direct approach:
        // We need to find if there is *any* common character between s and t.
        // If there is a character 'c' present in string s, and also present in string t,
        // then we can transform s into a string of all 'c's, and t into a string of all 'c's.
        // Thus, s can be made equal to t.
        // If there is no common character, then it's impossible.
        // Suppose s has characters {c1, c2, ...} and t has {d1, d2, ...}.
        // If we want to make them equal to some string U, then U must be reachable from s and t.
        // If U is "ccc...c", then 'c' must be present in s and 'c' must be present in t.
        // If there is no common character, then any character 'c' present in s is not in t,
        // and any character 'd' present in t is not in s.
        // So, s can only become a string of 'c's (where 'c' is from s),
        // and t can only become a string of 'd's (where 'd' is from t).
        // Since no 'c' from s is equal to any 'd' from t, they can never be made equal.

        std::vector<bool> s_chars(26, false);
        for (char c : s) {
            s_chars[c - 'a'] = true;
        }

        for (char c : t) {
            if (s_chars[c - 'a']) {
                possible = true;
                break;
            }
        }

        if (possible) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }
    return 0;
}

