void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int initial_a1 = a[0];
    int max_a1 = initial_a1;

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile i+1 (index i) to pile 1 (index 0)
        int cost_per_haybale = i; // i-th pile (1-indexed) is at index i-1 (0-indexed).
                                  // So pile at index i (0-indexed) is pile i+1 (1-indexed).
                                  // Distance to pile 1 is (i+1) - 1 = i.

        // Number of haybales available in current pile
        int haybales_in_pile = a[i];

        // If we have enough days to move at least one haybale from this pile
        if (d >= cost_per_haybale) {
            // Calculate how many haybales we can move from this pile
            // based on available days and haybales in the pile.
            int haybales_to_move = std::min(haybales_in_pile, d / cost_per_haybale);

            // Add these haybales to pile 1
            max_a1 += haybales_to_move;

            // Deduct the days spent
            d -= haybales_to_move * cost_per_haybale;
        } else {
            // If we don't have enough days for even one haybale from this pile,
            // we can't move any more haybales from further piles either,
            // because they would have an even higher cost.
            break;
        }
    }

    std::cout << max_a1 << std::endl;
}

