int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we will use in the zigzag pattern to generate k distinct differences

    // Generate k distinct differences using a zigzag pattern
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // Fill the rest of the permutation with remaining numbers in increasing order
    // These numbers will be from (k+2) to n.
    // The differences generated by these numbers will all be 1,
    // which is already one of the k distinct differences (specifically, the smallest one).
    for (int i = k + 1; i < n; ++i) {
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
