int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point (0)
                            // The frog starts at 0.
                            // If s[i-1] is 'R', it can jump to i+1, ..., i+d.
                            // If s[i-1] is 'L', it can jump to max(0, i-d), ..., i-1.
                            // To reach n+1, the frog must always make progress to the right.
                            // The only way to make progress to the right is to jump from 0,
                            // or from a cell i where s[i-1] is 'R'.
                            // If s[i-1] is 'L', the frog can only jump left.
                            // This means the frog must always jump from an 'R' cell or cell 0
                            // to another 'R' cell or cell n+1.
                            // Consider the sequence of 'R' cells and cell 0 and cell n+1.
                            // Let these positions be p_0=0, p_1, p_2, ..., p_k, p_{k+1}=n+1.
                            // The frog must be able to jump from p_j to p_{j+1}.
                            // The maximum distance between any two consecutive such points
                            // will determine the minimum d.
                            // The frog can jump from 0 to any cell up to d.
                            // If s[i-1] is 'R', it can jump from i to any cell from i+1 to i+d.
                            // If s[i-1] is 'L', it can jump from i to any cell from max(0, i-d) to i-1.
                            // To reach n+1, the frog must always jump right.
                            // This means it must jump from 0 to some cell j, or from some cell i (where s[i-1] is 'R')
                            // to some cell j.
                            // The key insight is that if the frog is at cell `i` and `s[i-1]` is 'L', it cannot make progress
                            // towards `n+1`. It can only jump to cells `0` through `i-1`.
                            // Therefore, to reach `n+1`, the frog must always jump from a cell `i` where `s[i-1]` is 'R'
                            // (or from cell `0`) to a cell `j` where `j > i`.
                            // This implies that the frog must be able to "skip" all 'L' cells.
                            // The problem reduces to finding the maximum distance between consecutive 'R' cells,
                            // including the distance from cell 0 to the first 'R' cell, and from the last 'R' cell to n+1.
                            // The frog starts at 0. The first jump must be to the right.
                            // It can jump from 0 to any cell in [1, d].
                            // If it lands on cell `i` where `s[i-1]` is 'L', it's stuck going left.
                            // So it must land on cell `i` where `s[i-1]` is 'R', or directly on `n+1`.
                            // This means the frog must be able to jump from `last_R_pos` to the next 'R' cell,
                            // or to `n+1`.
                            // The distance from `last_R_pos` to the current `i` (where `s[i-1]` is 'R') is `i - last_R_pos`.
                            // The distance from `last_R_pos` to `n+1` is `n+1 - last_R_pos`.
                            // We need `d` to be at least this maximum distance.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' cell to n+1.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

