int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // a[i][i] is 0, skip it
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is still 0 (meaning max_val_in_row was 0 for that row)
    // This happens if all a[i][j] for j!=i are 0.
    // In such a case, p[i] should be n.
    // This logic is based on the observation that if p[i] is the largest value (n),
    // then min(p[i], p[j]) = p[j] for all j.
    // If p[i] is n, then max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j].
    // This max value would be n-1 if n > 1.
    // However, if p[i] is n, then for any j, p[j] < n.
    // So max_{j!=i} a[i][j] = max_{j!=i} p[j].
    // If p[i] is n, then all other p[j] are < n.
    // The maximum of these p[j] values is n-1.
    // So if p[i] = n, then max_{j!=i} a[i][j] = n-1.
    // This means if p[i] is n, our current calculation would set p[i] to n-1.
    // We need to find the element that should be n.
    // The element that should be n is the one whose calculated p[i] value
    // is n-1, and all other p[j] values are less than n-1.
    // Or, more simply, if all values in p are less than n, then one of them must be n-1,
    // and that one should be n.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not present in p, it means one of the elements that should be n
        // was assigned n-1 by our logic.
        // This happens because if p_k = n, then for any j != k, a_{k,j} = min(p_k, p_j) = p_j.
        // So max_{j!=k} a_{k,j} = max_{j!=k} p_j = n-1 (since p is a permutation of 1..n).
        // Thus, the element p_k that should be n, is currently set to n-1.
        // We need to find one such element and increment it.
        // Since there's always a solution, there must be exactly one such element.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a decreasing sequence from the right
    // This is the first index `i` from the right such that a[i] < a[i+1]
    // All elements from a[i+1] to a[n-1] form a non-decreasing suffix.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost peak of an increasing sequence from the right
    // This is the first index `j` from the right such that a[j] > a[j+1]
    // All elements from a[j+1] to a[n-1] form a non-increasing suffix.
    int j = i; // Start search from `i` because we only care about elements to the left of `i`
               // If we start from n-1, we might find a j that is to the right of i,
               // which is not what we want for the "valley" part.
               // The elements a[i...n-1] are already non-decreasing.
               // We are looking for the point where the sequence stops being non-increasing
               // from the right, considering elements to the left of `i`.
               // More precisely, we are looking for the first `k` from the right such that `a[k] < a[k+1]`
               // and `a[k+1]` is part of the non-increasing sequence.
               // The elements `a[k+1...n-1]` are non-increasing.
               // The elements `a[i...n-1]` are non-decreasing.
               // The "good" array structure is `... valley ... peak ...`.
               // The `i` found above marks the start of the non-decreasing suffix `a[i...n-1]`.
               // We need to find the start of the non-increasing suffix `a[j...i-1]` (or `a[j...n-1]` if we consider the whole array).
               // Let's rephrase: we want to find the largest `k` such that `a[k...n-1]` is a good array.
               // A good array `b` has the form `b_1 <= b_2 <= ... <= b_p >= b_{p+1} >= ... >= b_m`.
               // Or, `b_1 >= b_2 >= ... >= b_p <= b_{p+1} <= ... <= b_m`.
               // The problem statement example `[1, 2, 3, 4, 4, 2, 1]` is `1<=2<=3<=4<=4 >= 2 >= 1`. This is a "mountain" shape.
               // The example `[1, 1, 2, 2, 3, 4, 4]` is non-decreasing.
               // The example `[4, 5, 2]` is `4<=5 >= 2`. This is a "mountain" shape.
               // The definition of a good array is that it can be made non-decreasing.
               // This implies that the array itself must be a "mountain" shape (non-decreasing then non-increasing)
               // or a "valley" shape (non-increasing then non-decreasing).
               // The example `[1, 2, 3, 4, 4, 2, 1]` is a mountain.
               // The elements are picked from ends.
               // If `b` is good, it must be of the form `x_1, x_2, ..., x_k, ..., x_m` where
               // `x_1 <= x_2 <= ... <= x_k` and `x_k >= x_{k+1} >= ... >= x_m`.
               // This is a "mountain" array.
               // The elements are picked from the ends.
               // The smallest elements must be picked first.
               // If `b_1` is picked, then `b_m`. If `b_1 <= b_m`, then `c = [b_1, b_m]`.
               // If `b_m` is picked, then `b_1`. If `b_m <= b_1`, then `c = [b_m, b_1]`.
               // This means the array must be a "mountain" shape.
               // `a_k <= a_{k+1} <= ... <= a_p >= a_{p+1} >= ... >= a_m`.
               // The `i` found above is the start of the non-decreasing part `a[i...n-1]`.
               // We need to find the start of the non-increasing part `a[j...i-1]`.
               // So, we are looking for the first `j` from the right such that `a[j] > a[j+1]`
               // where `j+1` is part of the non-increasing sequence.
               // This means `a[j+1...i-1]` must be non-increasing.
               // So, we search for `j` from `i-1` downwards.
    j = i;
    while (j > 0 && a[j-1] <= a[j]) { // This finds the start of the non-increasing part from the right.
                                      // Example: [4,3,3,8,4,5,2]
                                      // n=7
                                      // i starts at 6. a[5]=5, a[6]=2. a[5] >= a[6] is false.
                                      // i=6. a[5]=4, a[6]=5. a[5] >= a[6] is false.
                                      // i=5. a[4]=8, a[5]=4. a[4] >= a[5] is true. i becomes 4.
                                      // i=4. a[3]=3, a[4]=8. a[3] >= a[4] is false.
                                      // So i stops at 4. The suffix a[4...6] is [8,4,5,2] which is not non-decreasing.
                                      // My initial `i` logic was wrong.
                                      // `i` should be the first index from the right such that `a[i] < a[i+1]` is false.
                                      // i.e., `a[i] >= a[i+1]`.
                                      // The loop `while (i > 0 && a[i-1] >= a[i]) { i--; }` finds the first index `i`
                                      // such that `a[i...n-1]` is non-decreasing.
                                      // Example: [1,2,3,4] -> i=0.
                                      // Example: [4,3,3,8,4,5,2]
                                      // n=7
                                      // i=6. a[5]=5, a[6]=2. a[5] >= a[6] is true. i=5.
                                      // i=5. a[4]=4, a[5]=5. a[4] >= a[5] is false.
                                      // So i stops at 5. The suffix a[5...6] is [5,2]. This is not non-decreasing.
                                      // The definition of `i` is: `a[i...n-1]` is non-decreasing.
                                      // Let's trace `i` again:
                                      // `i` starts at `n-1`.
                                      // `i` moves left as long as `a[i-1] <= a[i]`.
                                      // Example: [1,2,3,4]
                                      // i=3. a[2]=3, a[3]=4. a[2] <= a[3]. i=2.
                                      // i=2. a[1]=2, a[2]=3. a[1] <= a[2]. i=1.
                                      // i=1. a[0]=1, a[1]=2. a[0] <= a[1]. i=0.
                                      // i=0. Loop terminates. Result `i=0`. Correct.

                                      // Example: [4,3,3,8,4,5,2]
                                      // i=6. a[5]=5, a[6]=2. a[5] <= a[6] is false. Loop terminates. Result `i=6`.
                                      // This means `a[6...6]` is non-decreasing. This is always true for a single element.
                                      // This `i` is the start of the non-decreasing suffix.
                                      // The problem is that the "good" array can be a mountain.
                                      // `b_1 <= b_2 <= ... <= b_p >= b_{p+1} >= ... >= b_m`.
                                      // The elements are picked from ends.
                                      // The smallest elements are picked first.
                                      // This means the elements picked must be `min(b_left, b_right)`.
                                      // If `b` is good, it must be a "mountain" shape.
                                      // `a_k <= a_{k+1} <= ... <= a_p >= a_{p+1} >= ... >= a_m`.
                                      // The elements `a[k...m]` form a mountain.
                                      // We need to find the smallest `k` such that `a[k...n-1]` is a mountain.
                                      // Let's find the peak `p`.
                                      // The right part `a[p...n-1]` must be non-increasing.
                                      // The left part `a[k...p]` must be non-decreasing.
                                      // So, we find the rightmost index `p` such that `a[p...n-1]` is non-increasing.
                                      // Let `p_idx` be this index.
                                      // `p_idx` is the first index from the right such that `a[p_idx] < a[p_idx+1]`.
                                      // All elements `a[p_idx+1...n-1]` are non-increasing.
                                      // Let's find `p_idx`.
    int p_idx = n - 1;
    while (p_idx > 0 && a[p_idx-1] >= a[p_idx]) {
        p_idx--;
    }
    // Now, `a[p_idx...n-1]` is non-increasing.
    // Example: [4,3,3,8,4,5,2]
    // p_idx=6. a[5]=5, a[6]=2. a[5] >= a[6]. p_idx=5.
    // p_idx=5. a[4]=4, a[5]=5. a[4] >= a[5] is false.
    // So p_idx stops at 5. `a[5...6]` is `[5,2]`, which is non-increasing. Correct.

    // Now, we need to find the leftmost index `k` such that `a[k...p_idx]` is non-decreasing.
    // Let `k_idx` be this index.
    // `k_idx` is the first index from the right (starting from `p_idx`) such that `a[k_idx] > a[k_idx+1]`.
    // All elements `a[k_idx+1...p_idx]` are non-decreasing.
    int k_idx = p_idx;
    while (k_idx > 0 && a[k_idx-1] <= a[k_idx]) {
        k_idx--;
    }
    // Now, `a[k_idx...p_idx]` is non-decreasing.
    // Example: [4,3,3,8,4,5,2]
    // p_idx = 5.
    // k_idx starts at 5.
    // k_idx=5. a[4]=4, a[5]=5. a[4] <= a[5]. k_idx=4.
    // k_idx=4. a[3]=8, a[4]=4. a[3] <= a[4] is false.
    // So k_idx stops at 4. `a[4...5]` is `[4,5]`. This is non-decreasing. Correct.

    // The array `a[k_idx...n-1]` is a mountain shape.
    // `a[k_idx...p_idx]` is non-decreasing.
    // `a[p_idx...n-1]` is non-increasing.
    // The length of the prefix to erase is `k_idx`.
    std::cout << k_idx << std::endl;
}

