void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Case 1: Final toy in Box 1 (fun value <= -1)
    // This requires an odd number of negative factors and magnitude >= 1.
    // Number of negative factors: A + B
    // Number of factors with magnitude < 1: B + C
    // Number of factors with magnitude >= 1: A + D

    // To get a negative result, A+B must be odd.
    // To get magnitude >= 1, we need to ensure enough factors with magnitude >= 1.
    // Let N_neg = A+B, N_mag_lt1 = B+C, N_mag_ge1 = A+D.

    // Box 1: Negative, magnitude >= 1
    // Condition for negative: (A + B) % 2 == 1
    // Condition for magnitude >= 1:
    // If A+D >= 1, it's possible to get magnitude >= 1.
    // If A+D == 0, then all initial toys have magnitude < 1 (B+C > 0).
    // In this case, the product will always have magnitude < 1.
    // So, A+D must be >= 1 for Box 1 or Box 4.
    if ((A + B) % 2 == 1 && (A + D >= 1 || total_toys == 1)) {
        ans1 = "Ya";
    }
    // Special case: if total_toys == 1, the single toy determines the box.
    // If A=1, B=C=D=0, then Box 1 is the special box.
    // The general condition (A+B)%2==1 covers A=1.
    // The general condition A+D>=1 covers A=1.
    // So, total_toys == 1 is handled.

    // Box 2: Negative, magnitude < 1
    // Condition for negative: (A + B) % 2 == 1
    // Condition for magnitude < 1:
    // If B+C >= 1, it's possible to get magnitude < 1.
    // If B+C == 0, then all initial toys have magnitude >= 1 (A+D > 0).
    // In this case, the product will always have magnitude >= 1.
    // So, B+C must be >= 1 for Box 2 or Box 3.
    if ((A + B) % 2 == 1 && (B + C >= 1 || total_toys == 1)) {
        ans2 = "Ya";
    }

    // Box 3: Positive, magnitude < 1
    // Condition for positive: (A + B) % 2 == 0
    // Condition for magnitude < 1: B+C >= 1
    if ((A + B) % 2 == 0 && (B + C >= 1 || total_toys == 1)) {
        ans3 = "Ya";
    }

    // Box 4: Positive, magnitude >= 1
    // Condition for positive: (A + B) % 2 == 0
    // Condition for magnitude >= 1: A+D >= 1
    if ((A + B) % 2 == 0 && (A + D >= 1 || total_toys == 1)) {
        ans4 = "Ya";
    }

    // Edge case: total_toys == 1
    // If A=1, B=C=D=0: Box 1. (A+B)%2=1, A+D=1. ans1=Ya. Correct.
    // If B=1, A=C=D=0: Box 2. (A+B)%2=1, B+C=1. ans2=Ya. Correct.
    // If C=1, A=B=D=0: Box 3. (A+B)%2=0, B+C=1. ans3=Ya. Correct.
    // If D=1, A=B=C=0: Box 4. (A+B)%2=0, A+D=1. ans4=Ya. Correct.
    // The `|| total_toys == 1` part in the conditions handles this.

    // Additional check for magnitude:
    // If all initial toys have magnitude < 1 (A+D == 0), then the final product must have magnitude < 1.
    // In this scenario, Box 1 and Box 4 are impossible.
    if (A + D == 0 && total_toys > 0) { // If A+D=0, then A=0, D=0. All toys are in B or C.
        ans1 = "Tidak";
        ans4 = "Tidak";
    }
    // If all initial toys have magnitude >= 1 (B+C == 0), then the final product must have magnitude >= 1.
    // In this scenario, Box 2 and Box 3 are impossible.
    if (B + C == 0 && total_toys > 0) { // If B+C=0, then B=0, C=0. All toys are in A or D.
        ans2 = "Tidak";
        ans3 = "Tidak";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

