int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // Quadratic equation: a^2 - d*a + d = 0
        // Discriminant = d^2 - 4d
        double discriminant = d * d - 4.0 * d;

        if (discriminant < 0.0) {
            std::cout << "N\n";
        } else {
            // Solutions for 'a': (d +/- sqrt(discriminant)) / 2
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // We need a and b to be non-negative.
            // Since d >= 0, and sqrt_discriminant >= 0,
            // a1 = (d + sqrt_discriminant) / 2.0 will always be non-negative.
            // For b1 = d - a1 to be non-negative:
            // d - (d + sqrt_discriminant) / 2.0 >= 0
            // (2d - d - sqrt_discriminant) / 2.0 >= 0
            // (d - sqrt_discriminant) / 2.0 >= 0
            // This means d >= sqrt_discriminant
            // d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, both a1 and b1 will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median must be <= s
    // If a[i] > s, we must decrease it to s.
    // If a[i] <= s, it's already fine relative to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s
    // If a[i] < s, we must increase it to s.
    // If a[i] >= s, it's already fine relative to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (from sorted 'a')
    int right_ptr = 0; // Pointer for positions (from sorted 'a')

    while (right_ptr < n) {
        // We are trying to find an element a[left_ptr]
        // that can be placed at position a[right_ptr] such that a[left_ptr] > a[right_ptr].
        // Since both arrays are sorted, if a[left_ptr] > a[right_ptr],
        // then a[left_ptr+1] will also be >= a[left_ptr] and thus > a[right_ptr].
        // We want to use the smallest possible element from the 'available' pool
        // to satisfy the condition for the current 'position' element.
        // This leaves larger elements for larger 'position' elements later.

        // Find the smallest element a[left_ptr] that is strictly greater than a[right_ptr].
        // If a[left_ptr] <= a[right_ptr], it cannot be placed at a[right_ptr]'s position
        // to satisfy the condition. So, we need to try a larger element for a[right_ptr]'s position.
        // This means we advance left_ptr until we find an element that is greater.
        // If we find such an element, we use it, increment count, and advance both pointers.
        // If we reach the end of the 'available' elements (left_ptr == n) without finding one,
        // then no more matches are possible.

        if (a[left_ptr] > a[right_ptr]) {
            // Found an element a[left_ptr] that is greater than a[right_ptr].
            // We can make a match.
            count++;
            left_ptr++; // This element a[left_ptr] is now "used".
            right_ptr++; // This position a[right_ptr] is now "filled".
        } else {
            // a[left_ptr] is not greater than a[right_ptr].
            // This means a[left_ptr] cannot be placed at a[right_ptr]'s position
            // to satisfy the condition.
            // We must try a larger element for a[right_ptr]'s position.
            // So, we advance left_ptr to consider the next available element.
            left_ptr++;
        }
        // Ensure left_ptr does not exceed n. If it does, we've run out of elements to place.
        if (left_ptr == n) {
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a.begin(), a.end());

    // Sort B elements based on their values in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Fill A' such that A'_i corresponds to the original index of B_i
    // The largest A_j should be paired with the largest B_k (which means largest B_k.value)
    // The smallest A_j should be paired with the smallest B_k (which means smallest B_k.value)
    // This is because F(n, k) = (n+1)/(k+1).
    // To maximize sum( (A'_i+1)/(B_i+1) ), we want to pair large A' with small B,
    // and small A' with large B.
    // However, the problem states A_i >= B_j for all i, j.
    // The formula is F(n, k) = (n+1)/(k+1).
    // We want to maximize sum (A'_i + 1) / (B_i + 1).
    // Let x_i = A'_i + 1 and y_i = B_i + 1. We want to maximize sum x_i / y_i.
    // The values x_i are (sorted A_j + 1). The values y_i are (sorted B_j + 1).
    // To maximize sum x_i / y_i, we should pair the largest x_i with the smallest y_i,
    // the second largest x_i with the second smallest y_i, and so on.
    // This means sorting A in ascending order and B in ascending order,
    // then pairing A[i] with B[m-1-i] (if B is sorted ascending).
    // Or, if A is sorted ascending and B is sorted descending, pair A[i] with B[i].

    // A is sorted ascending: a[0] <= a[1] <= ... <= a[m-1]
    // b_elements is sorted ascending by value: b_elements[0].value <= ... <= b_elements[m-1].value
    // We want to pair a[i] with b_elements[m-1-i].value.
    // The result needs to be stored in a_prime at the original index of b_elements[m-1-i].
    for (int i = 0; i < m; ++i) {
        // a[i] is the i-th smallest value from array A.
        // b_elements[m-1-i] is the i-th largest value from array B.
        // We assign the i-th smallest A value to the original position of the i-th largest B value.
        // This means a_prime[b_elements[m-1-i].original_index] = a[i].
        a_prime[b_elements[m - 1 - i].original_index] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

