// Function to check if a subarray is a permutation of its length
// `arr` is the full array, `start_idx` is the starting index of the subarray,
// `len` is the length of the subarray.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) { // A permutation must have non-zero length
        return false;
    }
    std::vector<bool> seen(len + 1, false); // Use 1-based indexing for values 1 to len
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    // After checking all elements, ensure max_val is exactly len
    // This implicitly checks if all numbers from 1 to len are present
    // because we already checked for duplicates and values out of range.
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_overall) {
            max_val_overall = a[i];
        }
    }

    // Precompute prefix_max and suffix_max
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    // Precompute prefix_is_perm and suffix_is_perm
    std::vector<bool> prefix_is_perm(n + 1, false); // prefix_is_perm[k] means a[0...k-1] is perm of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_prefix_max = 0;
    bool current_prefix_valid = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[k-1];
        if (val < 1 || val > k || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        if (current_prefix_valid) {
            seen_prefix[val] = true;
            if (val > current_prefix_max) {
                current_prefix_max = val;
            }
            if (current_prefix_max == k) {
                prefix_is_perm[k] = true;
            }
        }
    }

    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[k] means a[n-k...n-1] is perm of length k
    std::vector<bool> seen_suffix(n + 1, false);
    int current_suffix_max = 0;
    bool current_suffix_valid = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[n-k];
        if (val < 1 || val > k || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        if (current_suffix_valid) {
            seen_suffix[val] = true;
            if (val > current_suffix_max) {
                current_suffix_max = val;
            }
            if (current_suffix_max == k) {
                suffix_is_perm[k] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Condition 1: max value in p1 must be l1
        // Condition 2: max value in p2 must be l2
        // Condition 3: p1 must be a permutation of length l1
        // Condition 4: p2 must be a permutation of length l2

        // Check conditions using precomputed arrays
        if (prefix_max[l1-1] == l1 && suffix_max[l1] == l2 &&
            prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

