                                       // So k will not overflow long long.
                                       // The cost `(k-1)*(k/2)` can overflow if `k` is too large.
                                       // `k` can be up to `2^31`.
                                       // `(2^31-1)*(2^30)` is approx `2^61`, which fits in `long long`.
                                       // The next `k` would be `2^32`.
                                       // `(2^32-1)*(2^31)` is approx `2^63`, which fits in `long long`.
                                       // The next `k` would be `2^33`.
                                       // `(2^33-1)*(2^32)` is approx `2^65`, which overflows `long long`.
                                       // So `k` can go up to `2^32`.
                                       // If `k` is `2^32`, `k*2` is `2^33`, which is `(1LL << 33)`.
                                       // This is fine.
                                       // The maximum value for `k` before `k*2` overflows `long long` is `(1LL << 62)`.
                                       // So `k` can be `(1LL << 62)`.
                                       // `(1LL << 62)` is `4.6 * 10^18`.
                                       // `(k-1)*(k/2)` for `k = (1LL << 32)` is `(2^32-1)*2^31` which is `~2^63`.
                                       // This is `~9 * 10^18`. This is fine.
                                       // For `k = (1LL << 33)`, `(k-1)*(k/2)` is `(2^33-1)*2^32` which is `~2^65`.
                                       // This would overflow `long long`.
                                       // So `k` should not exceed `(1LL << 33)`.
                                       // The loop condition `current_cost + current_stair_cost <= x` will handle this.
                                       // `k` will not exceed `(1LL << 33)` because the cost would be too high.
                                       // So `k*2` will not overflow `long long`.
                    break; // No more staircases can be built.
                }
                k *= 2;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
