#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need current_sum + S_appended = 2 * (current_xor_sum ^ X_appended)
    // Let S_appended be the sum of appended elements and X_appended be their XOR sum.
    // We want current_sum + S_appended = 2 * (current_xor_sum ^ X_appended)

    // Strategy: Append at most 3 elements.
    // The problem statement guarantees a solution always exists.
    // A common strategy for these problems is to append 0, X, or X, X, 0, etc.
    // Let's try to append two elements.
    // Let the two elements be X_0 and S_0 + X_0.
    // This is a known trick for similar problems.
    // Let X_0 be the current_xor_sum.
    // Let S_0 be the current_sum.
    // We want to append b1, b2 such that:
    // (S_0 + b1 + b2) = 2 * (X_0 ^ b1 ^ b2)

    // Consider appending two elements: X_0 and S_0 + X_0.
    // Let b1 = X_0.
    // Let b2 = S_0 + X_0.
    // New sum: S' = S_0 + b1 + b2 = S_0 + X_0 + (S_0 + X_0) = 2 * S_0 + 2 * X_0.
    // New XOR sum: X' = X_0 ^ b1 ^ b2 = X_0 ^ X_0 ^ (S_0 + X_0) = 0 ^ (S_0 + X_0) = S_0 + X_0.
    // We need S' = 2 * X'.
    // Is (2 * S_0 + 2 * X_0) = 2 * (S_0 + X_0)?
    // Yes, this is always true.
    // So, appending X_0 and S_0 + X_0 always works.
    // The number of appended elements is 2.

    // The problem states we don't have to minimize.
    // If the array is already good, we can output 0 elements.
    // If not, we can always append 2 elements.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // Append current_xor_sum and current_sum + current_xor_sum
        // Let X_val = current_xor_sum
        // Let S_val = current_sum
        // Append X_val and S_val + X_val
        // New sum = S_val + X_val + (S_val + X_val) = 2 * S_val + 2 * X_val
        // New XOR sum = X_val ^ X_val ^ (S_val + X_val) = 0 ^ (S_val + X_val) = S_val + X_val
        // Check condition: (2 * S_val + 2 * X_val) == 2 * (S_val + X_val)
        // This is always true.
        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

