int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1000000007;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // This 'b' will effectively double the number of 'a's
            // that need to be processed (or rather, the number of 'ab' pairs
            // that will be formed and need to be resolved)
            // when an 'a' passes it.
            // Each 'a' passing this 'b' will generate one 'bba' operation.
            // The 'a' moves past, and a new 'b' is created.
            // This new 'b' effectively doubles the count_a for future 'a's.
            // So, if we have count_a 'a's to the left, and they all pass this 'b',
            // they will contribute count_a steps.
            // After they pass, the new 'b' effectively doubles the 'a's that
            // will interact with 'b's further to the left.
            // This is equivalent to saying that for each 'b', the current
            // count_a 'a's to its left will each contribute 1 step.
            // And this 'b' itself will effectively double the 'a's that
            // are yet to be encountered (further left).
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to pass all 'b's to its right.
            // The current value of count_a represents the number of 'a's
            // that are effectively "active" and need to be moved past 'b's.
            // This 'a' adds one to that count.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

