int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // They should only be counted once.
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // Rule 1: If s_i is 0, then w_{i-x} (if exists) and w_{i+x} (if exists) must be 0.
    // We use this to set bits in w to 0.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Rule 2: Verify if the constructed w produces the given s.
    // For each s_i, check if it can be 1 based on w.
    // If s_i is 1, but our w cannot produce it, then no solution exists.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool can_be_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
                can_be_one = true;
            }
            if (i + x < n && w[i + x] == '1') {
                can_be_one = true;
            }

            if (!can_be_one) {
                std::cout << -1 << std::endl;
                return;
            }
        }
    }

    std::cout << w << std::endl;
}

