void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of 'val' in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment is just [1]. It always exists.
    // The position of 1 is pos[1]. l=pos[1], r=pos[1].
    // min_idx = pos[1], max_idx = pos[1].
    // Current range [min_idx, max_idx] has length 1.
    // This covers the number 1.
    result[0] = '1';

    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Get the position of the current number 'm'
        int current_m_pos = pos[m];

        // Expand the current range [min_idx, max_idx] to include current_m_pos
        min_idx = std::min(min_idx, current_m_pos);
        max_idx = std::max(max_idx, current_m_pos);

        // Check if the length of the expanded range is equal to 'm'
        // If max_idx - min_idx + 1 == m, it means all numbers from 1 to m
        // are contained within this contiguous subsegment, and its length
        // is exactly m. This implies it's a permutation of 1...m.
        if (max_idx - min_idx + 1 == m) {
            result[m - 1] = '1';
        } else {
            result[m - 1] = '0';
        }
    }

    std::cout << result << std::endl;
}

