#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
// The pattern will always be 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This effectively means padding with '0's from the left in the original number
    // because we built the string from right to left.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    // Reverse the string to get the correct order (most significant digit first)
    // This is not strictly necessary if we always use the map with this format,
    // but it's good for consistency with how patterns are usually read.
    // However, the problem statement says "i-th from the right digit",
    // so storing it reversed (least significant digit first) might be more direct.
    // Let's re-evaluate.
    // If s = 010, and x = 92.
    // x=92 -> 2 (even) -> 0, 9 (odd) -> 1. Pattern for 92 is "10".
    // If we pad to 18 digits: "000...00010".
    // If s = 010, it's also padded to "000...00010".
    // So, the string should be built from right to left, and then padded from the left.
    // My current `pattern += '0'` adds to the right, so it's building from right to left.
    // Example: n=92.
    // n%10=2 (even) -> pattern="0"
    // n=9
    // n%10=9 (odd) -> pattern="01"
    // n=0
    // Loop ends. pattern="01".
    // Pad to 18: pattern="010000000000000000".
    // This is the reverse of what we want if we read it left-to-right.
    // The problem says "i-th from the right digit".
    // So, if pattern is "010", it means rightmost is '0', second from right is '1', third from right is '0'.
    // For 92: rightmost is 2 (even), second is 9 (odd).
    // So, 92 matches "10" (rightmost 0, second 1).
    // If we store "01" for 92, and "010" for pattern, then we need to compare them from left to right.
    // The problem states: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
    // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should effectively compare 18-digit strings.
    // For 92: "000...00092"
    // For s=010: "000...000010"
    // Parity string for 92: "000...00010" (18 digits)
    // Parity string for s=010: "000...000010" (18 digits)
    // These are different. The example says 92 matches 010.
    // Let's re-read: "parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
    // This means we should compare digit by digit from right to left.
    // If s = 010, x = 92.
    // x: ...00092
    // s: ...000010
    // 1st from right: x=2 (even), s=0 (even). Match.
    // 2nd from right: x=9 (odd), s=1 (odd). Match.
    // 3rd from right: x=0 (even), s=0 (even). Match.
    // All other digits of x are 0 (even), all other digits of s are 0 (even). Match.
    // So, 92 matches 010.
    // This implies that the pattern string we generate for a number should be its parity string,
    // padded with '0's from the LEFT to a fixed length (18).
    // My current `pattern` string is built from right to left.
    // For n=92:
    // n%10=2 (even) -> pattern="0"
    // n=9
    // n%10=9 (odd) -> pattern="01"
    // n=0
    // Loop ends. pattern="01". This is the parity string from right to left.
    // To pad it from the left to 18 characters, we need to reverse it first, then pad, then reverse again.
    // Or, more simply, pad with '0's at the beginning.
    // Example: "01" -> pad to 18 -> "000...00001" (18 chars).
    // This is the string representation of the number's parity, where the rightmost char is the parity of the rightmost digit.
    // Let's use this.
    std::reverse(pattern.begin(), pattern.end()); // Now it's left-to-right
    std::string padded_pattern(18 - pattern.length(), '0'); // Pad with '0's from left
    padded_pattern += pattern;
    return padded_pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to 18 characters
            std::string padded_s(18 - s.length(), '0');
            padded_s += s;
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

