int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum_w(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_w[i + 1] = prefix_sum_w[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n - i' items must be taken from the right
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum_w[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items w_{n-j}, ..., w_{n-1}
        current_energy += (prefix_sum_w[n] - prefix_sum_w[n - j]) * r;

        // Add penalty for imbalance
        if (i > j) { // More items from left than right
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (long long)(j - i - 1) * Qr;
        }
        // If i == j, no penalty

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1 is odd. Opponent takes 1.
                // Then N-2 is even. Chanek takes N-2/2.
                // This path is generally worse if N/2 is a good move.

                // Option 2: Take N/2 coins
                // This is generally the greedy move.
                // But we need to consider if taking 1 coin leads to a better outcome for Chanek.

                // If N is even, Chanek has two choices: take 1 or take N/2.
                // Taking N/2 is always better or equal to taking 1, unless taking 1
                // forces the opponent into a bad state, or allows Chanek to take a large amount later.

                // Consider the case where N is a power of 2 (e.g., 2, 4, 8, 16, ...).
                // If N is a power of 2, say 2^k:
                // Chanek takes N/2 = 2^(k-1). N becomes 2^(k-1).
                // Opponent takes N/2 = 2^(k-2). N becomes 2^(k-2).
                // ...
                // This continues until N=1.
                // Chanek gets 2^(k-1) + 2^(k-3) + ...
                // Opponent gets 2^(k-2) + 2^(k-4) + ...
                // In this scenario, Chanek gets 2/3 of the total coins (approx).
                // Example N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. Opponent: 1.
                // Example N=6: Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 3+1=4. Opponent: 1+1=2.

                // What if N is even, but not a power of 2?
                // N = 2^k * M, where M is odd and M > 1.
                // If Chanek takes N/2: N becomes 2^(k-1) * M.
                // If Chanek takes 1: N becomes 2^k * M - 1 (odd).

                // The optimal strategy for Chanek when N is even:
                // If N is a power of 2 (N = 2^k, k >= 1):
                // Chanek takes N/2. This is always optimal.
                // Example: N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 3. Opponent: 1.
                // If Chanek took 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+1=2. Opponent: 1+1=2.
                // So for N=4, taking N/2 is better.

                // If N is even but not a power of 2 (N = 2^k * M, M > 1, M odd):
                // Chanek takes N/2. N becomes 2^(k-1) * M.
                // This leaves an even number for the opponent if k-1 >= 1.
                // If k=1, N = 2 * M. Chanek takes M. N becomes M (odd).
                // Opponent takes 1. N becomes M-1 (even).
                // This seems to be the best strategy.

                // Let's re-evaluate the strategy:
                // If N is odd: Chanek must take 1.
                // If N is even:
                //   If N is a power of 2 (N = 2^k): Chanek takes N/2.
                //   If N is even but not a power of 2 (N = 2^k * M, M > 1, M odd):
                //     Chanek takes N/2. This is always optimal.
                //     Why? Because taking 1 leaves N-1 (odd) for opponent. Opponent takes 1.
                //     Then N-2 (even) for Chanek.
                //     Taking N/2 leaves N/2 (even or odd) for opponent.
                //     If N/2 is odd (i.e., N = 2 * M, M odd), Chanek takes M. N becomes M.
                //     Opponent takes 1. N becomes M-1.
                //     This seems to be the most aggressive move.

                // The only time taking 1 is better than taking N/2 is if taking N/2
                // gives the opponent a very good position, and taking 1 gives Chanek a better position.
                // This happens when N/2 is a power of 2, and N is not.
                // Example: N=6.
                // Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Chanek takes N/2 (3): N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Both give 4.

                // Example: N=10.
                // Chanek takes 1: N=9. Opponent takes 1. N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                // Chanek: 1+4+1=6. Opponent: 1+2+1=4.
                // Chanek takes N/2 (5): N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                // Chanek: 5+2+1=8. Opponent: 1+1=2.
                // Here, taking N/2 is better.

                // It seems the strategy is always:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is a greedy strategy. Let's test it.

                // The only exception is if N is even, and N/2 is a power of 2, and N is not.
                // This means N = 2 * (2^k) = 2^(k+1). This is a power of 2.
                // So the condition "N/2 is a power of 2, and N is not" is impossible.
                // If N/2 is a power of 2, then N must be a power of 2.

                // The only case where taking 1 might be better than taking N/2 is if N is even,
                // and taking N/2 leads to a state where the opponent gets a lot,
                // while taking 1 leads to a state where Chanek gets a lot.
                // This happens when N is even, and N/2 is odd (i.e., N = 2 * M, M odd).
