    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    std::vector<int> ans(n);
    bool found_solution = false;

    for (int pivot_val = 0; pivot_val <= 9; ++pivot_val) {
        int last1 = -1; // Represents -infinity
        int last2 = -1; // Represents -infinity
        bool possible_pivot = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot_val) {
                // Must be color 1
                if (d[i] >= last1) {
                    ans[i] = 1;
                    last1 = d[i];
                } else {
                    possible_pivot = false;
                    break;
                }
            } else if (d[i] > pivot_val) {
                // Must be color 2
                if (d[i] >= last2) {
                    ans[i] = 2;
                    last2 = d[i];
                } else {
                    possible_pivot = false;
                    break;
                }
            } else { // d[i] == pivot_val
                // Can be color 1 or 2
                // Prioritize color 2 if possible, to keep last1 small
                if (d[i] >= last2) { // Can be color 2
                    ans[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) { // Can be color 1
                    ans[i] = 1;
                    last1 = d[i];
                } else { // Cannot be either
                    possible_pivot = false;
                    break;
                }
            }
        }

