// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // This means we need to "remove" just enough factors from p to make it not divisible by q.
        // To maximize x, we should remove as few factors as possible, and specifically,
        // remove factors that are part of q.

        // Get prime factors of q
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        long long max_x = 0;

        // For each prime factor f of q, we try to construct an x by dividing p by f
        // until x is no longer divisible by q.
        // Specifically, we want to find the largest x = p / f^k such that x % q != 0.
        // This means x must have fewer factors of f than q has.
        // If q = f_1^a_1 * ... * f_k^a_k, then x must not be divisible by q.
        // This means for at least one f_j, the exponent of f_j in x must be less than a_j.
        // To maximize x, we should pick one f_j and reduce its exponent in p just enough.
        // For each prime factor f_i of q:
        // 1. Calculate the maximum power of f_i that divides p. Let it be p_exp_i.
        // 2. Calculate the maximum power of f_i that divides q. Let it be q_exp_i.
        // 3. We need to reduce the power of f_i in p to be less than q_exp_i.
        //    The largest such divisor of p would be p / f_i^(p_exp_i - q_exp_i + 1).
        //    This ensures that the resulting number has f_i^(q_exp_i - 1) as its highest power of f_i,
        //    which is less than f_i^q_exp_i.
        // We do this for each distinct prime factor of q and take the maximum resulting x.

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            int q_exp = factor_pair.second; // Exponent of f in q

            long long current_p = p;
            int p_exp = 0;
            while (current_p > 0 && current_p % f == 0) {
                current_p /= f;
                p_exp++;
            }

            // We need to remove f^(p_exp - q_exp + 1) from p
            // This ensures that the new exponent of f is (p_exp - (p_exp - q_exp + 1)) = q_exp - 1,
            // which is less than q_exp.
            long long divisor_to_remove = 1;
            for (int i = 0; i < p_exp - q_exp + 1; ++i) {
                divisor_to_remove *= f;
            }
            max_x = std::max(max_x, p / divisor_to_remove);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

