    long long term2 = (a % MOD);                 // sum 1 (a times)

    long long inner_sum_val = (term1 + term2) % MOD; // (sum k * b + sum 1) = sum (k*b + 1)

    long long total_sum = (inner_sum_val * sum_r) % MOD; // (sum (k*b+1)) * (sum r)

