#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> present_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s[s[i] - 'a'] = true;
        if (i > 0) {
            char c1 = s[i - 1];
            char c2 = s[i];
            if (adj[c1 - 'a'].find(c2) == adj[c1 - 'a'].end()) {
                adj[c1 - 'a'].insert(c2);
                adj[c2 - 'a'].insert(c1);
                degree[c1 - 'a']++;
                degree[c2 - 'a']++;
            }
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (degree[i] > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting point for a path: a character with degree 1 that is present in s
    // Or, if all present characters have degree 0 or 2, pick one with degree 0 or 2.
    // If all present characters have degree 2, it means they form cycles.
    // If there are multiple paths/cycles, we need to connect them.
    // The problem implies a single path/cycle for the characters in s.

    char start_char = 0;
    bool found_start = false;
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && degree[i] == 1) {
            start_char = (char)('a' + i);
            found_start = true;
            break;
        }
    }
    if (!found_start) { // No degree 1 nodes among present characters
        for (int i = 0; i < 26; ++i) {
            if (present_in_s[i] && degree[i] == 0) { // Isolated character
                start_char = (char)('a' + i);
                found_start = true;
                break;
            }
        }
    }
    if (!found_start) { // All present characters have degree 2
        for (int i = 0; i < 26; ++i) {
            if (present_in_s[i] && degree[i] == 2) {
                start_char = (char)('a' + i);
                found_start = true;
                break;
            }
        }
    }

    if (found_start) {
        char current_char = start_char;
        char prev_char = 0; // Sentinel for the first step

        while (current_char != 0 && !visited[current_char - 'a']) {
            layout += current_char;
            visited[current_char - 'a'] = true;

            char next_char = 0;
            for (char neighbor : adj[current_char - 'a']) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Check if all characters from s are included in the layout
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            std::cout << "NO\n"; // This means there are disconnected components in the graph of s-chars
            return;
        }
    }

    // Add remaining characters (not in s or not part of the main path)
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

