#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_val: minimum possible value for a[i] if it's part of an increasing sequence starting from 0.
    // prefix_min_val[i] = i
    // We need a[i] >= i for the increasing part.
    // If a[i] < i, then it's impossible to make a[i] = i.
    // So, we need to find the first index i where a[i] < i.
    // If such an index exists, then no k can be chosen such that k >= i+1.
    // This means k must be <= i.
    // Let's find the first index `i` such that `a[i] < i`.
    // If no such `i` exists, then `a[i] >= i` for all `i` from `0` to `n-1`.
    // In this case, we can always form an increasing sequence `0, 1, ..., n-1`.
    // So, `k=n` is a possible peak.
    // If `k=n` is possible, then `a[n-1]` must be the peak.
    // The left part `a[0] < ... < a[n-1]` requires `a[i] >= i`.
    // The right part is empty.
    // So if `a[i] >= i` for all `i`, then `k=n` is possible.

    int first_bad_prefix_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            first_bad_prefix_idx = i;
            break;
        }
    }

    // Calculate suffix_min_val: minimum possible value for a[i] if it's part of a decreasing sequence ending at 0.
    // suffix_min_val[i] = n-1-i
    // We need a[i] >= n-1-i for the decreasing part.
    // If a[i] < n-1-i, then it's impossible to make a[i] = n-1-i.
    // So, we need to find the first index i (from right) where a[i] < n-1-i.
    // If such an index exists, then no k can be chosen such that k <= i+1.
    // This means k must be >= i+1.
    // Let's find the first index `i` (from right) such that `a[i] < n-1-i`.
    // If no such `i` exists, then `a[i] >= n-1-i` for all `i` from `0` to `n-1`.
    // In this case, we can always form a decreasing sequence `n-1, n-2, ..., 0`.
    // So, `k=1` is a possible peak.
    // If `k=1` is possible, then `a[0]` must be the peak.
    // The left part is empty.
    // The right part `a[0] > ... > a[n-1]` requires `a[i] >= n-1-i`.
    // So if `a[i] >= n-1-i` for all `i`, then `k=1` is possible.

    int first_bad_suffix_idx = -1; // This will be the index from the left
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            first_bad_suffix_idx = i;
            break;
        }
    }

    // If first_bad_prefix_idx is -1, it means a[i] >= i for all i.
    // This implies we can always make the array strictly increasing up to a[n-1].
    // So k=n is a valid peak.
    // Example: [0,1,2,3] -> [0,1,2,3] is sharpened with k=4.
    // So if first_bad_prefix_idx == -1, answer is Yes.
    if (first_bad_prefix_idx == -1) {
        std::cout << "Yes\n";
        return;
    }

    // If first_bad_suffix_idx is -1, it means a[i] >= n-1-i for all i.
    // This implies we can always make the array strictly decreasing from a[0].
    // So k=1 is a valid peak.
    // Example: [3,2,1,0] -> [3,2,1,0] is sharpened with k=1.
    // So if first_bad_suffix_idx == -1, answer is Yes.
    if (first_bad_suffix_idx == -1) {
        std::cout << "Yes\n";
        return;
    }

    // If both are not -1, it means there's a prefix that cannot be made increasing
    // and a suffix that cannot be made decreasing.
    // Specifically, for any k, the left part requires a[i] >= i for i < k.
    // The first_bad_prefix_idx is the smallest i such that a[i] < i.
    // This means any k chosen must be <= first_bad_prefix_idx.
    // (Because if k > first_bad_prefix_idx, then a[first_bad_prefix_idx] would need to be >= first_bad_prefix_idx, which is false).
    // So, possible peaks k are 1, ..., first_bad_prefix_idx.

    // For any k, the right part requires a[i] >= n-1-i for i >= k.
    // The first_bad_suffix_idx is the largest i such that a[i] < n-1-i.
    // This means any k chosen must be > first_bad_suffix_idx.
    // (Because if k <= first_bad_suffix_idx, then a[first_bad_suffix_idx] would need to be >= n-1-first_bad_suffix_idx, which is false).
    // So, possible peaks k are first_bad_suffix_idx + 1, ..., n.

    // For a valid k to exist, we need a k that satisfies both conditions:
    // k <= first_bad_prefix_idx  AND  k > first_bad_suffix_idx
    // This means first_bad_suffix_idx < k <= first_bad_prefix_idx.
    // Such a k exists if and only if first_bad_suffix_idx < first_bad_prefix_idx.
    // If first_bad_suffix_idx < first_bad_prefix_idx, then we can pick k = first_bad_prefix_idx.
    // For this k, the left part is valid up to k-1.
    // The right part is valid from k.
    // The peak a[k-1] (0-indexed) must satisfy a[k-1] >= k-1 AND a[k-1] >= n-k.
    // The condition first_bad_suffix_idx < first_bad_prefix_idx means there is at least one index `i`
    // such that `a[i] >= i` AND `a[i] >= n-1-i`.
    // This `i` can be chosen as `k-1`.
    // For example, if `i = first_bad_prefix_idx - 1`, then `a[i] >= i`.
    // And since `i = first_bad_prefix_idx - 1 >= first_bad_suffix_idx`, it means `a[i] >= n-1-i`.
    // So, if `first_bad_suffix_idx < first_bad_prefix_idx`, then there is a valid `k`.
    // The peak index `k_0` (0-indexed) can be any index `i` such that `i < first_bad_prefix_idx` and `i > first_bad_suffix_idx`.
    // For such an `i`, `a[i] >= i` and `a[i] >= n-1-i`.
    // So we can make `a[i]` the peak.
    // The elements to its left `a[0]...a[i-1]` can be made `0...i-1` because `a[j] >= j` for `j < first_bad_prefix_idx`.
    // The elements to its right `a[i+1]...a[n-1]` can be made `n-1-(i+1)...0` because `a[j] >= n-1-j` for `j > first_bad_suffix_idx`.
    // And `a[i]` can be made `max(i, n-1-i)`. Since `a[i]` is at least `i` and `n-1-i`, it can be made the peak.

    if (first_bad_suffix_idx < first_bad_prefix_idx) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

