#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

// Suffix array construction (DC3 or SA-IS are faster, but N=5000 allows N log^2 N or N log N)
// This is a standard O(N log N) suffix array construction using `std::sort` and doubling.
std::vector<int> build_suffix_array(const std::string& s) {
    int n = s.length();
    std::vector<int> sa(n);
    std::vector<int> rank(n);
    std::vector<int> new_rank(n);
    std::vector<std::pair<std::pair<int, int>, int>> tuples(n);

    for (int i = 0; i < n; ++i) {
        sa[i] = i;
        rank[i] = s[i];
    }

    for (int k = 1; k < n; k <<= 1) {
        for (int i = 0; i < n; ++i) {
            tuples[i] = {{rank[i], (i + k < n ? rank[i + k] : -1)}, i};
        }
        std::sort(tuples.begin(), tuples.end());

        for (int i = 0; i < n; ++i) {
            sa[i] = tuples[i].second;
        }

        new_rank[sa[0]] = 0;
        for (int i = 1; i < n; ++i) {
            new_rank[sa[i]] = new_rank[sa[i-1]];
            if (tuples[i].first != tuples[i-1].first) {
                new_rank[sa[i]]++;
            }
        }
        rank = new_rank;
        if (rank[sa[n-1]] == n - 1) break;
    }
    return sa;
}

// LCP array construction (Kasai's algorithm)
std::vector<int> build_lcp_array(const std::string& s, const std::vector<int>& sa) {
    int n = s.length();
    std::vector<int> lcp(n);
    std::vector<int> rank(n); // rank[i] = position of suffix s[i..] in SA

    for (int i = 0; i < n; ++i) {
        rank[sa[i]] = i;
    }

    int h = 0;
    for (int i = 0; i < n; ++i) {
        if (rank[i] == n - 1) {
            h = 0;
            continue;
        }
        int j = sa[rank[i] + 1];
        while (i + h < n && j + h < n && s[i + h] == s[j + h]) {
            h++;
        }
        lcp[rank[i]] = h;
        if (h > 0) {
            h--;
        }
    }
    return lcp;
}

// Sparse table for RMQ (Range Minimum Query) on LCP array
struct SparseTable {
    std::vector<std::vector<int>> st;
    std::vector<int> log_table;
    int n;

    SparseTable(const std::vector<int>& arr) {
        n = arr.size();
        log_table.resize(n + 1);
        log_table[1] = 0;
        for (int i = 2; i <= n; ++i) {
            log_table[i] = log_table[i / 2] + 1;
        }

        int max_log = log_table[n];
        st.assign(n, std::vector<int>(max_log + 1));

        for (int i = 0; i < n; ++i) {
            st[i][0] = arr[i];
        }

        for (int j = 1; j <= max_log; ++j) {
            for (int i = 0; i + (1 << j) <= n; ++i) {
                st[i][j] = std::min(st[i][j - 1], st[i + (1 << (j - 1))][j - 1]);
            }
        }
    }

    int query(int L, int R) { // query minimum in [L, R]
        if (L > R) return 1e9; // Should not happen with correct usage
        int j = log_table[R - L + 1];
        return std::min(st[L][j], st[R - (1 << j) + 1][j]);
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    std::string s_double = s + s;

    std::vector<int> sa = build_suffix_array(s_double);
    std::vector<int> lcp = build_lcp_array(s_double, sa);
    std::vector<int> rank_s_double(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        rank_s_double[sa[i]] = i;
    }

    SparseTable st_lcp(lcp);

    // Precompute for each starting position i, the length of the longest common prefix
    // between s[i..] and s[j..] for all j.
    // Specifically, for a given i, we need to find the maximum LCP value for any j != i.
    // This is equivalent to finding the maximum LCP value in the LCP array for suffixes
    // starting at i and j.
    // For a fixed i, and a fixed length L, we want to know if there exists j != i such that
    // s[i..i+L-1] == s[j..j+L-1]. This is true if LCP(s[i..], s[j..]) >= L.
    // The maximum LCP for s[i..] with any other suffix s[j..] is max(LCP[rank[i]-1], LCP[rank[i]]).
    // (if rank[i]-1 or rank[i] is out of bounds, handle appropriately)
    // This is for the original string s. For s_double, it's slightly different.
    // We need to find the length of the longest common prefix of s[i..] with any other s[j..]
    // where j is also in [0, n-1].
    // This is the maximum LCP value between rank_s_double[i] and rank_s_double[j] for j in [0, n-1], j!=i.
    // This can be found by iterating through the SA and LCP array.
    // For each suffix s_double[sa[x]..], if sa[x] < n, it's an original suffix.
    // We want to find the longest common prefix of s[i..] with s[j..] for j != i.
    // This is the maximum LCP value between rank_s_double[i] and rank_s_double[j] for j in [0, n-1], j!=i.
    // This is max(LCP(rank_s_double[i], rank_s_double[i-1]), LCP(rank_s_double[i], rank_s_double[i+1]))
    // where LCP(r1, r2) is the minimum LCP value in the range [min(r1,r2), max(r1,r2)-1] of the LCP array.

    std::vector<int> max_lcp_with_other_original_suffix(n);
    for (int i = 0; i < n; ++i) {
        int current_rank = rank_s_double[i];
        int max_l = 0;

        // Check suffixes before current_rank in SA
        for (int r = current_rank - 1; r >= 0; --r) {
            if (sa[r] < n) { // If it's an original suffix
                max_l = std::max(max_l, st_lcp.query(r, current_rank - 1));
                break; // Found the closest original suffix to the left
            }
        }
        // Check suffixes after current_rank in SA
        for (int r = current_rank; r < 2 * n - 1; ++r) {
            if (sa[r+1] < n) { // If it's an original suffix
                max_l = std::max(max_l, st_lcp.query(current_rank, r));
                break; // Found the closest original suffix to the right
            }
        }
        max_lcp_with_other_original_suffix[i] = max_l;
    }

    std::vector<int> win_count(n, 0); // win_count[p] = number of k for which Vasya wins if he chooses position p

    for (int k = 0; k < n; ++k) { // Kolya's chosen shift k
        char t0_char = s[k]; // First character Vasya sees

        // Find all possible k' values that could produce t0_char
        std::vector<int> possible_k_prime;
        for (int kp = 0; kp < n; ++kp) {
            if (s[kp] == t0_char) {
                possible_k_prime.push_back(kp);
            }
        }

        if (possible_k_prime.size() == 1) { // If t0_char uniquely determines k
            for (int p = 1; p < n; ++p) { // Vasya can choose any p, he wins
                win_count[p]++;
            }
        } else { // t0_char does not uniquely determine k
            // For each p, Vasya needs to check if (t[0], t[p-1]) uniquely determines k.
            // t[0] = s[k]
            // t[p-1] = s[(k + p - 1) % n]
            // Vasya wins if for this (t[0], t[p-1]) pair, there is only one k' such that
            // s[k'] == t[0] AND s[(k' + p - 1) % n] == t[p-1].
            // This means for all k_prime in possible_k_prime, if k_prime != k, then
            // s[(k_prime + p - 1) % n] != t[p-1].
            // Or, equivalently, for all k_prime in possible_k_prime, if k_prime != k, then
            // s[(k_prime + p - 1) % n] != s[(k + p - 1) % n].

            // This is equivalent to checking if the string s[k..k+p-1] is unique among
            // all strings s[k_prime..k_prime+p-1] for k_prime in possible_k_prime.
            // The length of the prefix to check is p.
            // For a given k, and a given p, Vasya wins if for all k_prime in possible_k_prime, k_prime != k,
            // the prefix s[k..k+p-1] is different from s[k_prime..k_prime+p-1].
            // This means LCP(s[k..], s[k_prime..]) < p for all k_prime in possible_k_prime, k_prime != k.
            // The maximum LCP of s[k..] with any other s[k_prime..] (where s[k_prime] == s[k])
            // must be less than p.
            // We need to find the maximum LCP of s[k..] with s[k_prime..] where k_prime != k and s[k_prime] == s[k].
            // This is the max_lcp_with_other_original_suffix[k] if we consider only suffixes starting with s[k].
            // No, this is not quite right. We need to consider only k' such that s[k'] == s[k].
            // Let's re-evaluate.
            // For a fixed k, and a fixed p, Vasya wins if for all k_prime in possible_k_prime, k_prime != k,
            // it holds that s[(k_prime + p - 1) % n] != s[(k + p - 1) % n].
            // This means that the character at index (k+p-1)%n in s is unique among all (k_prime+p-1)%n for k_prime in possible_k_prime.
            // This is equivalent to saying that the string s[k..k+p-1] is unique among all s[k_prime..k_prime+p-1]
            // for k_prime in possible_k_prime.
            // This means that for all k_prime in possible_k_prime, k_prime != k,
            // LCP(s_double[k..], s_double[k_prime..]) < p.
            // So, for a given k, Vasya wins for a given p if
            // max_{k_prime in possible_k_prime, k_prime != k} LCP(s_double[k..], s_double[k_prime..]) < p.
            // Let L_k = max_{k_prime in possible_k_prime, k_prime != k} LCP(s_double[k..], s_double[k_prime..]).
            // Then Vasya wins if p > L_k.
            // We need to find L_k for each k.

            int L_k = 0;
            for (int kp : possible_k_prime) {
                if (kp == k) continue;
                int r1 = rank_s_double[k];
                int r2 = rank_s_double[kp];
                if (r1 > r2) std::swap(r1, r2);
                L_k = std::max(L_k, st_lcp.query(r1, r2 - 1));
            }

            // If Vasya chooses position p, he wins if p > L_k.
            // The positions are 1-indexed, so p ranges from 1 to n-1.
            // If L_k is n-1, then s[k..] is identical to s[kp..] for some kp != k,
            // meaning s is periodic and s[k..] == s[kp..] for length n.
            // In this case, no p will work.
            // If L_k < n-1, then any p from L_k + 1 to n-1 will work.
            for (int p = L_k + 1; p < n; ++p) {
                win_count[p]++;
            }
        }
    }

    double max_prob = 0.0;
    for (int p = 1; p < n; ++p) {
        max_prob = std::max(max_prob, (double)win_count[p] / n);
    }

    std::cout << std::fixed << std::setprecision(15) << max_prob << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance (strawberry_count - blueberry_count)
    // For type 1 (strawberry), add 1. For type 2 (blueberry), subtract 1.
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // If initial_balance is 0, no jars need to be emptied.
    if (initial_balance == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain balance.
    // key: balance, value: number of jars removed from left (k_L)
    std::map<int, int> left_balances;
    left_balances[0] = 0; // 0 jars removed from left, balance is 0 (relative to left side)

    int current_balance_left = 0;
    for (int k_L = 1; k_L <= n; ++k_L) {
        int jar_idx = n - k_L; // Jars are 0-indexed, so n-k_L is the index of the jar being removed
        if (a[jar_idx] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        // Store the minimum k_L for this balance. Since we iterate k_L from 1 upwards,
        // the first time we see a balance, it corresponds to the minimum k_L.
        if (left_balances.find(current_balance_left) == left_balances.end()) {
            left_balances[current_balance_left] = k_L;
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible removals

    // Case 1: Only remove jars from the left side.
    // We need the final balance to be 0.
    // If we remove k_L jars from the left, the remaining jars are a[0...n-k_L-1] and a[n...2n-1].
    // The balance of the remaining jars would be initial_balance - current_balance_left.
    // We want initial_balance - current_balance_left = 0, so current_balance_left = initial_balance.
    // If initial_balance is found in left_balances, then we can achieve a final balance of 0
    // by removing only jars from the left.
    if (left_balances.count(initial_balance)) {
        min_total_removed = std::min(min_total_removed, left_balances[initial_balance]);
    }

    // Case 2: Remove jars from the right side (and potentially left side).
    // Iterate through possible number of jars removed from the right side (k_R).
    int current_balance_right = 0;
    for (int k_R = 1; k_R <= n; ++k_R) {
        int jar_idx = n + k_R - 1; // Jars are 0-indexed, so n+k_R-1 is the index of the jar being removed
        if (a[jar_idx] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }

        // If we remove k_L jars from left and k_R jars from right,
        // the total balance change is current_balance_left + current_balance_right.
        // We want initial_balance - (current_balance_left + current_balance_right) = 0.
        // So, current_balance_left = initial_balance - current_balance_right.
        int target_balance_left = initial_balance - current_balance_right;

        if (left_balances.count(target_balance_left)) {
            int k_L = left_balances[target_balance_left];
            min_total_removed = std::min(min_total_removed, k_L + k_R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

