                // Choose (0,0,0) as it's simpler.
                // A_j = 0, B_j = 0, C_j = 0
            } else if (s0 == 0 && s1 == 1) { // Identity
                // Option 1 (C_j=0): A_j = 1 & 1 = 1, B_j = 0, C_j = 0. (1,0,0)
                // Option 2 (C_j=1): A_j = 0 & 0 = 0, B_j = 1, C_j = 1. (0,1,1)
                // Choose (1,0,0) as it's simpler.
                // A_j = 1, B_j = 0, C_j = 0
                A |= (1 << bit_idx);
            } else if (s0 == 1 && s1 == 0) { // Flip
                // Option 1 (C_j=0): A_j = 0 & 0 = 0, B_j = 1, C_j = 0. (0,1,0)
                // Option 2 (C_j=1): A_j = 1 & 1 = 1, B_j = 0, C_j = 1. (1,0,1)
                // Choose (1,0,1) as it's simpler.
                // A_j = 1, B_j = 0, C_j = 1
                A |= (1 << bit_idx);
                C |= (1 << bit_idx);
            } else { // (s0 == 1 && s1 == 1) // Always 1
                // Option 1 (C_j=0): A_j = 1 & 0 = 0, B_j = 1, C_j = 0. (0,1,0)
                // Option 2 (C_j=1): A_j = 0 & 1 = 0, B_j = 0, C_j = 1. (0,0,1)
                // Choose (0,1,0) as it's simpler.
                // A_j = 0, B_j = 1, C_j = 0
                B |= (1 << bit_idx);
            }
        }

    std::cout << 3 << std::endl;
    std::cout << "& " << A << std::endl;
    std::cout << "| " << B << std::endl;
    std::cout << "^ " << C << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using 1-based indexing for 'a' array to match problem statement
// a[0] will be unused, a[1] will be the initial 'i'
// a[2]...a[n] are given.
std::vector<long long> a_values;
int N;

// Memoization tables
// dp_x[k] stores the final x value if starting from (k, 0)
// dp_y[k] stores the final y value if starting from (k, 0)
// visited[k] is used to detect cycles (non-termination)
std::vector<long long> dp_x;
std::vector<long long> dp_y;
std::vector<bool> visited;
std::vector<bool> in_recursion_stack;

// Function to calculate the final (x, y) from a starting x_start
// This function assumes a_values[1] is already set for the current run.
void solve_from(int k) {
    if (k <= 0 || k > N) {
        // Base case: out of bounds, program terminates.
        // The y value accumulated up to this point is the final y.
        // The x value is k itself.
        dp_x[k] = k;
        dp_y[k] = 0; // No additional y from this state, as it's already terminated.
        visited[k] = true;
        return;
    }

    if (visited[k]) {
        // Already computed or part of a cycle
        return;
    }

    if (in_recursion_stack[k]) {
        // Cycle detected: non-terminating path
        dp_x[k] = -1; // Mark as non-terminating
        dp_y[k] = -1; // Mark as non-terminating
        visited[k] = true;
        return;
    }

    in_recursion_stack[k] = true;

    long long current_a_val = a_values[k];

    // Step 1: x = x + a_x, y = y + a_x
    // New x_prime = k + current_a_val
    // y_prime = current_a_val (this is the y accumulated in this step)

    // Step 2: x = x_prime - a_x_prime, y = y_prime + a_x_prime
    // The next state we jump to is (x_prime - a_x_prime).
    // The y accumulated in this step is a_x_prime.

    // The state we transition to is (k + current_a_val - a_values[k + current_a_val]).
    // The total y accumulated in these two steps is current_a_val + a_values[k + current_a_val].
    // However, a_values[k + current_a_val] is only valid if k + current_a_val is within [1, N].
    // If k + current_a_val is out of bounds, the program terminates after step 1.

    long long x_after_step1 = k + current_a_val;
    long long y_accum_step1 = current_a_val;

    if (x_after_step1 <= 0 || x_after_step1 > N) {
        // Program terminates after step 1.
        dp_x[k] = x_after_step1;
        dp_y[k] = y_accum_step1;
    } else {
        // Program continues to step 2.
        long long a_val_at_x_after_step1 = a_values[x_after_step1];
        long long x_after_step2 = x_after_step1 - a_val_at_x_after_step1;
        long long y_accum_step2 = a_val_at_x_after_step1;

        // Recursively solve for the state after step 2
        solve_from(static_cast<int>(x_after_step2));

        if (dp_x[static_cast<int>(x_after_step2)] == -1) {
            // If the subsequent path leads to non-termination
            dp_x[k] = -1;
            dp_y[k] = -1;
        } else {
            // If the subsequent path terminates
            dp_x[k] = dp_x[static_cast<int>(x_after_step2)];
            dp_y[k] = y_accum_step1 + y_accum_step2 + dp_y[static_cast<int>(x_after_step2)];
        }
    }

    in_recursion_stack[k] = false;
    visited[k] = true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_values.resize(N + 1); // 1-indexed
    // a_values[1] will be set for each query
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize DP tables for the current run
    // Size N+1 for 1-indexed access, plus 2 for 0 and N+1 boundary conditions
    dp_x.resize(N + 2);
    dp_y.resize(N + 2);
    visited.resize(N + 2);
    in_recursion_stack.resize(N + 2);

    for (int i = 1; i < N; ++i) {
        a_values[1] = i; // Set a_1 for the current run

        // Reset visited and in_recursion_stack for each new a_1
        // Only need to reset for states that could be reached.
        // Since a_x can be large, any state from 1 to N could potentially be visited.
        // Also, 0 and N+1 are boundary conditions.
        std::fill(visited.begin(), visited.end(), false);
        std::fill(in_recursion_stack.begin(), in_recursion_stack.end(), false);

        // Initialize boundary conditions for dp_x and dp_y
        // These are states where the program terminates immediately.
        // dp_x[0] = 0, dp_y[0] = 0
        // dp_x[N+1] = N+1, dp_y[N+1] = 0
        // These are handled by the solve_from function's base case.
        // We just need to ensure they are marked as visited.
        visited[0] = true;
        visited[N+1] = true;
        dp_x[0] = 0;
        dp_y[0] = 0;
        dp_x[N+1] = N+1;
        dp_y[N+1] = 0;

        solve_from(1); // Start the program from x=1

        std::cout << dp_y[1] << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute prefix sums of '1's
    std::vector<int> prefix_ones(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_ones[i + 1] = prefix_ones[i] + (s[i] == '1');
    }

    // Iterate over all possible right endpoints r
    for (int r = 0; r < n; ++r) {
        // Case 1: Substrings with length up to 20 (or 21, to be safe)
        // These are short enough that their binary value won't exceed 2^20,
        // which is roughly 1 million.
        // We can directly calculate the value and check the condition.
        long long current_val = 0;
        for (int l = r; l >= std::max(0, r - 20); --l) { // Max length 21
            if (s[l] == '1') {
                current_val += (1LL << (r - l));
            }
            if (current_val == (r - l + 1)) {
                good_substrings_count++;
            }
        }

        // Case 2: Substrings with length greater than 20
        // For these substrings, the value can be very large.
        // However, if the length is L, the value V must be at least L.
        // The maximum possible value for a binary string of length L is 2^L - 1.
        // The minimum value for a binary string of length L starting with '1' is 2^(L-1).
        // If s[l] == '0', then the value V is determined by s[l+1...r].
        // The condition is r - l + 1 = V.
        //
        // Let's consider substrings s[l...r] where r-l+1 > 20.
        // If s[l] == '1', then V >= 2^(r-l).
        // If r-l+1 > 20, then 2^(r-l) is much larger than r-l+1.
        // For example, if r-l+1 = 21, then 2^(r-l) = 2^20 = 1048576.
        // So, if s[l] == '1' and r-l+1 > 20, then V will be much larger than r-l+1.
        // Thus, no good substrings can start with '1' if their length is > 20.
        //
        // This means any good substring of length > 20 must start with '0'.
        // If s[l] == '0', then V = f(s[l+1...r]).
        // The condition becomes r - l + 1 = f(s[l+1...r]).
        // Let k = r - l + 1 be the length.
        // Let num_leading_zeros = l_prime - l, where s[l_prime] is the first '1' in s[l...r].
        // If there are no '1's, V=0.
        //
        // We are looking for substrings s[l...r] such that:
        // 1. r - l + 1 > 20 (or some constant like 21)
        // 2. s[l] == '0'
        // 3. r - l + 1 = f(s[l...r])
        //
        // Let's fix r. We are looking for l such that r - l + 1 = V.
        // Since s[l] must be '0', we are interested in l such that s[l] == '0'.
        // The value V is determined by the '1's in s[l...r].
        //
        // Consider the number of '1's in s[l...r]. Let this be `ones_count`.
        // If `ones_count` is 0, then V=0. The condition becomes r-l+1 = 0, which is impossible.
        // So `ones_count` must be at least 1.
        //
        // Let's iterate `l` from `r - 21` down to `0`.
        // We already covered `l` from `r` down to `max(0, r - 20)`.
        // So we need to cover `l` from `max(0, r - 21)` down to `0`.
        //
        // For a fixed `r`, and a potential `l` such that `s[l] == '0'`:
        // We need `r - l + 1 = V`.
        // The value `V` is `f(s[l...r])`.
        // The maximum value of `V` for a substring of length `k` is `2^k - 1`.
        // The minimum value of `V` for a substring of length `k` that contains at least one '1' is `1`.
        //
        // If `s[l] == '0'`, then `V` is the value of `s[l+1...r]`.
        // Let `k = r - l + 1`.
        // We need `k = f(s[l+1...r])`.
        // The maximum value of `f(s[l+1...r])` is `2^(r-(l+1)+1) - 1 = 2^(r-l) - 1`.
        // So we need `r - l + 1 <= 2^(r-l) - 1`.
        // Let `len_suffix = r - l`. Then `len_suffix + 1 <= 2^len_suffix - 1`.
        // This inequality holds for `len_suffix >= 2`.
        // If `len_suffix = 0`, `1 <= 2^0 - 1 = 0` (false).
        // If `len_suffix = 1`, `2 <= 2^1 - 1 = 1` (false).
        // So, `r-l` must be at least 2. This means `l <= r-2`.
        //
        // Let's consider the number of leading zeros.
        // Suppose `s[l] = '0'`, `s[l+1] = '0'`, ..., `s[l+z-1] = '0'`, and `s[l+z] = '1'`.
        // Then `V = f(s[l+z...r])`.
        // The length is `k = r - l + 1`.
        // We need `k = f(s[l+z...r])`.
        // The value `f(s[l+z...r])` is at most `2^(r-(l+z)+1) - 1`.
        // So `r - l + 1 <= 2^(r - l - z + 1) - 1`.
        // Let `effective_len = r - l - z + 1`. This is the length of `s[l+z...r]`.
        // We need `r - l + 1 <= 2^effective_len - 1`.
        //
        // The number of '1's in `s[l...r]` is `prefix_ones[r+1] - prefix_ones[l]`.
        // If this count is `C`, then `V >= 2^(C-1)` if `s[l]` is '1' and `C` is the number of '1's.
        // If `s[l]` is '0', then `V` is the value of `s[l+1...r]`.
        //
        // Let's use the observation that if `s[l] == '1'`, then `V >= 2^(r-l)`.
        // If `r-l+1 > 20`, then `2^(r-l)` is much larger than `r-l+1`.
        // For example, if `r-l+1 = 21`, `2^(r-l) = 2^20 = 1048576`.
        // So, for `r-l+1 > 20`, if `s[l] == '1'`, it's impossible for `r-l+1 = V`.
        // This means any good substring of length `> 20` must start with `s[l] == '0'`.
        //
        // Let's find the index of the first '1' to the left of `r`.
        // Let `p_one` be the index of the first '1' such that `p_one <= r`.
        // If `s[p_one] == '1'`, then `f(s[p_one...r])` is at least `2^(r-p_one)`.
        // If `r - p_one + 1 > 20`, then `f(s[p_one...r])` is too large.
        // So, `p_one` must be such that `r - p_one + 1 <= 20`.
        // This means `p_one >= r - 19`.
        //
        // So, for any `l < r - 19`, `s[l...r]` must have `s[l] == '0'`.
        // And `s[l...r]` must contain at least one '1' at an index `p_one` such that `p_one >= r - 19`.
        //
        // Let's iterate `l` from `r - 21` down to `0`.
        // For each `l`, if `s[l] == '0'`:
        // We need to find `l` such that `r - l + 1 = f(s[l...r])`.
        // Let `k = r - l + 1`.
        // The value `f(s[l...r])` is `f(s[l+1...r])`.
        // Let `p_one` be the index of the first '1' in `s[l...r]`.
        // If no '1's, `f=0`, `k=0` impossible.
        // If `p_one` exists, then `f(s[l...r]) = f(s[p_one...r])`.
        // We need `r - l + 1 = f(s[p_one...r])`.
        //
        // The maximum value of `f(s[p_one...r])` is `2^(r-p_one+1) - 1`.
        // So we need `r - l + 1 <= 2^(r-p_one+1) - 1`.
        //
        // Let's fix `r`. We are looking for `l`.
        // We know `l` must be such that `s[l] == '0'`.
        // And the first '1' in `s[l...r]` must be at some index `p_one` such that `r - p_one + 1 <= 20`.
        // This means `p_one >= r - 19`.
        //
        // So, for a fixed `r`, we only need to consider `l` such that `s[l] == '0'` and `l < r - 20`.
        // For such `l`, the first '1' in `s[l...r]` must be at an index `p_one` where `p_one >= r - 19`.
        //
        // Let `p_one_idx` be the index of the first '1' in `s[0...r]` that is `>= r - 19`.
        // If no such '1' exists, then for `l < r - 19`, `s[l...r]` contains no '1's, so `f=0`, impossible.
        //
        // If such `p_one_idx` exists:
        // We are looking for `l` such that `s[l] == '0'` and `l < p_one_idx`.
        // The condition is `r - l + 1 = f(s[p_one_idx...r])`.
        // Let `val_suffix = f(s[p_one_idx...r])`. This value is fixed for a given `r` and `p_one_idx`.
        // We need `r - l + 1 = val_suffix`.
        // This implies `l = r + 1 - val_suffix`.
        //
        // So, for each `r`:
        // 1. Iterate `l` from `r` down to `max(0, r - 20)`. Calculate `f(s[l...r])` and check. (Done above)
        // 2. Find the smallest `p_one_idx` such that `s[p_one_idx] == '1'` and `p_one_idx >= max(0, r - 19)`.
        //    If no such `p_one_idx` exists, then no more good substrings for this `r`.
        //    Otherwise, calculate `val_suffix = f(s[p_one_idx...r])`.
        //    Calculate the required `l_target = r + 1 - val_suffix`.
        //    If `l_target < 0`, or `l_target >= p_one_idx`, or `s[l_target] == '1'`, then this `l_target` is not valid.
        //    Otherwise, `l_target` is a valid starting index.
        //    The number of leading zeros before `p_one_idx` is `p_one_idx - l_target`.
        //    We need to count how many `l` values satisfy `s[l] == '0'` and `l < p_one_idx` and `r - l + 1 = val_suffix`.
        //    This means `l = r + 1 - val_suffix`.
        //    We need to check if `s[l] == '0'` for this specific `l`.
        //    And `l` must be less than `p_one_idx`.
        //    And `l` must be less than `r - 20`.
        //
        // Let's refine Case 2.
        // For a fixed `r`, we are looking for `l` such that `r - l + 1 = f(s[l...r])`.
        // We know that if `r - l + 1 > 20`, then `s[l]` must be '0'.
        // Let `p_one` be the index of the first '1' in `s[l...r]`.
        // Then `f(s[l...r]) = f(s[p_one...r])`.
        // Also, `r - p_one + 1` must be at most 20 (otherwise `f(s[p_one...r])` is too large).
        // So `p_one >= r - 19`.
        //
        // This means for `l` such that `r - l + 1 > 20`, the first '1' in `s[l...r]` must be at an index `p_one`
        // in the range `[max(0, r - 19), r]`.
        //
        // Let's iterate `p_one` from `max(0, r - 19)` to `r`.
        // If `s[p_one] == '1'`:
        //   Calculate `val_suffix = f(s[p_one...r])`.
        //   We need `r - l + 1 = val_suffix`.
        //   This implies `l = r + 1 - val_suffix`.
        //   Now check if this `l` is valid:
        //     1. `l >= 0`
        //     2. `l < p_one` (because `p_one` is the first '1', so `s[l...p_one-1]` must be all '0's)
        //     3. `r - l + 1 > 20` (this is the condition for Case 2)
        //     4. `s[l]` must be '0' (implied by `l < p_one`)
        //
        //   Condition 3: `r - l + 1 > 20` means `val_suffix > 20`.
        //   Condition 2: `l < p_one` means `r + 1 - val_suffix < p_one`.
        //   This is `r + 1 - p_one < val_suffix`.
        //   Condition 1: `l >= 0` means `r + 1 - val_suffix >= 0`.
        //
        //   So, for each `r`, and for each `p_one` in `[max(0, r - 19), r]` where `s[p_one] == '1'`:
        //     Calculate `val_suffix = f(s[p_one...r])`.
        //     If `val_suffix > 20` AND `val_suffix > r + 1 - p_one`:
        //       Then `l = r + 1 - val_suffix` is a candidate.
        //       We need to count how many `l'`s satisfy `s[l'] == '0'` for `l' \in [l, p_one-1]`.
        //       This is simply `p_one - l`.
        //       The number of zeros in `s[l...p_one-1]` is `(p_one - l) - (prefix_ones[p_one] - prefix_ones[l])`.
        //       Since `s[l...p_one-1]` must be all zeros, `prefix_ones[p_one] - prefix_ones[l]` must be 0.
        //       This means `prefix_ones[p_one] == prefix_ones[l]`.
        //       So, we need to count `l` such that `l = r + 1 - val_suffix`, `l >= 0`, `l < p_one`, and `prefix_ones[p_one] == prefix_ones[l]`.
        //       The last condition `prefix_ones[p_one] == prefix_ones[l]` is equivalent to saying all characters `s[l...p_one-1]` are '0'.
        //       This is exactly what we need for `p_one` to be the first '1'.
        //
        //   So, for each `r`:
        //     Iterate `p_one` from `max(0, r - 19)` to `r`.
        //     If `s[p_one] == '1'`:
        //       Calculate `val_suffix = f(s[p_one...r])`.
        //       If `val_suffix > 20`: // This ensures `r - l + 1 > 20`
        //         `l_candidate = r + 1 - val_suffix`.
        //         If `l_candidate >= 0` and `l_candidate < p_one`:
        //           // Check if all characters s[l_candidate...p_one-1] are '0'.
        //           // This is true if prefix_ones[p_one] - prefix_ones[l_candidate] == 0.
        //           // Since p_one is the first '1' in s[l_candidate...r], this condition is automatically met.
        //           // No, this is not automatically met. p_one is the first '1' in s[l_candidate...r] IF s[l_candidate...p_one-1] are all '0'.
        //           // We need to check if `prefix_ones[p_one] == prefix_ones[l_candidate]`.
        //           if (prefix_ones[p_one] == prefix_ones[l_candidate]) {
        //               good_substrings_count++;
        //           }
        //
        // This logic seems correct. The constant 20 is chosen because 2^20 is large enough.
        // 2^20 = 1,048,576. Max length is 2e5.
        // If length is 21, value can be 2^20.
        // If length is 20, value can be 2^19.
        // So, if `r-l+1 > 20`, then `s[l]` must be '0'.
        // And `p_one` must be such that `r-p_one+1 <= 20`.
        // So `p_one >= r-19`.
        //
        // Let's use a constant `MAX_LEN_CHECK = 20`.
        //
        // For `r` from `0` to `n-1`:
        //   `current_val = 0`
        //   For `l` from `r` down to `max(0, r - MAX_LEN_CHECK)`:
        //     If `s[l] == '1'`, `current_val += (1LL << (r - l))`.
        //     If `current_val == (r - l + 1)`, `good_substrings_count++`.
        //
        //   // Now handle `l` such that `r - l + 1 > MAX_LEN_CHECK`.
        //   // This means `l < r - MAX_LEN_CHECK`.
        //   // For such `l`, `s[l]` must be '0'.
        //   // And the first '1' in `s[l...r]` must be at `p_one` such that `r - p_one + 1 <= MAX_LEN_CHECK`.
        //   // So `p_one >= r - MAX_LEN_CHECK + 1`.
        //   // Let `p_one_start_idx = max(0, r - MAX_LEN_CHECK + 1)`.
        //   // Iterate `p_one` from `p_one_start_idx` to `r`.
        //   // If `s[p_one] == '1'`:
        //   //   `val_suffix = f(s[p_one...r])`.
        //   //   If `val_suffix > MAX_LEN_CHECK`: // This ensures `r - l + 1 > MAX_LEN_CHECK`
        //   //     `l_candidate = r + 1 - val_suffix`.
        //   //     If `l_candidate >= 0` and `l_candidate < p_one`:
        //   //       // Check if `s[l_candidate...p_one-1]` are all '0's.
        //   //       // This is true if `prefix_ones[p_one] - prefix_ones[l_candidate] == 0`.
        //   //       if (prefix_ones[p_one] == prefix_ones[l_candidate]) {
        //   //           good_substrings_count++;
        //   //       }
        //
        // This logic seems robust.
        // The maximum value of `val_suffix` can be `2^MAX_LEN_CHECK - 1`.
        // If `MAX_LEN_CHECK = 20`, `val_suffix` can be up to `2^20 - 1`.
        // `l_candidate = r + 1 - val_suffix`. `r` can be up to `N-1`.
        // `l_candidate` can be negative.
        //
