struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a(n, 0); // Initial array, we'll determine its values
    std::vector<long long> current_deltas(n, 0); // Sum of d's applied to each element

    // For each type 2 operation, we know that for all j in [l, r],
    // a[j] + current_deltas[j] <= m_i.
    // This means a[j] <= m_i - current_deltas[j].
    // We want to find the largest possible a[j] that satisfies all constraints.
    // So, a[j] = min(m_i - current_deltas[j]) over all type 2 operations
    // that cover index j.
    // Initialize a[j] to a very large value (effectively infinity)
    // and then take minimums.
    for (int i = 0; i < n; ++i) {
        a[i] = std::numeric_limits<long long>::max();
    }

    // First pass: Determine upper bounds for a[j]
    // For each type 2 operation, update upper bounds for a[j]
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a[j] = std::min(a[j], ops[i].val - current_deltas[j]);
            }
        }
    }

    // If any a[j] is still max_long_long, it means it was never constrained by a type 2 query.
    // We can set it to 0 (or any value within bounds).
    // The problem states |a_i| <= 10^9. 0 is a safe choice.
    for (int i = 0; i < n; ++i) {
        if (a[i] == std::numeric_limits<long long>::max()) {
            a[i] = 0;
        }
    }

    // Second pass: Verify the solution
    // Re-simulate operations with the determined initial array 'a'
    // and check if all type 2 queries match.
    std::fill(current_deltas.begin(), current_deltas.end(), 0); // Reset deltas

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, a[j] + current_deltas[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check if initial array elements are within bounds [-10^9, 10^9]
    for (int i = 0; i < n; ++i) {
        if (a[i] < -1000000000LL || a[i] > 1000000000LL) {
            // This case should ideally not be reached if m_i and d_i are within bounds
            // and a[j] is initialized to 0 if not constrained.
            // However, it's good practice to check.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

