int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // Calculate the maximum possible number of ones in string a
    // after any number of operations.
    // If ones_a is odd, we can append '1' once, making it ones_a + 1 (even).
    // After that, we can only append '0's.
    // If ones_a is even, we can only append '0's.
    // So, the maximum number of ones we can achieve is ones_a if ones_a is even,
    // or ones_a + 1 if ones_a is odd.
    int max_ones_a_possible = ones_a;
    if (ones_a % 2 != 0) { // If initial ones_a is odd
        max_ones_a_possible++; // We can append a '1' once
    }
    // After potentially appending one '1', all subsequent appends are '0's.
    // So, the number of '1's will not increase further.

    // Condition 1: The number of '1's in b must not exceed the maximum possible '1's from a.
    if (ones_b > max_ones_a_possible) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of b must not exceed the length of a after all possible appends.
    // We can append characters until string a reaches length |b|.
    // The maximum length a can reach is effectively infinite, but we only care if it can reach |b|.
    // If |a| < |b|, we must append at least |b| - |a| characters.
    // If |a| >= |b|, we can just remove characters from a.
    // The only constraint on length is that we can always make a longer if needed,
    // and we can always make a shorter (down to length 1) if needed.
    // So, if |a| < |b|, we must be able to append enough characters.
    // This is always possible as we can append indefinitely.
    // The only real constraint is the number of ones.

    // If we reach this point, it means ones_b <= max_ones_a_possible.
    // This implies that we can achieve the required number of '1's in string 'a'
    // by either not appending any '1' (if ones_b == ones_a and ones_a is even)
    // or by appending exactly one '1' (if ones_b == ones_a + 1 and ones_a is odd).
    // In all other cases where ones_b <= max_ones_a_possible, we can achieve ones_b
    // by appending '0's until the length is sufficient, and then removing prefix characters.

    // The only remaining constraint is that we must be able to form 'b' itself.
    // The operations allow us to effectively take any suffix of 'a' (after some appends)
    // and check if it matches 'b'.
    // However, the problem is simpler: we just need to check if the *properties* match.
    // If we can achieve `ones_b` '1's and `|b|` length, then it's possible.
    // The "remove first character" operation means we can effectively start `a` from any index `i`
    // and then apply append operations.
    // The "append parity" operation means we can increase the length and potentially the '1' count.

    // The core idea is:
    // 1. We can always remove prefix characters from 'a' until its length is 1.
    // 2. We can always append characters to 'a' indefinitely.
    // 3. The number of '1's can be `ones_a` (if `ones_a` is even) or `ones_a + 1` (if `ones_a` is odd).
    //    Once `ones_a` becomes even (either initially or after one '1' append), it stays even.
    //    All subsequent appends are '0's.

    // So, if `ones_b` is less than or equal to `max_ones_a_possible`,
    // and `|b|` is less than or equal to the maximum length we can achieve (which is effectively infinite),
    // then it is always possible.
    // The length constraint is only that |b| must be at least 1.
    // Since |b| >= 1 is given, this is not an issue.

    // Therefore, the only condition is `ones_b <= max_ones_a_possible`.
    std::cout << "YES\n";

    return 0;
