struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in S1).
    // All f values are a_i + a_j.
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // This case is only potentially better if h is small enough.
    // The optimal strategy for two non-empty subsequences is to put a_1 and a_n into different subsequences.
    // Let a_1 be in S1, a_n in S2.
    // The remaining elements a_2, ..., a_{n-1} can be assigned to S1 or S2.
    // To minimize max_f - min_f, we want to make the range of f values as small as possible.
    // The smallest possible f value is a_1 + a_2 (if a_1, a_2 in same) or a_1 + a_2 + h (if a_1, a_2 in different).
    // The largest possible f value is a_{n-1} + a_n (if a_{n-1}, a_n in same) or a_{n-1} + a_n + h (if a_{n-1}, a_n in different).
    //
    // Consider the partition where a_1 is in S1, a_n is in S2, and all other elements a_2, ..., a_{n-1} are in S2.
    // S1 = {a_1}
    // S2 = {a_2, ..., a_n}
    //
    // f values:
    // 1. a_i + a_j for i, j in S2: min is a_2 + a_3, max is a_{n-1} + a_n.
    // 2. a_1 + a_i + h for a_i in S2: min is a_1 + a_2 + h, max is a_1 + a_n + h.
    //
    // Overall min_f = min(a_2 + a_3, a_1 + a_2 + h)
    // Overall max_f = max(a_{n-1} + a_n, a_1 + a_n + h)
    //
    // This specific partition (S1={a_1}, S2={a_2,...,a_n}) is chosen because it minimizes the maximum f value
    // involving a_1 and maximizes the minimum f value not involving a_1.
    //
    // Let's analyze the values:
    // min_f_candidate1 = elements[0].value + elements[1].value + h (a_1 in S1, a_2 in S2)
    // min_f_candidate2 = elements[1].value + elements[2].value (a_2, a_3 in S2)
    // min_f = std::min(min_f_candidate1, min_f_candidate2)
    //
    // max_f_candidate1 = elements[n-1].value + elements[n-2].value (a_{n-1}, a_n in S2)
    // max_f_candidate2 = elements[0].value + elements[n-1].value + h (a_1 in S1, a_{n-1} in S2)
    // max_f_candidate3 = elements[0].value + elements[n].value + h (a_1 in S1, a_n in S2)
    // max_f = std::max({max_f_candidate1, max_f_candidate2, max_f_candidate3})
    //
    // The problem statement says "distinct elements (that is i != j)".
    // If S1 = {a_1}, S2 = {a_2, ..., a_n}, then:
    // min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)
    // Note: elements[n-1] is the largest value, elements[n-2] is the second largest.
    // The largest sum within S2 is elements[n-1].value + elements[n-2].value.
    // The largest sum between S1 and S2 is elements[0].value + elements[n-1].value + h.
    // So max_f = max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h).
    //
    // This specific partition is:
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // Let's re-evaluate the min/max f values for this partition:
    // min_f_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    // max_f_val = std::max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value);
    //
    // This is the partition used in the sample case 1.
    // For n=3, a={1,2,3}, h=2. Sorted: {1,2,3}.
    // S1={1}, S2={2,3}.
    // f(1,2) = 1+2+2 = 5 (diff)
    // f(1,3) = 1+3+2 = 6 (diff)
    // f(2,3) = 2+3 = 5 (same)
    // min_f = 5, max_f = 6. Goodness = 1.
    //
    // Using the formulas:
    // elements[0]=1, elements[1]=2, elements[2]=3.
    // min_f_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    //           = std::min(1 + 2 + 2, 2 + 3) = std::min(5, 5) = 5.
    // max_f_val = std::max(elements[0].value + elements[2].value + h, elements[2].value + elements[1].value)
    //           = std::max(1 + 3 + 2, 3 + 2) = std::max(6, 5) = 6.
    // Goodness = 6 - 5 = 1. This matches the sample.

    long long goodness2 = -1;
    std::vector<int> partition2(n);

    if (n >= 2) { // Need at least two elements for this partition type
        // Partition: S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
        // Smallest f value:
        //   - elements[0].value + elements[1].value + h (a_1 from S1, a_2 from S2)
        //   - elements[1].value + elements[2].value (a_2, a_3 from S2, if n >= 3)
        long long min_f_val_case2;
        if (n == 2) {
            min_f_val_case2 = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            min_f_val_case2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        }

        // Largest f value:
        //   - elements[0].value + elements[n-1].value + h (a_1 from S1, a_n from S2)
        //   - elements[n-1].value + elements[n-2].value (a_{n-1}, a_n from S2, if n >= 3)
        long long max_f_val_case2;
        if (n == 2) {
            max_f_val_case2 = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            max_f_val_case2 = std::max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value);
        }

        goodness2 = max_f_val_case2 - min_f_val_case2;

        partition2[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition2[elements[i].original_index] = 2;
        }
    }

    if (goodness2 != -1 && goodness2 < goodness1) {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

