        // Number of bad pairs for this l is max(0, max_r_for_l - l + 1).
        // If min_end_idx[l] == n+1, then max_r_for_l = n.
        // Number of bad pairs for this l is n - l + 1.
        // This is equivalent to max(0, min_end_idx[l] - l).
        bad_pairs += std::max(0, min_end_idx[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
