// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces.
    // We cut s into s_prefix and s_suffix.
    // The new string can be s_suffix + s_prefix.
    // We need to check if s_suffix + s_prefix is a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the length of s_prefix
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string new_s = s_suffix + s_prefix;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces.
    // We cut s into s_left, s_middle, s_right.
    // The new string can be s_right + s_middle + s_left.
    // We need to check if s_right + s_middle + s_left is a palindrome and not equal to s.
    // This covers the example "nolon" -> "onlno"
    // s_left = "no", s_middle = "l", s_right = "on"
    // new_s = "on" + "l" + "no" = "onlno"
    // This is equivalent to checking if s_left + s_middle + s_right is a palindrome
    // and not equal to s, where s_left and s_right are swapped.
    // This is covered by the k=1 case if we consider s_left + s_middle as a prefix
    // and s_right as a suffix, then swap them.
    // The problem statement for k=2 is more general: "pieces could be shuffled".
    // However, for a string to be a palindrome, its first half must match its reversed second half.
    // If we have pieces P1, P2, P3, ..., Pk+1, and we rearrange them to form S'.
    // If S' is a palindrome, then S'[0]...S'[N/2-1] must be the reverse of S'[N-1]...S'[N/2].
    //
    // Consider the structure of a palindrome.
    // If we cut s into s_left, s_middle, s_right, and form s_right + s_middle + s_left.
    // This is a specific rearrangement.
    //
    // Let's re-evaluate the problem constraints for k=2.
    // The only way to get a new palindrome from 3 pieces (s_left, s_middle, s_right)
    // that is not covered by k=1 (swapping prefix/suffix) is if the middle piece is a palindrome
    // and the left and right pieces are swapped.
    // For example, s = s_left + s_middle + s_right.
    // If s_left is reversed s_right, and s_middle is a palindrome, then s is a palindrome.
    // If we swap s_left and s_right, we get s_right + s_middle + s_left.
    // If s_left = "no", s_middle = "l", s_right = "on".
    // s = "nolon". s_left is not reverse of s_right.
    // The example "nolon" -> "onlno" is achieved by cutting "no|l|on" and rearranging to "on|l|no".
    // This means s_left = "no", s_middle = "l", s_right = "on".
    // The new string is s_right + s_middle + s_left.
    // This is a specific rearrangement.
    //
    // The general case for k=2:
    // We have s_0, s_1, s_2.
    // Original string: s_0 s_1 s_2.
    // Possible permutations:
    // s_0 s_1 s_2 (original)
    // s_0 s_2 s_1
    // s_1 s_0 s_2
    // s_1 s_2 s_0
    // s_2 s_0 s_1
    // s_2 s_1 s_0 (this is the one from "nolon" example)
    //
    // For "nolon", n=5.
    // i=1: "n" | "olon". new = "olonn". Not palindrome.
    // i=2: "no" | "lon". new = "lonno". Not palindrome.
    // i=3: "nol" | "on". new = "onnol". Not palindrome.
    // i=4: "nolo" | "n". new = "nnolo". Not palindrome.
    // So k=1 doesn't work for "nolon".
    //
    // For k=2, we need to iterate over all possible cut positions.
    // Cut at i and j, where 0 < i < j < n.
    // s_0 = s.substr(0, i)
    // s_1 = s.substr(i, j-i)
    // s_2 = s.substr(j)
    //
    // For "nolon", n=5.
    // i=1, j=2: s_0="n", s_1="o", s_2="lon". Permutations:
    //   "nolon" (original)
    //   "nlon" (s_0 s_2 s_1)
    //   "onlon" (s_1 s_0 s_2)
    //   "onl" (s_1 s_2 s_0)
    //   "lonno" (s_2 s_0 s_1)
    //   "lonon" (s_2 s_1 s_0)
    // None of these are "onlno".
    //
    // i=1, j=3: s_0="n", s_1="ol", s_2="on".
    //   "nolon" (original)
    //   "nonol" (s_0 s_2 s_1)
    //   "olnon" (s_1 s_0 s_2)
    //   "olonn" (s_1 s_2 s_0)
    //   "onnol" (s_2 s_0 s_1)
    //   "onoln" (s_2 s_1 s_0)
    // None of these are "onlno".
    //
    // i=1, j=4: s_0="n", s_1="olo", s_2="n".
    //   "nolon" (original)
    //   "nnolo" (s_0 s_2 s_1)
    //   "olonn" (s_1 s_0 s_2)
    //   "olonn" (s_1 s_2 s_0)
    //   "nolon" (s_2 s_0 s_1)
    //   "nolon" (s_2 s_1 s_0)
    // None of these are "onlno".
    //
    // i=2, j=3: s_0="no", s_1="l", s_2="on". This is the example!
    //   s_0="no", s_1="l", s_2="on"
    //   Permutations:
    //   "nolon" (original)
    //   "noonl" (s_0 s_2 s_1)
    //   "lnoon" (s_1 s_0 s_2)
    //   "lon" (s_1 s_2 s_0)
    //   "onnol" (s_2 s_0 s_1)
    //   "onlno" (s_2 s_1 s_0) -> This is a palindrome and not equal to "nolon"!
    // So k=2 is the answer.
    //
    // This means we need to check all permutations of pieces for k=2.
    // There are 3! = 6 permutations.
    //
    // The problem states "minimum number of cuts k".
    // If k=1 works, output 1.
    // If k=1 doesn't work, check k=2.
    // If k=2 works, output 2.
    // If k=2 doesn't work, output "Impossible".
    // Why only up to k=2?
    //
    // Consider the structure of the original palindrome `s`.
    // If all characters in `s` are the same (e.g., "qqqq"), then any rearrangement of its substrings will result in the same string "qqqq".
    // For example, "q|qq|q" -> "qqqq".
    // In this case, it's impossible to form a new string `s' != s`.
    // We need to check this condition.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }
    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, can we always find a solution with k=2?
    // The problem statement implies that if k=1 doesn't work, and k=2 doesn't work, then it's impossible.
    // This suggests that k=2 is the maximum number of cuts we need to consider.
    //
    // Let's check k=2.
    // Iterate over all possible cut positions i and j (0 < i < j < n).
    // s_0 = s.substr(0, i)
    // s_1 = s.substr(i, j-i)
    // s_2 = s.substr(j)
    //
    // Store pieces in a vector and permute.
    std::vector<std::string> pieces(3);
    std::vector<int> p = {0, 1, 2}; // Indices for permutation

    for (int i = 1; i < n; ++i) { // First cut position
        for (int j = i + 1; j < n; ++j) { // Second cut position
            pieces[0] = s.substr(0, i);
            pieces[1] = s.substr(i, j - i);
            pieces[2] = s.substr(j);

            std::sort(p.begin(), p.end()); // Ensure starting from smallest permutation

            do {
                std::string new_s_candidate = pieces[p[0]] + pieces[p[1]] + pieces[p[2]];
                if (new_s_candidate != s && is_palindrome(new_s_candidate)) {
                    std::cout << 2 << std::endl;
                    return 0;
                }
            } while (std::next_permutation(p.begin(), p.end()));
        }
    }

    // If neither k=1 nor k=2 worked (and not all chars are same), then it's impossible.
    // This logic is based on the problem structure and typical competitive programming problem constraints.
    // If it were possible with k > 2, the problem would likely ask for minimum k without an implicit upper bound.
    std::cout << "Impossible" << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // If the current head cannot reach the current target track p[p_idx]
        // even by moving left as much as possible (i.e., p[p_idx] is too far right),
        // then this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // If p[p_idx] is to the right of current_h + T, this head cannot cover it.
        // If p[p_idx] is to the left of current_h - T, this head cannot cover it.
        // The condition for a head to cover p[p_idx] is |h_idx - p_idx| <= T.
        // If p[p_idx] is outside [current_h - T, current_h + T], this head cannot cover it.
        // Since p is sorted, if p[p_idx] is too far right for current_h,
        // it will be too far right for any h_k where k < h_idx.
        // So we must use current_h or a later head.
        // If current_h cannot reach p[p_idx] (i.e., p[p_idx] > right_reach),
        // then this head cannot start covering p[p_idx].
        // We need to advance h_idx.
        // However, the problem is about covering a contiguous block of p_j's.
        // A head at h_idx can cover a range [L, R].
        // We want to cover p[p_idx], p[p_idx+1], ..., p[m-1].

        // Find the first target track that this head can potentially cover.
        // This is p[p_idx]. If p[p_idx] is too far right for current_h,
        // then this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // If p[p_idx] > right_reach, this head cannot cover p[p_idx].
        // We must use a later head.
        // If p[p_idx] < left_reach, this head cannot cover p[p_idx] by moving right.
        // It must move left.
        // The crucial part is that a head can cover a range.
        // We want to cover p[p_idx] using current_h.
        // If current_h moves to p[p_idx], it takes |current_h - p[p_idx]| time.
        // The remaining time is T - |current_h - p[p_idx]|.
        // With this remaining time, it can cover tracks in range
        // [p[p_idx] - (T - |current_h - p[p_idx]|), p[p_idx] + (T - |current_h - p[p_idx]|)].
        // This is equivalent to saying it can cover any track x such that
        // |current_h - x| <= T.
        // So, current_h can cover any track in [current_h - T, current_h + T].

        // We need to cover p[p_idx].
        // If p[p_idx] is to the right of current_h + T, this head cannot cover p[p_idx].
        // We must use the next head.
        if (p[p_idx] > right_reach) {
            continue; // This head cannot reach p[p_idx], try next head
        }

        // If p[p_idx] is to the left of current_h - T, this head cannot cover p[p_idx]
        // by moving right. It must move left.
        // The range covered by current_h is [current_h - T, current_h + T].
        // We need to cover p[p_idx].
        // If p[p_idx] is within this range, current_h can cover it.
        // The question is, how far right can current_h cover?
        // It can cover up to right_reach.
        // But it also needs to cover p[p_idx].
        // If p[p_idx] is to the left of current_h, current_h moves left to p[p_idx].
        // The time taken is current_h - p[p_idx].
        // Remaining time is T - (current_h - p[p_idx]).
        // It can then move right from p[p_idx] by this remaining time.
        // So it covers up to p[p_idx] + (T - (current_h - p[p_idx])) = p[p_idx] + T - current_h + p[p_idx] = 2*p[p_idx] - current_h + T.
        // This is the rightmost point if it moves left first to p[p_idx] and then right.

        // If p[p_idx] is to the right of current_h, current_h moves right to p[p_idx].
        // Time taken is p[p_idx] - current_h.
        // Remaining time is T - (p[p_idx] - current_h).
        // It can then move right from p[p_idx] by this remaining time.
        // So it covers up to p[p_idx] + (T - (p[p_idx] - current_h)) = p[p_idx] + T - p[p_idx] + current_h = current_h + T.
        // This is the rightmost point if it moves right first to p[p_idx] and then right.

        // The maximum reach to the right for current_h, given it must cover p[p_idx]:
        // If current_h is to the left of p[p_idx] (current_h <= p[p_idx]):
        //   It moves right to p[p_idx], taking p[p_idx] - current_h time.
        //   It has T - (p[p_idx] - current_h) time left.
        //   It can reach up to p[p_idx] + (T - (p[p_idx] - current_h)) = current_h + T.
        // If current_h is to the right of p[p_idx] (current_h > p[p_idx]):
        //   It moves left to p[p_idx], taking current_h - p[p_idx] time.
        //   It has T - (current_h - p[p_idx]) time left.
        //   It can reach up to p[p_idx] + (T - (current_h - p[p_idx])) = 2*p[p_idx] - current_h + T.
        // Combining these:
        // If current_h <= p[p_idx], max_reach_right = current_h + T.
        // If current_h > p[p_idx], max_reach_right = 2*p[p_idx] - current_h + T.
        // This can be written as:
        // max_reach_right = p[p_idx] + (T - std::abs(current_h - p[p_idx])).
        // This is the rightmost point it can reach *after* covering p[p_idx].
        // This is the correct logic.

        long long max_reach_right_after_p_idx;
        if (current_h <= p[p_idx]) {
            // Head moves right to p[p_idx], then continues right
            max_reach_right_after_p_idx = current_h + T;
        } else { // current_h > p[p_idx]
            // Head moves left to p[p_idx], then moves right
            // Time to reach p[p_idx] is current_h - p[p_idx].
            // Remaining time is T - (current_h - p[p_idx]).
            // From p[p_idx], it can move right by this remaining time.
            max_reach_right_after_p_idx = p[p_idx] + (T - (current_h - p[p_idx]));
        }

        // Now, advance p_idx as far as possible using this head.
        while (p_idx < m && p[p_idx] <= max_reach_right_after_p_idx) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: (max_p - min_h) or (max_h - min_p)
    // A loose upper bound: difference between max p and min h, or max h and min p.
    // Max value of p_i or h_i is 10^10. So difference can be 10^10.
    // A tighter upper bound: max(p[m-1] - h[0], h[n-1] - p[0])
    // Or simply, max(p[m-1], h[n-1]) - min(p[0], h[0])
    // This is roughly 10^10.
    long long high = 20000000000LL; // 2 * 10^10, a safe upper bound
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2; // current_x
        bool possible = true;
        long long prev_b = 0; // b_0 is effectively 0 for b_1 >= b_0

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long current_b;

            // Case 1: a_i + x_i = b_i, where b_i >= prev_b
            // This means a_i <= b_i.
            // If a_i >= prev_b, we can set b_i = a_i. This requires x_i = 0.
            // If a_i < prev_b, we must set b_i >= prev_b.
            // The smallest b_i we can achieve is prev_b.
            // To get b_i = prev_b, we need (a_i + x_i) % m = prev_b.
            // This means a_i + x_i = prev_b or a_i + x_i = prev_b + m.
            // If a_i <= prev_b, we need x_i = prev_b - a_i.
            // If a_i > prev_b, we need x_i = prev_b - a_i + m.
            // In both cases, x_i = (prev_b - a_i + m) % m.
            // This x_i must be <= mid.

            // Case 2: a_i + x_i = b_i, where b_i < prev_b
            // This is not allowed by non-decreasing condition.
            // So we must ensure b_i >= prev_b.

            // We need to find x_i such that (a_i + x_i) % m >= prev_b and x_i <= mid.
            // The smallest possible value for x_i is 0.
            // The largest possible value for x_i is mid.

            // If a_i >= prev_b:
            // We can choose x_i = 0, then b_i = a_i. This satisfies b_i >= prev_b.
            // This is always possible if a_i >= prev_b.
            // The value of b_i would be a_i.
            // We can also choose x_i > 0.
            // If a_i + mid < m and a_i + mid < prev_b, then it's impossible.
            // But we want to minimize x_i.
            // If a_i >= prev_b, we can just take x_i = 0, so b_i = a_i.
            // This is valid because 0 <= mid.
            // So, if a_i >= prev_b, we set current_b = a_i.

            // If a_i < prev_b:
            // We must increment a_i.
            // We need (a_i + x_i) % m >= prev_b.
            // The smallest x_i that makes (a_i + x_i) % m >= prev_b is when (a_i + x_i) % m = prev_b.
            // This requires x_i = (prev_b - a_i + m) % m.
            // Let this required_x_i be `req_x`.
            // If `req_x` <= mid, then we can achieve `prev_b` as the new value.
            // So, if a_i < prev_b and `req_x` <= mid, we set current_b = prev_b.
            // If a_i < prev_b and `req_x` > mid, then we cannot achieve `prev_b` or anything larger than `prev_b`
            // by incrementing `a_i` by at most `mid` times to reach a value >= `prev_b`.
            // In this case, it's impossible.

            if (current_a >= prev_b) {
                // We can potentially keep current_a as b_i, which requires x_i = 0.
                // This is valid as 0 <= mid.
                // However, we might need to increment current_a to make it smaller (modulo m)
                // if current_a is very large and we want to keep it small.
                // But we want b_i >= prev_b.
                // If current_a + mid < prev_b + m (i.e., current_a + mid wraps around and becomes smaller than prev_b),
                // then it's impossible.
                // Example: a_i=6, prev_b=0, m=7, mid=0.
                // current_a >= prev_b. Set current_b = current_a = 6. prev_b becomes 6.
                // Example: a_i=0, prev_b=6, m=7, mid=0.
                // current_a < prev_b. req_x = (6-0+7)%7 = 6. req_x > mid. Impossible.

                // If a_i >= prev_b, we can always choose x_i = 0, making b_i = a_i.
                // This satisfies b_i >= prev_b.
                // The only way this fails is if we *must* increment a_i to make it smaller (modulo m)
                // to satisfy a later condition, but we can't.
                // But we are trying to find the minimum x_i for *this* element.
                // If a_i >= prev_b, we can set b_i = a_i. This requires x_i = 0.
                // This is always valid since 0 <= mid.
                // So, current_b = a_i.
                current_b = current_a;
            } else { // current_a < prev_b
                // We must increment current_a.
                // The smallest number of increments to make (current_a + x_i) % m >= prev_b
                // is to make (current_a + x_i) % m = prev_b.
                // This requires x_i = (prev_b - current_a + m) % m.
                long long required_x = (prev_b - current_a + m) % m;
                if (required_x <= mid) {
                    current_b = prev_b;
                } else {
                    possible = false;
                    break;
                }
            }
            prev_b = current_b;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

